# ==================== CNCL-6: `5dive council` (v0.11) ====================
# Standalone deliberation council. The engine + CLI are node modules (src/council/
# engine.mjs + cli.mjs); this bundle ships as ONE bash file, so they are embedded
# below and materialized to a temp dir at call time — the same self-contained
# pattern as `memory search`. This file is GENERATED by src/council/gen_cmd.mjs
# from those two canonical sources; edit the .mjs (or the template) and re-run the
# generator, never this embedded copy. Drift is caught by tests/council_cli_contract.mjs.
#
# Ports the four tested prototypes (convene/verdict, gate-clear map, loop+node,
# standing benches + tamper-evident receipt). Model calls go through the A-with-seam
# adapter (COUNCIL_API_KEY / COUNCIL_BASE_URL); COUNCIL_MOCK=1 runs offline.

COUNCIL_DIR="${STATE_DIR}/council"
COUNCIL_REGISTRY="${COUNCIL_DIR}/benches.json"
COUNCIL_RECEIPTS="${COUNCIL_DIR}/receipts"
COUNCIL_GENESIS="${COUNCIL_DIR}/genesis.json"
COUNCIL_LINEAGE="${COUNCIL_DIR}/lineage.jsonl"

_council_constitution_path() {
  printf '%s' "${FIVEDIVE_CONSTITUTION_FILE:-${STATE_DIR}/5dive.md}"
}

# Parse the machine-enforced YAML frontmatter through the same loader the tally
# engine uses. Kept as a function (not a source-time global) so test/runtime
# STATE_DIR overrides resolve correctly.
_council_constitution_json() {
  command -v node >/dev/null 2>&1 || return 1
  local dir rc=0
  dir="$(mktemp -d -t 5dive-constitution.XXXXXX)" || return 1
  _council_write_runtime "$dir"
  node "$dir/cli.mjs" constitution --path="$(_council_constitution_path)" || rc=$?
  rm -rf "$dir"
  return "$rc"
}

_council_hard_gate_rx() {
  _council_constitution_json | jq -r '.hardGateRegex'
}

_council_help() {
  cat >&2 <<'COUNCIL_HELP'
5dive council — standalone deliberation council (v0.11)

  5dive council init --seats=<a:chair,b,c,...> --threshold=<majority|all|N|a/b> --veto=<principal>
      Human-seed the primary Council ONCE (sudo-gated, fail-closed if already initialized;
      --force re-seeds and the re-seed is logged in the lineage). The veto principal must be
      RESOLVABLE (human:<agent> -> that agent's paired human, or tg:<user_id>) or init refuses
      it. The genesis record is sealed on the root gate-proof rail and hash-chained into
      ${COUNCIL_LINEAGE}. Principle: an agent must not bootstrap its own governance body.

  5dive council lineage [verify|ls]
      Verify the sealed genesis lineage (re-seal each record, compare digests, check the
      hash-chain) or list it. `verify` fails closed on any tamper or broken link.

  5dive council roster
      The live Council: current seats, the pass threshold + quorum, the founder-veto holder,
      and the sealed lineage head (seq + digest) rooted at genesis.

  5dive council log [--limit=N]
      The past sealed verdicts — genesis + every promote/demote motion + any founder veto —
      in lineage order (the append-only governance record).

  5dive council verify [<receipt-digest>]
      Verify the WHOLE governance lineage: the prevDigest hash-chain AND a per-record ROOT
      re-seal (each canonical must re-seal to its stored digest). Fails closed on an edited,
      dropped, or reordered record. With a receipt digest, also re-seals that sealed receipt.

  sudo 5dive council {promote|demote|expel} --subject=<seat> [--lens="…"] [--mode=…] [--dry-run]
      Run a membership MOTION as a convened Council vote (sudo-gated — it mutates the root-owned
      roster + lineage). The subject RECUSES (does not vote on its own membership); the class is
      auto-derived IN CODE (promote = simple majority, demote/expel = 2/3 supermajority; a motion
      touching a governance param is forced constitutional). On a PASS the roster is mutated and a
      root-sealed motion record is hash-chained onto the lineage; a non-pass leaves the roster
      untouched. The convene receipt that decided it is linked from the motion record.

  5dive council convene "<question>" [--seats=a,b,c] [--mode=quick|deliberate|adversarial]
                                     [--bench=<name>] [--class=<decisionClass>]
                                     [--threshold=<n>]
                                     [--timeout=120] [--idle-secs=5] [--poll-secs=2] [--standalone]
      Convene a council over a question. By DEFAULT (CNCL-7) it DISPATCHES the question
      to the real seated agents — each seat votes via its OWN harness over the
      `5dive agent ask` rail, no shared model key. A seat that times out or replies
      without a COUNCIL-VOTE line is a recorded ABSTAIN; a convene that falls below
      quorum returns no verdict and auto-escalates with a human brief. The first round
      is BLIND (no seat sees another before its own vote); adversarial adds a rebuttal
      round, recorded separately. Emits an auditable verdict (deterministic tally over
      the current roster) and a tamper-evident, root-signed receipt. On a primary-council
      PASS it also OFFERS the founder veto to the genesis principal (CNCL-9, non-blocking):
      the pass stands, the receipt stamps executeAfter + a one-time tap nonce, and a ping
      fires. Defaults to the 5-seat standing Council. --standalone selects the deferred
      single-key modelCall seam instead of dispatch.
      (A veto can NEVER be asserted from a CLI string — `--veto-by` is refused; see below.)

  5dive council veto exercise --receipt=<sealed digest> --nonce=<tap nonce>
                              [--tier=hold|posthoc] [--reason=<why>]
      Exercise the founder veto on a sealed pass — the authenticated tap. The one-time
      nonce (minted at seal, bound to the offered recipient) authenticates it; `hold`
      (within veto_hold, default 15m) flips the pass to BLOCKED before execution,
      `posthoc` (until veto_posthoc, default 48h) flips it and flags an unwind. The flip
      is a NEW root-sealed record hash-chained to the original verdict digest; the
      original receipt is never mutated. Tier is auto-derived from the clock if omitted.

  5dive council sign-vote --seat=<id> --vote=<approve|reject|escalate|abstain>
                          --convene=<id> (--qdigest=<hex> | --question=<text>)
                          --key-file=<seat PKCS8 PEM | "-"> [--rationale=…] [--emit=line|json]
      (CNCL-10) A SEAT signs its own vote at source, from its OWN harness — sign-at-source,
      so the shell is the surface (a seat has no node of its own). Emits the `COUNCIL-SIG:`
      line the seat pastes after its COUNCIL-VOTE line (--emit=json for the full row). The
      convene id + question digest are in the signed bytes, so the signature is replay-proof.

  5dive council verify-votes --votes=<json|@file> --roster=<json|@file>
                             --convene=<id> (--qdigest=<hex> | --question=<text>)
      (CNCL-10) Re-check EVERY co-signed vote against the roster pubkeys + revocation, bound
      to THIS convene. Exits non-zero if any non-abstain vote is unsigned/forged/replayed/
      revoked, so a caller can gate on the exit code.

  5dive council bench ls
  5dive council bench show <name>
  5dive council bench add  <name> --seats=a:lens|b:lens [--mode=] [--threshold=] [--desc=]
  5dive council bench rm   <name>
      Manage the persisted, editable registry of standing benches (built-ins:
      council, ship, brand, security — fail-closed on an unknown name; add/rm are
      privileged governance writes and need sudo).

  5dive council gate-clear <task|DIVE-N> [--mode=deliberate] [--seats=a,b,c] [--dry-run]
      (CNCL-12) Route an OPEN tier-1 gate to the council. The escalate-only guardrail
      runs first: a tier>=2 gate or a human-only type (secret/approval/manual/access)
      is NEVER self-cleared — it is bumped to a human with a one-paragraph brief. A genuine
      tier-1 gate is convened (default: the primary Council), and the sealed verdict either
      CLEARS it (`task answer` with the recommendation) or escalates it with the brief.
      --dry-run prints the planned action without touching the gate.

  5dive council rot-triage [<task|DIVE-N> | --all] [--older-than-hours=48] [--dry-run]
      (CNCL-12) Rot-triage stale tier-2 gates: a tier-2 gate left UNANSWERED for 48h+
      is convened ONLY to re-brief it sharper for the human (and, in that brief, propose
      a rescope or a park+wake). It NEVER clears a tier-2 gate — tier-2 stays human-only
      (fail-closed). --all scans every stale tier-2 gate; --dry-run lists them without
      convening. Wired into the heartbeat behind COUNCIL_ROT_TRIAGE=on (default off).

  Add --json for a machine envelope. The default dispatch path needs NO model key
  (each seat uses its own harness). The --standalone seam uses COUNCIL_API_KEY
  (A-with-seam; BYO/OpenRouter via COUNCIL_BASE_URL). COUNCIL_MOCK=1 runs a
  deterministic offline council (no key, no network, no agent dispatch) for tests + smoke.
COUNCIL_HELP
}

_council_write_runtime() {
  local dir="$1"
  cat > "$dir/engine.mjs" <<'COUNCIL_ENGINE_MJS'
// The Council — standalone deliberation engine (CNCL-6, v0.11).
//
// Reimplements the four tested Workflow-harness prototypes (council/council-*.js:
// P0 convene, P1 gate-clear, P2 loop-verifier + goal-DAG node, P3 standing benches
// + tamper-evident receipt) as a standalone node module callable from any shell via
// the `5dive council` CLI. Seats call the model API DIRECTLY through the injectable
// `modelCall` adapter (A-with-seam: Anthropic Messages shape by default, {baseUrl,
// model,apiKey} behind config so a BYO/OpenRouter key drops in later with no engine
// rework). No Workflow harness, no `agent()` global.
//
// The PURE LOGIC region below (verdict->action maps + escalate-only guardrail +
// standing registry + receipt canonicalization) is ported VERBATIM from the
// prototypes and sliced by the bound contract test (no drift). The one behavioural
// invariant: a council NEVER self-clears a hard-gate class (tier>=2 or a human-only
// type) — it escalates, fail-closed on a missing tier.

import { createHash, generateKeyPairSync, sign as edSign, verify as edVerify, createPrivateKey, createPublicKey } from 'node:crypto'
import fs from 'node:fs'

// ==================== PURE LOGIC (the ported contract — auditable, offline-testable) ====================
export const HUMAN_ONLY_TYPES = ['secret', 'approval', 'manual', 'access']

// Escalate-only guardrail, shared by the gate (P1), verifier + node (P2) roles.
// tier>=2 or a human-only type is never council-decidable; a missing tier fails closed.
export function guardrail(x) {
  const tier = Number(x.tier == null ? 2 : x.tier)
  if (tier >= 2) return { forceEscalate: true, reason: `tier-${tier} hard human gate (councils escalate, never self-clear tier>=2)` }
  if (HUMAN_ONLY_TYPES.includes(x.type)) return { forceEscalate: true, reason: `type=${x.type} is human-only (money/secret/manual/access) — escalate` }
  return { forceEscalate: false, reason: '' }
}
export const gateGuardrail = guardrail   // P1 name
export const nodeGuardrail = guardrail   // P2 name

export function shellQuote(s) { return `'${String(s).replace(/'/g, `'\\''`)}'` }
export function tallyStr(t) { return `a${t.approve}/r${t.reject}/e${t.escalate}` }

// (P1) GATE-CLEAR: council verdict -> clear the gate (task answer) | bump to a human
// (task need --tier=2 + task escalate) WITH the one-paragraph brief. Never self-clears.
export function verdictToAction(gate, verdict) {
  if (verdict && verdict.recommendation === 'approve' && !verdict.escalated) {
    const value = gate.recommend && gate.recommend !== '-' ? gate.recommend : 'approve'
    return {
      action: 'clear',
      command: `5dive task answer ${gate.ident} --value=${shellQuote(`[council] ${value} (rec=${verdict.recommendation}, tally ${tallyStr(verdict.tally)}, conf ${verdict.confidence})`)}`,
      value,
    }
  }
  const brief = (verdict && (verdict.brief || verdict.dissent)) || 'Council could not clear; human decision required.'
  // PRESERVE the original gate type on re-file. Never coerce a human-only type (secret/approval/
  // manual/access) down to a free-text `decision` — that would re-open a `secret` gate (whose ask
  // may say "do NOT paste here") as a plain decision and invite the human to paste the secret onto
  // the fleet-readable board. A human-only escalation stays human-only (CNCL-12 main-gate amendment).
  const t = gate.type || 'decision'
  return {
    action: 'escalate',
    command: `5dive task need ${gate.ident} --type=${t} --tier=2 --ask=${shellQuote(`[council escalation] ${brief} — original ask: ${gate.ask}`)}`
      + (gate.recommend && gate.recommend !== '-' ? ` --recommend=${shellQuote(gate.recommend)}` : '')
      + (gate.options ? ` --options=${shellQuote(gate.options)}` : '')
      + ` && 5dive task escalate ${gate.ident} --from=council`,
    brief,
  }
}

// (P2a) LOOP VERIFIER: approve -> task done | reject -> task reject --feedback (stays
// in the loop, no human) | escalate -> task need --tier=2 + task escalate.
export function verifierVerdictToAction(task, verdict) {
  const conf = verdict.confidence, tly = tallyStr(verdict.tally)
  if (verdict.recommendation === 'approve' && !verdict.escalated) {
    return {
      action: 'accept',
      command: `5dive task done ${task.ident} --result=${shellQuote(`[council verifier] PASS (tally ${tly}, conf ${conf})`)}`,
    }
  }
  if (verdict.recommendation === 'reject' && !verdict.escalated) {
    const critique = verdict.dissent && verdict.dissent !== 'none' ? verdict.dissent : (verdict.brief || 'Did not meet the acceptance criteria.')
    return {
      action: 'reject',
      command: `5dive task reject ${task.ident} --feedback=${shellQuote(`[council verifier] FAIL (tally ${tly}). ${critique}`)}`,
    }
  }
  const brief = (verdict.brief || verdict.dissent) || 'Council could not grade; human decision required.'
  const t = task.type && HUMAN_ONLY_TYPES.indexOf(task.type) === -1 ? task.type : 'decision'
  return {
    action: 'escalate',
    command: `5dive task need ${task.ident} --type=${t} --tier=2 --ask=${shellQuote(`[council verifier escalation] ${brief} — original: ${task.ask}`)}`
      + ` && 5dive task escalate ${task.ident} --from=council`,
    brief,
  }
}

// (P2b) GOAL-DAG DECISION NODE: valid winning branch -> task answer --value | else escalate.
export function nodeVerdictToDecision(node, verdict) {
  const opts = (node.options || '').split('|').map(o => o.trim()).filter(Boolean)
  const choice = verdict.choice
  const validChoice = choice && opts.length > 0 && opts.indexOf(choice) !== -1
  if (!verdict.escalated && validChoice) {
    return {
      action: 'decide',
      choice,
      command: `5dive task answer ${node.ident} --value=${shellQuote(`[council] ${choice} (conf ${verdict.confidence}, tally ${tallyStr(verdict.tally)})`)}`,
    }
  }
  const brief = (verdict.brief || verdict.dissent) || 'Council could not pick a branch; human decision required.'
  return {
    action: 'escalate',
    command: `5dive task need ${node.ident} --type=decision --tier=2 --ask=${shellQuote(`[council node escalation] ${brief} — decision: ${node.question}`)}`
      + (node.options ? ` --options=${shellQuote(node.options)}` : '')
      + ` && 5dive task escalate ${node.ident} --from=council`,
    brief,
  }
}

// (CNCL-12) T2 ROT-TRIAGE: a tier-2 gate left unanswered 48h. The council re-briefs it
// sharper (or, in its brief, recommends a rescope/park to the human) and re-escalates —
// but it NEVER clears a tier-2 gate. This is the fail-closed rule: tier-2 stays human-only,
// so this mapping has NO `task answer` branch AT ALL, not even for an `approve` verdict.
// The load-bearing invariant (asserted in the unit test): `.cleared === false` and the
// command never contains `task answer`, regardless of what the verdict says.
export function triageVerdictToAction(gate, verdict) {
  const brief = (verdict && (verdict.brief || verdict.dissent))
    || 'Council reviewed the stale gate; the human decision still stands and needs an answer.'
  // Keep the gate human-only: re-file the SAME type, ALWAYS tier-2, with a sharper one-paragraph
  // brief, then re-ping the owner. Never downgrades tier, never answers, and (CNCL-12 main-gate
  // amendment) never downgrades a human-only type to `decision` — a stale `secret` gate must be
  // re-briefed as type=secret, not re-opened as a free-text decision that invites a paste.
  const t = gate.type || 'decision'
  return {
    action: 'triage-rebrief',
    cleared: false,
    command: `5dive task need ${gate.ident} --type=${t} --tier=2 --ask=${shellQuote(`[council triage] ${brief} — original ask: ${gate.ask}`)}`
      + (gate.recommend && gate.recommend !== '-' ? ` --recommend=${shellQuote(gate.recommend)}` : '')
      + (gate.options ? ` --options=${shellQuote(gate.options)}` : '')
      + ` && 5dive task escalate ${gate.ident} --from=council-triage`,
    brief,
  }
}

// (P3.1) STANDING / NAMED COUNCILS — the built-in defaults. The CLI layer persists an
// editable copy (benches.json) seeded from these; resolveCouncil fails CLOSED on a miss.
export const STANDING_COUNCILS = {
  ship: {
    description: 'Ship-worthiness of a build/diff before it goes live.',
    mode: 'deliberate',
    seats: [
      { id: 'reviewer', lens: 'Review, correctness, ship-worthiness. Reversible? Tested? Any regression?' },
      { id: 'security', lens: 'Injection, blast radius, secrets, auth boundaries.' },
      { id: 'cost', lens: 'Token + infra spend, capacity/egress, provider concentration.' },
    ],
  },
  brand: {
    description: 'Customer-facing / brand + messaging call on a mature surface.',
    mode: 'deliberate',
    seats: [
      { id: 'brand', lens: 'Brand + customer read; how it lands, support load.' },
      { id: 'operator', lens: 'Operational soundness + ship-worthiness.' },
      { id: 'contrarian', lens: 'Divergent/contrarian; the take everyone is too polite to say.' },
    ],
  },
  security: {
    description: 'Security-sensitive change (auth, sudo, gate/tamper rails, MCP).',
    mode: 'adversarial',
    seats: [
      { id: 'security', lens: 'Injection, privilege, blast radius, forgeability.' },
      { id: 'red-team', lens: 'Actively try to REFUTE the leading option / find the bypass.' },
      { id: 'reviewer', lens: 'Correctness + reversibility of the change.' },
    ],
  },
}

// Fails CLOSED: an unknown bench name is NOT silently defaulted. Pass a registry map to
// resolve against a persisted copy; defaults to the built-ins. Returns null on a miss.
export function resolveCouncil(name, registry = STANDING_COUNCILS) {
  if (!name) return null
  const c = registry[name]
  if (!c) return null
  return { name, description: c.description, mode: c.mode, seats: c.seats }
}

// (P3.1b) THE default Council: a self-governed standing body of role-archetype
// voting seats, one vote each. Seat count is UNBOUNDED and the roster is MUTABLE — the
// council promotes/demotes seats by a quorum vote (addSeat/removeSeat, gated at the CLI
// layer by a real convene). These 5 are the STARTING membership, NOT a cap or a fixed
// roster. `threshold` is a CONFIG value (see resolveThreshold) — nothing hardcodes 5 or 3.
export const DEFAULT_COUNCIL = {
  name: 'council', description: 'The 5dive Council — self-governed standing body, one vote each. Seats mutable by quorum vote.',
  mode: 'deliberate', threshold: 3, thresholdRule: 'flat',
  seats: [
    { id: 'eng-lead', lens: 'Engineering lead. Correctness, ship-worthiness, reversibility.' },
    { id: 'brand', lens: 'Brand + customer read; how it lands publicly.' },
    { id: 'builder', lens: 'Implementation soundness, edge cases, blast radius.' },
    { id: 'strategy', lens: 'Strategic fit, organizational priorities, risk appetite.' },
    { id: 'contrarian', lens: 'Divergent view; the objection everyone is too polite to raise.' },
  ],
}

// (CNCL-16) SEAT ID vs REGISTRY AGENT. A seat `id` is a PERSONA (display + receipts). The agent
// that `5dive agent ask` dispatches to is a REGISTRY NAME, which is not always the same string:
// persona 'theo' is the 'marketing' agent, 'lilbro' is 'creative'. A seat MAY carry an explicit
// `agent` (canonical, wins); otherwise this alias map resolves the known personas; otherwise the
// id IS the registry name. Genesis/ad-hoc rosters that seed a bare persona id resolve via the map.
export const SEAT_AGENT_ALIAS = { theo: 'marketing', lilbro: 'creative' }
export function resolveSeatAgent(seat) {
  if (!seat) return ''
  if (typeof seat === 'string') return SEAT_AGENT_ALIAS[seat] || seat
  if (seat.agent && typeof seat.agent === 'string') return seat.agent
  return SEAT_AGENT_ALIAS[seat.id] || seat.id
}
export const DEFAULT_THRESHOLD = 3   // default flat pass-threshold; overridable per bench

// (P3.1b2) TIERED THRESHOLD POLICY (lodar is steering toward this). Per decision-CLASS pass
// rule + quorum, ALL config so the final numbers drop in once locked. A rule is 'flat' (fixed
// N), 'majority' (floor(seats/2)+1), or 'fraction' (ceil(value*seats), e.g. 2/3). `quorum`
// = how many of the CURRENT seats must actually vote for the result to count ('majority' by
// default, a number, or 'none'). Nothing hardcodes 5 or 3 — this map is the single knob.
export const THRESHOLD_POLICY = {
  ordinary:       { rule: 'majority',            quorum: 'majority' },
  promote:        { rule: 'majority',            quorum: 'majority' },
  demote:         { rule: 'fraction', value: 2 / 3, quorum: 'majority' },
  expel:          { rule: 'fraction', value: 2 / 3, quorum: 'majority' },
  constitutional: { rule: 'fraction', value: 2 / 3, quorum: 'all', requireQuorum: true },
}

// CNCL-14 — constitution-as-data. Missing or malformed files fall back to these
// exact pre-constitution values; a valid 5dive.md may replace them per org.
export const DEFAULT_HARD_GATE_CLASSES = {
  spend_billing: 'spend|billing|invoice|charge|payment|refund|subscription|price|pricing|\\$[0-9]|€[0-9]',
  public_comms: 'publish|public post|announce|launch post|press|customer email|email customers|newsletter|blast',
  secrets: 'secret|credential|api key|token|password',
  destructive: 'delete|destroy|teardown|wipe|purge|drop[^.]{0,20}table|truncate|irreversible|revoke|dns|domain transfer',
}
export const DEFAULT_HARD_GATE_RX = Object.values(DEFAULT_HARD_GATE_CLASSES).join('|')
export const DEFAULT_CONSTITUTION = {
  council: { bench: 'council' },
  quorum: 'majority',
  thresholds: THRESHOLD_POLICY,
  veto: { principals: [], principal: '', holdSecs: 900, posthocSecs: 172800 },
  hardGates: DEFAULT_HARD_GATE_CLASSES,
  hardGateRegex: DEFAULT_HARD_GATE_RX,
  ship: {},
  comms: {},
}

function yamlScalar(raw) {
  const s = String(raw).trim()
  if (!s) return {}
  if (s.startsWith('"') && s.endsWith('"')) return JSON.parse(s)
  if (s.startsWith("'") && s.endsWith("'")) return s.slice(1, -1).replace(/''/g, "'")
  if (s.startsWith('[') && s.endsWith(']')) {
    const inner = s.slice(1, -1).trim()
    return inner ? inner.split(',').map(x => yamlScalar(x.trim())) : []
  }
  if (/^(true|false)$/i.test(s)) return s.toLowerCase() === 'true'
  if (/^-?[0-9]+(?:\.[0-9]+)?$/.test(s)) return Number(s)
  if (/^(null|~)$/i.test(s)) return null
  return s
}

function stripYamlComment(line) {
  let single = false, double = false
  for (let i = 0; i < line.length; i++) {
    const c = line[i]
    if (c === "'" && !double) single = !single
    else if (c === '"' && !single && line[i - 1] !== '\\') double = !double
    else if (c === '#' && !single && !double && (i === 0 || /\s/.test(line[i - 1]))) return line.slice(0, i).trimEnd()
  }
  return line
}

// Deliberately small YAML-frontmatter parser: mappings + scalar/inline-array
// values are the whole enforced v0 schema. Unsupported list/object syntax fails
// closed to defaults rather than being partially interpreted.
export function parseConstitutionFrontmatter(text) {
  const lines = String(text || '').replace(/\r\n/g, '\n').split('\n')
  if (lines[0] !== '---') throw new Error('5dive.md needs YAML frontmatter')
  const end = lines.indexOf('---', 1)
  if (end < 0) throw new Error('5dive.md frontmatter is not closed')
  const root = {}
  const stack = [{ indent: -1, value: root }]
  for (const original of lines.slice(1, end)) {
    if (!original.trim() || original.trimStart().startsWith('#')) continue
    if (original.includes('\t')) throw new Error('tabs are not allowed in constitution YAML')
    const indent = original.length - original.trimStart().length
    if (indent % 2) throw new Error('constitution YAML indentation must use two spaces')
    const line = stripYamlComment(original.trim())
    if (!line) continue
    if (line.startsWith('- ')) throw new Error('use inline arrays in constitution v0')
    const m = line.match(/^([A-Za-z_][A-Za-z0-9_-]*):(?:\s+(.*))?$/)
    if (!m) throw new Error(`unsupported constitution YAML: ${line}`)
    while (stack.length > 1 && stack[stack.length - 1].indent >= indent) stack.pop()
    const parent = stack[stack.length - 1]
    if (indent > parent.indent + 2) throw new Error('constitution YAML skipped an indentation level')
    const key = m[1]
    if (['__proto__', 'prototype', 'constructor'].includes(key)) throw new Error('unsafe constitution key')
    if (Object.hasOwn(parent.value, key)) throw new Error(`duplicate constitution key: ${key}`)
    if (m[2] == null || m[2] === '') {
      parent.value[key] = {}
      stack.push({ indent, value: parent.value[key] })
    } else {
      parent.value[key] = yamlScalar(m[2])
    }
  }
  return root
}

function thresholdSpec(value, base, globalQuorum) {
  const out = { ...base }
  if (typeof value === 'string' || typeof value === 'number') {
    const v = String(value).trim()
    const frac = v.match(/^([1-9][0-9]*)\/([1-9][0-9]*)$/)
    if (frac) { out.rule = 'fraction'; out.value = Number(frac[1]) / Number(frac[2]); delete out.threshold }
    else if (v === 'majority') { out.rule = 'majority'; delete out.value; delete out.threshold }
    else if (v === 'all') { out.rule = 'fraction'; out.value = 1; delete out.threshold }
    else if (/^[1-9][0-9]*$/.test(v)) { out.rule = 'flat'; out.threshold = Number(v); delete out.value }
    else throw new Error(`invalid threshold: ${v}`)
  } else if (value && typeof value === 'object' && !Array.isArray(value)) {
    const unknown = Object.keys(value).filter(k => !['rule', 'threshold', 'value', 'quorum', 'require_quorum', 'requireQuorum'].includes(k))
    if (unknown.length) throw new Error(`unknown threshold field(s): ${unknown.join(', ')}`)
    if (value.rule != null) {
      const rule = String(value.rule)
      if (!['majority', 'fraction', 'flat'].includes(rule)) throw new Error(`invalid threshold rule: ${rule}`)
      out.rule = rule
    }
    if (value.threshold != null) { out.rule = 'flat'; out.threshold = Number(value.threshold); delete out.value }
    if (value.value != null) {
      const n = Number(value.value)
      if (!Number.isFinite(n) || n <= 0 || n > 1) throw new Error(`invalid threshold fraction: ${value.value}`)
      out.rule = 'fraction'; out.value = n; delete out.threshold
    }
    if (value.quorum != null) out.quorum = value.quorum
    if (value.require_quorum != null) {
      if (typeof value.require_quorum !== 'boolean') throw new Error('require_quorum must be true or false')
      out.requireQuorum = value.require_quorum
    }
    if (value.requireQuorum != null) {
      if (typeof value.requireQuorum !== 'boolean') throw new Error('requireQuorum must be true or false')
      out.requireQuorum = value.requireQuorum
    }
  } else throw new Error('threshold must be a scalar or mapping')
  if (out.quorum == null) out.quorum = globalQuorum
  if (out.rule === 'fraction' && (!Number.isFinite(Number(out.value)) || Number(out.value) <= 0 || Number(out.value) > 1)) throw new Error('fraction threshold needs value >0 and <=1')
  if (out.rule === 'flat' && (!Number.isInteger(Number(out.threshold)) || Number(out.threshold) < 1)) throw new Error('flat threshold needs a positive integer')
  return out
}

function quorumSpec(value) {
  if (typeof value === 'number' && Number.isInteger(value) && value >= 0) return value
  const s = String(value)
  if (['majority', 'all', 'none'].includes(s)) return s
  if (/^[0-9]+$/.test(s)) return Number(s)
  throw new Error(`invalid quorum: ${s}`)
}

export function normalizeConstitution(raw = {}) {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) throw new Error('constitution frontmatter must be a mapping')
  const unknownTop = Object.keys(raw).filter(k => !['council', 'quorum', 'thresholds', 'veto', 'hard_gates', 'ship', 'comms'].includes(k))
  if (unknownTop.length) throw new Error(`unknown constitution field(s): ${unknownTop.join(', ')}`)
  if (raw.council != null && (typeof raw.council !== 'object' || Array.isArray(raw.council))) throw new Error('council must be a mapping')
  const council = raw.council || {}
  const unknownCouncil = Object.keys(council).filter(k => k !== 'bench')
  if (unknownCouncil.length) throw new Error(`unknown council field(s): ${unknownCouncil.join(', ')}`)
  if (council.bench != null && (typeof council.bench !== 'string' || !council.bench.trim())) throw new Error('council.bench must be a non-empty string')
  const globalQuorum = quorumSpec(raw.quorum == null ? DEFAULT_CONSTITUTION.quorum : raw.quorum)
  const thresholds = {}
  if (raw.thresholds != null && (typeof raw.thresholds !== 'object' || Array.isArray(raw.thresholds))) throw new Error('thresholds must be a mapping')
  const configured = raw.thresholds || {}
  const unknownClasses = Object.keys(configured).filter(k => !Object.hasOwn(THRESHOLD_POLICY, k))
  if (unknownClasses.length) throw new Error(`unknown threshold class(es): ${unknownClasses.join(', ')}`)
  for (const cls of Object.keys(THRESHOLD_POLICY)) {
    thresholds[cls] = thresholdSpec(Object.hasOwn(configured, cls) ? configured[cls] : THRESHOLD_POLICY[cls], THRESHOLD_POLICY[cls], globalQuorum)
    const classValue = configured[cls]
    const classHasQuorum = classValue && typeof classValue === 'object' && Object.hasOwn(classValue, 'quorum')
    thresholds[cls].quorum = quorumSpec(thresholds[cls].quorum)
    if (raw.quorum != null && cls !== 'constitutional' && !classHasQuorum) thresholds[cls].quorum = globalQuorum
  }
  if (raw.veto != null && (typeof raw.veto !== 'object' || Array.isArray(raw.veto))) throw new Error('veto must be a mapping')
  const veto = raw.veto || {}
  const unknownVeto = Object.keys(veto).filter(k => !['principal', 'principals', 'hold_secs', 'posthoc_secs'].includes(k))
  if (unknownVeto.length) throw new Error(`unknown veto field(s): ${unknownVeto.join(', ')}`)
  if (veto.principal != null && typeof veto.principal !== 'string') throw new Error('veto.principal must be a string')
  if (veto.principals != null && (!Array.isArray(veto.principals) || veto.principals.some(x => typeof x !== 'string'))) throw new Error('veto.principals must be an inline string array')
  if (veto.principal && veto.principals) throw new Error('use veto.principal or veto.principals, not both')
  const principals = Array.isArray(veto.principals) ? veto.principals : (veto.principal ? [veto.principal] : [])
  const seconds = (v, fallback, field) => {
    if (v == null) return fallback
    if (!Number.isInteger(v) || v < 0) throw new Error(`${field} must be a non-negative integer`)
    return v
  }
  let hardGates = DEFAULT_CONSTITUTION.hardGates
  let hardGateRegex = DEFAULT_HARD_GATE_RX
  if (Object.hasOwn(raw, 'hard_gates')) {
    if (!raw.hard_gates || typeof raw.hard_gates !== 'object' || Array.isArray(raw.hard_gates)) throw new Error('hard_gates must be a mapping')
    hardGates = Object.fromEntries(Object.entries(raw.hard_gates).map(([k, v]) => {
      if (typeof v !== 'string') throw new Error(`hard_gates.${k} must be a regex string`)
      if (/\(\?|\\[bBdDsSwW]|\\[1-9]/.test(v)) throw new Error(`hard_gates.${k} uses syntax outside POSIX ERE`)
      return [k, v]
    }))
    hardGateRegex = Object.values(hardGates).filter(Boolean).map(x => `(${x})`).join('|') || 'a^'
    new RegExp(hardGateRegex, 'i')
  }
  for (const section of ['ship', 'comms']) {
    if (raw[section] != null && (typeof raw[section] !== 'object' || Array.isArray(raw[section]))) throw new Error(`${section} must be a mapping`)
  }
  return {
    council: { bench: String(council.bench || DEFAULT_CONSTITUTION.council.bench) },
    quorum: globalQuorum,
    thresholds,
    veto: {
      principals,
      principal: principals[0] || '',
      holdSecs: seconds(veto.hold_secs, DEFAULT_CONSTITUTION.veto.holdSecs, 'veto.hold_secs'),
      posthocSecs: seconds(veto.posthoc_secs, DEFAULT_CONSTITUTION.veto.posthocSecs, 'veto.posthoc_secs'),
    },
    hardGates, hardGateRegex,
    ship: raw.ship && typeof raw.ship === 'object' ? raw.ship : {},
    comms: raw.comms && typeof raw.comms === 'object' ? raw.comms : {},
  }
}

export function loadConstitution(path, readFile = p => fs.readFileSync(p, 'utf8')) {
  if (!path) return { ...normalizeConstitution({}), source: 'defaults', path: '', valid: true, error: null }
  try {
    if (!fs.existsSync(path)) return { ...normalizeConstitution({}), source: 'defaults', path, valid: true, error: null }
    return { ...normalizeConstitution(parseConstitutionFrontmatter(readFile(path))), source: 'file', path, valid: true, error: null }
  } catch (e) {
    return { ...normalizeConstitution({}), source: 'defaults', path, valid: false, error: String(e && e.message || e) }
  }
}

// Resolve the numeric pass-threshold for a roster from a spec. 'flat' (fixed N, clamped to
// the roster), 'majority' (floor/2+1), 'fraction' (ceil(value*seats)). Never hardcoded.
export function resolveThreshold(seatCount, spec = {}) {
  const n = Number(seatCount) || 0
  const rule = spec.rule || spec.thresholdRule || (spec.threshold != null ? 'flat' : 'majority')
  if (rule === 'fraction') return Math.max(1, Math.ceil(Number(spec.value) * n))
  if (rule === 'flat') { const t = Number(spec.threshold == null ? DEFAULT_THRESHOLD : spec.threshold); return Math.max(1, n ? Math.min(t, n) : t) }
  return Math.floor(n / 2) + 1   // majority / quorum
}

// How many of the current seats must actually vote for a result to count (the quorum GATE).
export function quorumSize(seatCount, spec = {}) {
  const n = Number(seatCount) || 0
  const q = spec.quorum
  if (typeof q === 'number') return q
  if (q === 'none') return 0
  if (q === 'all') return n   // full quorum: every current seat must vote (constitutional)
  return Math.floor(n / 2) + 1   // default: majority participation
}

// (P3.1c) DETERMINISTIC tally -> verdict. Enforces the QUORUM gate first (an inquorate vote
// can't decide -> escalate), then passes iff approve-count reaches the class threshold. Not a
// pass is a reject, unless escalate is the plurality (a genuine "needs a human" split). The
// chair LLM only narrates — the PASS/FAIL is an auditable count over the current roster.
// opts: { decisionClass, policy, seatCount, threshold, thresholdRule } — explicit
// threshold/thresholdRule override the class policy (for ad-hoc convenes/tests).
export function tallyVotes(votes, opts = {}) {
  // CNCL-11 RECUSAL: the subject of a promote/demote motion does not vote — its seat is dropped
  // from BOTH the quorum base and the threshold base, so the vote runs over the remaining seats.
  const recuse = new Set([].concat(opts.recuse || []).filter(Boolean).map(String))
  const counted = (votes || []).filter(v => !recuse.has(String(v.seat)))
  const tally = { approve: 0, reject: 0, escalate: 0 }
  for (const v of counted) { if (tally[v.vote] != null) tally[v.vote]++ }
  let seatCount = opts.seatCount || (votes || []).length
  if (recuse.size) seatCount = Math.max(1, seatCount - recuse.size)
  // CNCL-11 CONSTITUTIONAL AUTO-CLASS: a motion touching a governance param is classified in
  // CODE, so a caller can never run a rule change under the ordinary bar by mislabelling it.
  const cls = opts.decisionClass || (opts.motion ? classifyMotion(opts.motion) : 'ordinary')
  const policy = (opts.policy || THRESHOLD_POLICY)[cls] || THRESHOLD_POLICY.ordinary
  const spec = { ...policy }
  if (opts.threshold != null) { spec.rule = 'flat'; spec.threshold = opts.threshold }
  if (opts.thresholdRule) spec.rule = opts.thresholdRule
  const votesCast = tally.approve + tally.reject + tally.escalate
  const quorum = quorumSize(seatCount, spec)
  const quorumMet = votesCast >= quorum
  const threshold = resolveThreshold(seatCount, spec)
  let recommendation
  if (!quorumMet) recommendation = 'escalate'                       // inquorate -> can't decide, surface
  else if (tally.approve >= threshold) recommendation = 'approve'
  else if (tally.escalate > tally.approve && tally.escalate >= tally.reject) recommendation = 'escalate'
  else recommendation = 'reject'
  return { recommendation, tally, threshold, seatCount, quorum, quorumMet, votesCast, decisionClass: cls, recused: [...recuse], escalated: recommendation === 'escalate' }
}

// (P3.1e) SELF-GOVERNANCE — pure roster mutations. The CLI gates each behind a real council
// quorum vote (a convene that must pass); these just produce the new, de-duplicated roster.
export function addSeat(seats, seat) {
  const s = typeof seat === 'string' ? { id: seat } : seat
  if (!s || !s.id) throw new Error('addSeat: seat needs an id')
  if ((seats || []).some(x => x.id === s.id)) return seats.slice()   // already seated (idempotent)
  return [...(seats || []), { id: s.id, lens: s.lens || `${s.id} — council seat.` }]
}
export function removeSeat(seats, seatId) {
  return (seats || []).filter(x => x.id !== seatId)
}

// ============================================================================
// CNCL-11 — GOVERNANCE SURFACE: motion classification, recusal, hash-chained
// lineage (promote/demote/roster/log/verify). Pure engine; the CLI+bash own the
// sudo gate, the root seal, and the persisted lineage write.
// ============================================================================

// Governance PARAMETERS — a motion that changes any of these is constitutional (the hardest
// bar: 2/3 + full quorum + founder-veto-able) and CANNOT run as an ordinary motion.
export const CONSTITUTIONAL_PARAMS = ['threshold', 'quorum', 'veto', 'mode', 'modes']

// CNCL-11: classify a motion IN CODE (never trust a caller-supplied class). Membership motions
// (promote/demote/expel) keep their own class; ANY motion touching a governance param is forced
// to `constitutional` regardless of what it claims; everything else is `ordinary`.
export function classifyMotion(motion = {}) {
  const kind = String(motion.kind || motion.type || '').toLowerCase()
  if (kind === 'promote') return 'promote'
  if (kind === 'demote') return 'demote'
  if (kind === 'expel') return 'expel'
  const raw = motion.params || motion.changes || (motion.param != null ? [motion.param] : [])
  const touched = Array.isArray(raw) ? raw : Object.keys(raw || {})
  if (touched.some(p => CONSTITUTIONAL_PARAMS.includes(String(p).toLowerCase()))) return 'constitutional'
  if (kind === 'constitutional') return 'constitutional'
  return 'ordinary'
}

// CNCL-11: the seat that must RECUSE for a given motion — the subject of a promote/demote/expel
// (they don't get to vote on their own membership). Returns [] for non-membership motions.
export function recusalFor(motion = {}) {
  const cls = classifyMotion(motion)
  return (['promote', 'demote', 'expel'].includes(cls) && motion.subject) ? [String(motion.subject)] : []
}

// CNCL-11: a promote/demote/constitutional motion runs as a convened vote; on a PASS its outcome
// is written as a lineage record HASH-CHAINED onto the prior lineage head (genesis or the last
// motion) via prevDigest — so the roster's entire history is an append-only, tamper-evident chain
// rooted at genesis. Mirrors buildGenesisRecord's discipline; bash root-seals canonicalMotion().
export function buildMotionRecord({ motion, verdict, seats, threshold, veto, prevDigest, stampedAt, seq, receiptDigest }) {
  const cls = classifyMotion(motion)
  if (!['promote', 'demote', 'expel', 'constitutional'].includes(cls)) {
    throw new Error(`buildMotionRecord: '${cls}' is not a governance motion (promote|demote|expel|constitutional)`)
  }
  if (!Array.isArray(seats) || !seats.length) throw new Error('motion record needs the resulting seats')
  return {
    kind: 'motion',
    version: 1,
    seq: Number(seq) || 0,
    council: 'council',
    motion: {
      class: cls,
      subject: motion.subject != null ? String(motion.subject) : null,
      param: motion.param != null ? String(motion.param) : null,
      to: motion.to != null ? String(motion.to) : null,
    },
    outcome: (verdict && verdict.recommendation) || null,
    tally: (verdict && verdict.tally) || null,
    recused: (verdict && verdict.recused) || recusalFor(motion),
    seats: seats.map(s => ({ id: s.id, lens: s.lens, ...(s.chair ? { chair: true } : {}) })),
    threshold: threshold || { rule: 'majority' },
    veto: veto ? { principal: veto.principal, resolved: String(veto.resolved) } : null,
    receiptDigest: receiptDigest || '',   // links the motion to the convene receipt that decided it
    prevDigest: prevDigest || '',
    stampedAt: stampedAt || '',
  }
}

// Deterministic, whitespace-normalized preimage of a motion record — the bytes the ROOT rail
// seals + hash-chains. Same discipline as canonicalGenesis: prevDigest + outcome + the resulting
// roster INSIDE the signed bytes so none can be quietly altered without failing verify.
export function canonicalMotion(rec) {
  const norm = (s) => String(s == null ? '' : s).replace(/\s+/g, ' ').trim()
  const m = rec.motion || {}
  const t = rec.tally || {}
  const L = []
  L.push(`motion: ${norm(rec.council)} v${Number(rec.version) || 1} seq=${Number(rec.seq) || 0}`)
  L.push(`class: ${norm(m.class)}`)
  L.push(`subject: ${norm(m.subject)}`)
  L.push(`param: ${norm(m.param)} -> ${norm(m.to)}`)
  L.push(`outcome: ${norm(rec.outcome)}`)
  L.push(`tally: a${Number(t.approve) || 0}/r${Number(t.reject) || 0}/e${Number(t.escalate) || 0}`)
  L.push(`recused: ${(rec.recused || []).slice().sort().map(norm).join(',')}`)
  L.push(`stampedAt: ${norm(rec.stampedAt)}`)
  L.push(`prevDigest: ${norm(rec.prevDigest)}`)
  L.push(`receiptDigest: ${norm(rec.receiptDigest)}`)
  const seats = (rec.seats || []).slice().sort((a, b) => (norm(a.id) < norm(b.id) ? -1 : 1))
  for (const s of seats) L.push(`seat ${norm(s.id)}${s.chair ? ' (chair)' : ''}: ${norm(s.lens)}`)
  const th = rec.threshold || {}
  L.push(`threshold: rule=${norm(th.rule)} value=${th.value != null ? Number(th.value) : ''} flat=${th.threshold != null ? Number(th.threshold) : ''}`)
  L.push(`veto: ${norm(rec.veto && rec.veto.principal)} -> ${norm(rec.veto && rec.veto.resolved)}`)
  return L.join('\n')
}

// CNCL-11: reduce a sealed lineage record to its chain entry — the fields that make the log
// tamper-evident. `digest` is the ROOT seal of the record's canonical bytes (bash computes it).
export function chainEntryOf(rec, digest) {
  return { seq: Number(rec.seq) || 0, prevDigest: rec.prevDigest || '', digest: String(digest || '') }
}

// CNCL-11: verify the append-only lineage CHAIN. `entries` is the ordered log — each entry
// { seq, prevDigest, digest }, digest = the record's root seal. Rooted at genesis (prevDigest
// === ''). Tamper-evidence across the WHOLE log, not one record: an edited record changes its
// digest so the NEXT entry's prevDigest link breaks; a dropped or reordered record breaks the
// prevDigest link and/or seq monotonicity. Returns { ok, head, length } or { ok:false, reason, index }.
export function verifyLineageChain(entries) {
  const list = entries || []
  if (!list.length) return { ok: false, reason: 'empty lineage — no genesis root', index: -1 }
  let prev = ''
  for (let i = 0; i < list.length; i++) {
    const e = list[i]
    if (!e || !e.digest) return { ok: false, reason: `record ${i} has no sealed digest`, index: i }
    if (i === 0) {
      if (e.prevDigest) return { ok: false, reason: 'genesis root must have an empty prevDigest', index: 0 }
    } else {
      if (String(e.prevDigest) !== String(prev)) {
        return { ok: false, reason: `broken chain at record ${i} (seq ${e.seq}): prevDigest ${String(e.prevDigest).slice(0, 12)}… != prior digest ${String(prev).slice(0, 12)}… (edited/dropped/reordered record)`, index: i }
      }
      if (Number(e.seq) <= Number(list[i - 1].seq)) {
        return { ok: false, reason: `non-monotonic seq at record ${i} (${list[i - 1].seq} -> ${e.seq}) — a reordered or dropped record`, index: i }
      }
    }
    prev = e.digest
  }
  return { ok: true, head: prev, length: list.length }
}

// (CNCL-9) AUTHENTICATED FOUNDER VETO — non-blocking OFFER model.
//
// The pre-CNCL-9 design flipped the verdict inline from a plain `--veto-by` CLI STRING, so any
// agent could forge lodar's veto straight into a signed receipt. That path is gone. Now:
//
//   1. convene NEVER waits for a tap and NEVER flips on a string. On a pass it records a
//      timeboxed OFFER (attachVetoOffer) naming the resolved genesis principal + window, seals
//      immediately, and the work proceeds. Expiry with no tap = the pass stands, and the receipt
//      already reads `veto-offered-not-exercised` (default-proceed is the do-nothing path).
//   2. The EXERCISE is a separate, authenticated event: only a tap confirmed on the tier-2 rail
//      by the resolved principal (bash validates the nonce->recipient binding) calls
//      exerciseFounderVeto, which flips the pass to BLOCKED inside a fresh record that is
//      root-sealed and hash-chained onto the convene receipt (the original bytes are never
//      re-sealed — post-hoc-after-seal re-seal stays deferred; the chain carries the flip).
//   3. Veto is FINAL — no council override. Hard-gate classes escalate upstream regardless.

// Non-blocking: attach a timeboxed veto OFFER to a pass. Disposition stays `pass` (the work is
// not blocked); the offer rides inside the sealed bytes so "an offer was made" is auditable.
// A non-pass verdict is returned unchanged (nothing to offer a veto on).
export function attachVetoOffer(verdict, offer) {
  if (!offer || !offer.principal || !offer.resolved) return verdict
  const passed = verdict.recommendation === 'approve' && !verdict.escalated
  if (!passed) return verdict
  return {
    ...verdict,
    vetoOffer: {
      principal: String(offer.principal),
      resolved: String(offer.resolved),
      windowSecs: Number(offer.windowSecs) || 0,
      state: 'offered-not-exercised',
    },
  }
}

// Authenticated EXERCISE (the confirmed tap) — TWO-TIER (lodar-locked):
//   tier='hold'    — the tap landed inside the 15m pre-execution hold; the work never ran.
//   tier='posthoc' — the tap landed after execution (up to veto_posthoc/48h); the verdict is
//                    overruled and the (reversible) work must be UNWOUND (manual unwind in v0.11).
// `veto` MUST carry the principal the bash rail authenticated (veto.by) and the resolved recipient
// the offer was made to (veto.resolved); bash has already proven the tap came from that recipient
// over the tier-2 nonce rail — the engine never trusts a bare string. The flip only applies to a
// verdict that carried the matching offer; anything else is returned unchanged (fail-closed).
// This builds the FLIPPED verdict for a NEW record; the caller hash-chains it to the original
// verdict digest and root-seals it. The original convene receipt is never re-signed or mutated.
export function exerciseFounderVeto(verdict, veto) {
  if (!veto || !veto.by || !veto.resolved) return verdict
  const offer = verdict.vetoOffer
  if (!offer || String(offer.resolved) !== String(veto.resolved)) return verdict
  const passed = verdict.recommendation === 'approve' && !verdict.escalated
  if (!passed) return verdict
  const tier = veto.tier === 'posthoc' ? 'posthoc' : 'hold'
  const briefHead = tier === 'posthoc'
    ? `Post-hoc founder veto by ${veto.by}: pass (tally ${tallyStr(verdict.tally)}) overruled — reversible work must be unwound.`
    : `Founder veto by ${veto.by}: pass (tally ${tallyStr(verdict.tally)}) held and flipped to BLOCKED before execution.`
  return {
    ...verdict,
    disposition: 'blocked',
    vetoed: true,
    vetoedBy: veto.by,
    vetoReason: veto.reason || '',
    vetoTier: tier,
    unwindRequired: tier === 'posthoc',
    vetoOffer: { ...offer, state: 'exercised' },
    brief: `${briefHead}${veto.reason ? ` Reason: ${veto.reason}` : ''}`,
  }
}

// Veto window durations. lodar-locked defaults: 15m pre-execution HOLD, 48h POST-HOC override.
// These are the seam CNCL-13/14 redirects to the `5dive.md` constitution — until then they read
// from the environment (bash sources the constitution or falls back), NEVER inline magic numbers.
export const VETO_DEFAULTS = { holdSecs: 15 * 60, posthocSecs: 48 * 60 * 60 }
export function vetoConfig(env = {}) {
  const n = (v, d) => { const x = Number(v); return Number.isFinite(x) && x > 0 ? x : d }
  return {
    holdSecs: n(env.COUNCIL_VETO_HOLD_SECS, VETO_DEFAULTS.holdSecs),
    posthocSecs: n(env.COUNCIL_VETO_POSTHOC_SECS, VETO_DEFAULTS.posthocSecs),
  }
}

// Build the chained veto RECORD emitted by an authenticated exercise. It is a distinct object from
// the convene receipt: it references the original verdict digest (origDigest) so the whole history
// links back without ever re-signing the original bytes. The caller root-seals `canonical` and
// stores {digest, prevDigest: origDigest, ...} — same hash-chain discipline as the genesis lineage.
export function buildVetoRecord({ origDigest, tier, by, resolved, reason, stampedAt, flippedVerdict }) {
  if (!origDigest) throw new Error('veto record needs the original verdict digest to chain to')
  if (!by || !resolved) throw new Error('veto record needs an authenticated principal (by) + resolved recipient')
  const t = tier === 'posthoc' ? 'posthoc' : 'hold'
  return {
    kind: 'veto',
    tier: t,
    origDigest: String(origDigest),
    by: String(by),
    resolved: String(resolved),
    reason: reason || '',
    unwindRequired: t === 'posthoc',
    stampedAt: stampedAt || '',
    disposition: 'blocked',
    tally: (flippedVerdict && flippedVerdict.tally) || null,
  }
}

// Deterministic, whitespace-normalized preimage of a veto record — the origDigest link is INSIDE
// the signed bytes so the chain cannot be re-pointed, and the tier/unwind flag cannot be stripped.
export function canonicalVetoRecord(rec) {
  const norm = (s) => String(s == null ? '' : s).replace(/\s+/g, ' ').trim()
  const t = rec.tally || {}
  return [
    `kind: veto`,
    `tier: ${norm(rec.tier)}`,
    `origDigest: ${norm(rec.origDigest)}`,
    `by: ${norm(rec.by)}`,
    `resolved: ${norm(rec.resolved)}`,
    `reason: ${norm(rec.reason)}`,
    `unwindRequired: ${!!rec.unwindRequired}`,
    `stampedAt: ${norm(rec.stampedAt)}`,
    `disposition: blocked`,
    `tally: a${Number(t.approve) || 0}/r${Number(t.reject) || 0}/e${Number(t.escalate) || 0}`,
  ].join('\n')
}

// The plain-English disposition of a (possibly vetoed) verdict.
export function dispositionOf(verdict) {
  if (verdict.vetoed) return 'blocked'
  if (verdict.escalated || verdict.recommendation === 'escalate') return 'escalate'
  if (verdict.recommendation === 'approve') return 'pass'
  return 'reject'
}

// (P3.2) TAMPER-EVIDENT RECEIPT — deterministic, order-independent, whitespace-normalized
// canonicalization of the whole deliberation; the dissent is INSIDE the signed bytes so it
// can't be quietly dropped. No in-engine clock: caller supplies rec.stampedAt.
export function canonicalTranscript(rec) {
  const norm = (s) => String(s == null ? '' : s).replace(/\s+/g, ' ').trim()
  const L = []
  L.push(`council: ${norm(rec.council)}`)
  L.push(`mode: ${norm(rec.mode)}`)
  L.push(`stampedAt: ${norm(rec.stampedAt)}`)
  L.push(`question: ${norm(rec.question)}`)
  L.push(`seats: ${(rec.seats || []).map(norm).slice().sort().join(',')}`)
  const votes = (rec.votes || []).slice().sort((a, b) => (norm(a.seat) < norm(b.seat) ? -1 : 1))
  for (const v of votes) L.push(`vote ${norm(v.seat)}: ${norm(v.vote != null ? v.vote : v.choice)} :: ${norm(v.rationale)}`)
  // CNCL-7: in adversarial mode the FINAL votes above are ROUND 2. Seal the sorted round-1
  // history too so a between-round seat flip cannot be misrepresented without failing verify
  // (the deliberative record is the product, not only the final tally). round1Votes is set on
  // the rec ONLY when a rebuttal round occurred, so a single-round receipt stays byte-identical.
  if (Array.isArray(rec.round1Votes)) {
    const r1 = rec.round1Votes.slice().sort((a, b) => (norm(a.seat) < norm(b.seat) ? -1 : 1))
    for (const v of r1) L.push(`round1 ${norm(v.seat)}: ${norm(v.vote != null ? v.vote : v.choice)} :: ${norm(v.rationale)}`)
  }
  const vd = rec.verdict || {}
  const t = vd.tally || {}
  L.push(`verdict: ${norm(vd.recommendation != null ? vd.recommendation : vd.choice)} conf=${Number(vd.confidence)} tally=a${Number(t.approve) || 0}/r${Number(t.reject) || 0}/e${Number(t.escalate) || 0} escalated=${!!vd.escalated}`)
  L.push(`dissent: ${norm(vd.dissent)}`)
  // CNCL-9: the veto OFFER and (if it happened) the EXERCISE both ride INSIDE the signed bytes,
  // so neither "an offer was made" nor "it was/wasn't exercised" can be quietly stripped. The
  // convene receipt seals with the offer's default `offered-not-exercised` state; a confirmed tap
  // seals its `exercised` flip in the CHAINED veto record (see exerciseFounderVeto), not by
  // re-signing these bytes.
  if (vd.vetoed) {
    L.push(`veto: exercised ${norm(vd.vetoTier || 'hold')} ${norm(vd.vetoedBy)} :: ${norm(vd.vetoReason)}`)
  } else if (vd.vetoOffer) {
    L.push(`veto: offered ${norm(vd.vetoOffer.principal)} window ${Number(vd.vetoOffer.windowSecs) || 0}s :: ${norm(vd.vetoOffer.state || 'offered-not-exercised')}`)
  } else {
    L.push('veto: none')
  }
  return L.join('\n')
}

// (CNCL-9 main-gate amendment) FOLD THE VETO SEAL-BINDING INTO THE SIGNED BYTES.
//
// The convene nonce digest + the executeAfter hold deadline are minted by the ROOT bash layer
// AT SEAL TIME (the engine has no clock/CSPRNG), i.e. AFTER canonicalTranscript(rec) is produced.
// Before this amendment they lived only on the UNSEALED receipt wrapper (`.vetoNonceDigest`,
// `.executeAfter`), OUTSIDE `.canonical` — so the exercise-time re-seal check (which only re-signs
// `.canonical`) did NOT cover them: an edit swapping `.vetoNonceDigest` to sha256(attacker-nonce)
// left `.canonical` untouched, the re-seal still matched, and the attacker could exercise the veto
// with a chosen nonce. FIX: bash appends this deterministic seal-binding LINE to the canonical
// BEFORE sealing, so the digest + deadline are covered by the same HMAC; exercise reads them back
// from the VERIFIED canonical (parseCanonicalVetoBinding), never from the raw wrapper. Any edit to
// the digest or deadline now changes `.canonical` and breaks the re-seal (fail-closed, refused).
//
// The line is appended (never interleaved) so a base-only receipt (no veto offer) stays byte-
// identical to CNCL-6/8. The format is a single stable line the parser round-trips exactly.
export function augmentCanonicalVetoBinding(canonical, binding) {
  const nd = String((binding && binding.nonceDigest) || '').replace(/\s+/g, '')
  const ea = String((binding && binding.executeAfter) || '').replace(/\s+/g, '')
  if (!nd && !ea) return String(canonical == null ? '' : canonical)   // nothing to bind — unchanged
  return `${String(canonical == null ? '' : canonical)}\nveto-seal: nonceDigest=${nd} executeAfter=${ea}`
}

// Parse the seal-binding back OUT of a VERIFIED canonical (the bytes that re-sealed to the stored
// digest). Returns { nonceDigest, executeAfter, stampedAt, present }. stampedAt is read from the
// canonical's own `stampedAt: ` line (already inside the sealed bytes since CNCL-6). Fail-closed:
// a canonical with no seal-binding line returns present=false + empty digest, so exercise refuses.
export function parseCanonicalVetoBinding(canonical) {
  const text = String(canonical == null ? '' : canonical)
  const m = text.match(/^veto-seal: nonceDigest=(\S*) executeAfter=(\S*)$/m)
  const sm = text.match(/^stampedAt: (.*)$/m)
  return {
    present: !!m,
    nonceDigest: m ? m[1] : '',
    executeAfter: m ? m[2] : '',
    stampedAt: sm ? sm[1].trim() : '',
  }
}

// The seal/verify run at the ROOT CLI layer (a standalone engine has no root). $RECEIPT =
// canonicalTranscript(rec) on stdin; seal stores the base64url HMAC, verify re-signs + compares.
export function sealCommands() {
  return {
    seal: `printf '%s' "$RECEIPT" | sudo 5dive gate-proof sign`,
    verify: `test "$(printf '%s' "$RECEIPT" | sudo 5dive gate-proof sign)" = "$STORED_DIGEST"`,
  }
}

// ==================== CNCL-8: human-seeded GENESIS roster ====================
// The primary council must not bootstrap its OWN membership — it is seeded ONCE by a human
// via `council init` (sudo-gated at the bash layer). These helpers build + canonicalize the
// genesis record; the bash layer seals it on the ROOT gate-proof rail and hash-chains it into
// the lineage. `council` is special in exactly one way: raw bench add/rm on it is refused (CLI
// layer) — membership changes only via promote/demote motions once the machinery lands.

// Parse a threshold SPEC string: "majority" | "all" | "3" (flat N) | "2/3" (fraction). Returns
// a spec object consumable by resolveThreshold/quorumSize. Fails CLOSED (null) on garbage.
export function parseThresholdSpec(str) {
  const s = String(str == null ? '' : str).trim().toLowerCase()
  if (!s || s === 'majority') return { rule: 'majority' }
  if (s === 'all') return { rule: 'fraction', value: 1 }
  const frac = s.match(/^(\d+)\s*\/\s*(\d+)$/)
  if (frac) { const a = Number(frac[1]), b = Number(frac[2]); if (b > 0 && a > 0 && a <= b) return { rule: 'fraction', value: a / b, label: `${a}/${b}` }; return null }
  if (/^\d+$/.test(s)) { const n = Number(s); return n > 0 ? { rule: 'flat', threshold: n } : null }
  return null
}

// Parse a genesis seat spec: "a:chair,b,c" — a comma list of ids; a token "id:chair" marks the
// chair (princeps senatus, breaks ties, votes last). Exactly one chair is allowed. Anything
// else after the colon is treated as an explicit lens. Returns { seats, chair } or throws.
export function parseGenesisSeats(spec) {
  const parts = String(spec == null ? '' : spec).split(',').map(s => s.trim()).filter(Boolean)
  const seats = []
  let chair = null
  const seen = new Set()
  for (const p of parts) {
    const i = p.indexOf(':')
    const id = (i < 0 ? p : p.slice(0, i)).trim()
    const tag = i < 0 ? '' : p.slice(i + 1).trim()
    if (!id) throw new Error(`empty seat id in "${p}"`)
    if (seen.has(id)) throw new Error(`duplicate seat: ${id}`)
    seen.add(id)
    const isChair = tag.toLowerCase() === 'chair'
    if (isChair) { if (chair) throw new Error(`more than one chair (${chair}, ${id})`); chair = id }
    const lens = (!tag || isChair) ? `${id} — council seat.` : tag
    seats.push({ id, lens, ...(isChair ? { chair: true } : {}) })
  }
  if (!seats.length) throw new Error('genesis needs at least one seat')
  return { seats, chair }
}

// Build the immutable genesis record. `veto` is { principal, resolved } — the resolvable human
// principal (e.g. human:main) plus the tg user_id the bash layer resolved it to; init REFUSES
// an unresolved principal (the record must carry a real, resolvable veto holder). prevDigest
// hash-chains this record to the prior lineage head (empty for the very first seed). No in-engine
// clock — caller supplies stampedAt (byte-reproducible canonical form).
export function buildGenesisRecord({ seats, chair, threshold, veto, prevDigest, stampedAt, forced, seq }) {
  if (!Array.isArray(seats) || !seats.length) throw new Error('genesis needs seats')
  if (!veto || !veto.principal) throw new Error('genesis needs a veto principal')
  if (!veto.resolved) throw new Error(`veto principal "${veto.principal}" did not resolve to a real recipient (fail-closed)`)
  return {
    kind: 'genesis',
    version: 1,
    seq: Number(seq) || 0,
    council: 'council',
    seats: seats.map(s => ({ id: s.id, lens: s.lens, ...(s.chair ? { chair: true } : {}) })),
    chair: chair || null,
    threshold: threshold || { rule: 'majority' },
    veto: { principal: veto.principal, resolved: String(veto.resolved) },
    forced: !!forced,
    prevDigest: prevDigest || '',
    stampedAt: stampedAt || '',
  }
}

// Deterministic, whitespace-normalized preimage of a genesis record — the bytes the ROOT rail
// seals + hash-chains. Same discipline as canonicalTranscript: order-independent seats, the veto
// + prevDigest INSIDE the signed bytes so neither can be quietly altered without failing verify.
export function canonicalGenesis(rec) {
  const norm = (s) => String(s == null ? '' : s).replace(/\s+/g, ' ').trim()
  const L = []
  L.push(`genesis: ${norm(rec.council)} v${Number(rec.version) || 1} seq=${Number(rec.seq) || 0}`)
  L.push(`stampedAt: ${norm(rec.stampedAt)}`)
  L.push(`forced: ${!!rec.forced}`)
  L.push(`prevDigest: ${norm(rec.prevDigest)}`)
  const seats = (rec.seats || []).slice().sort((a, b) => (norm(a.id) < norm(b.id) ? -1 : 1))
  for (const s of seats) L.push(`seat ${norm(s.id)}${s.chair ? ' (chair)' : ''}: ${norm(s.lens)}`)
  L.push(`chair: ${norm(rec.chair)}`)
  const th = rec.threshold || {}
  L.push(`threshold: rule=${norm(th.rule)} value=${th.value != null ? Number(th.value) : ''} flat=${th.threshold != null ? Number(th.threshold) : ''}`)
  L.push(`veto: ${norm(rec.veto && rec.veto.principal)} -> ${norm(rec.veto && rec.veto.resolved)}`)
  return L.join('\n')
}

// The bench entry a genesis record seeds into the persisted registry — the primary `council`.
export function genesisToBench(rec) {
  return {
    description: DEFAULT_COUNCIL.description,
    mode: DEFAULT_COUNCIL.mode,
    seats: rec.seats.map(s => ({ id: s.id, lens: s.lens })),
    threshold: rec.threshold,
    genesis: true,           // marks this bench as motion-governed (raw add/rm refused)
    seededAt: rec.stampedAt,
  }
}

// ==================== schemas (ported from P0/P2) ====================
export const TAKE = { type: 'object', additionalProperties: false, required: ['seat', 'position', 'keyRisk'],
  properties: { seat: { type: 'string' }, position: { type: 'string' }, keyRisk: { type: 'string' } } }
export const VOTE = { type: 'object', additionalProperties: false, required: ['seat', 'vote', 'rationale'],
  properties: { seat: { type: 'string' }, vote: { type: 'string', enum: ['approve', 'reject', 'escalate'] }, rationale: { type: 'string' } } }
export const NODE_VOTE = { type: 'object', additionalProperties: false, required: ['seat', 'choice', 'rationale'],
  properties: { seat: { type: 'string' }, choice: { type: 'string' }, rationale: { type: 'string' } } }
const TALLY = { type: 'object', additionalProperties: false, required: ['approve', 'reject', 'escalate'],
  properties: { approve: { type: 'integer' }, reject: { type: 'integer' }, escalate: { type: 'integer' } } }
export const VERDICT = { type: 'object', additionalProperties: false,
  required: ['recommendation', 'tally', 'confidence', 'dissent', 'escalated', 'brief'],
  properties: {
    recommendation: { type: 'string', enum: ['approve', 'reject', 'escalate'] }, tally: TALLY,
    confidence: { type: 'number' }, dissent: { type: 'string' }, escalated: { type: 'boolean' }, brief: { type: 'string' } } }
export const NODE_VERDICT = { type: 'object', additionalProperties: false,
  required: ['choice', 'tally', 'confidence', 'dissent', 'escalated', 'brief'],
  properties: {
    choice: { type: 'string' }, tally: TALLY,
    confidence: { type: 'number' }, dissent: { type: 'string' }, escalated: { type: 'boolean' }, brief: { type: 'string' } } }

// ==================== model-call adapter (A-with-seam) ====================
// Minimal structural validation of a model's forced-tool output against a schema — enough
// to catch a malformed object and trigger one retry (NOT a full JSON-schema validator).
export function validateAgainstSchema(obj, schema) {
  if (obj == null || typeof obj !== 'object') return 'not an object'
  for (const key of schema.required || []) {
    if (!(key in obj)) return `missing required field: ${key}`
  }
  for (const [k, spec] of Object.entries(schema.properties || {})) {
    if (!(k in obj)) continue
    if (spec.enum && !spec.enum.includes(obj[k])) return `field ${k}='${obj[k]}' not in enum`
    if (spec.type === 'integer' && !Number.isInteger(obj[k])) return `field ${k} not an integer`
    if (spec.type === 'string' && typeof obj[k] !== 'string') return `field ${k} not a string`
  }
  return null
}

// Build the default Anthropic-Messages modelCall. The seam: pass {baseUrl, model, apiKey}
// (and later a provider variant) without touching the engine. Returns a validated object
// matching `schema` via a forced `emit` tool, with one retry on a malformed result.
export function makeAnthropicModelCall(config = {}) {
  const baseUrl = (config.baseUrl || process.env.COUNCIL_BASE_URL || 'https://api.anthropic.com').replace(/\/+$/, '')
  const apiKey = config.apiKey || process.env.COUNCIL_API_KEY || ''
  const version = config.anthropicVersion || '2023-06-01'
  const maxTokens = config.maxTokens || 1024
  const fetchImpl = config.fetch || globalThis.fetch
  return async function modelCall(prompt, schema, opts = {}) {
    if (!apiKey) throw new Error('COUNCIL_API_KEY is not set — provision it via `5dive secret` (see CNCL-6). The engine is testable with a mock modelCall without a live key.')
    const model = opts.model || config.model || 'claude-sonnet-5'
    const body = {
      model, max_tokens: maxTokens,
      messages: [{ role: 'user', content: prompt }],
      tools: [{ name: 'emit', description: 'Return your answer as a structured object.', input_schema: schema }],
      tool_choice: { type: 'tool', name: 'emit' },
    }
    let lastErr = ''
    for (let attempt = 0; attempt < 2; attempt++) {
      const res = await fetchImpl(`${baseUrl}/v1/messages`, {
        method: 'POST',
        headers: { 'content-type': 'application/json', 'x-api-key': apiKey, 'anthropic-version': version },
        body: JSON.stringify(body),
      })
      if (!res.ok) { lastErr = `HTTP ${res.status}`; continue }
      const data = await res.json()
      const tool = (data.content || []).find(b => b.type === 'tool_use' && b.name === 'emit')
      const obj = tool && tool.input
      const err = validateAgainstSchema(obj, schema)
      if (!err) return obj
      lastErr = err
    }
    throw new Error(`modelCall failed to produce a valid ${schema.required ? schema.required.join('/') : 'object'} after retry: ${lastErr}`)
  }
}

// ==================== DISPATCH (CNCL-7): convene -> real seated agents ====================
// Fleet mode: convene DISPATCHES the question to the real seated agents (the `5dive agent ask`
// rail); each seat votes via its OWN harness + model access — NO shared council key. The engine
// stays pure: the CLI injects a `seatVote(seat, ctx)` adapter that shells the ask rail; tests
// inject a deterministic mock. makeAnthropicModelCall survives only as the deferred standalone
// seam. LIVENESS: a seat that times out / replies unparseably / throws is a recorded ABSTAIN —
// never silently dropped from the roster, so the quorum gate can fail an inquorate convene
// (one dead agent must not turn 3-of-5 into 3-of-4). BLIND FIRST ROUND: a round-1 prompt is a
// pure function of (seat, question) and never embeds another seat's answer.
export const VOTE_TOKENS = ['approve', 'reject', 'escalate', 'abstain']

// Parse a seat's free-text reply (pane-scraped by `agent ask`) into a structured vote. The seat
// is instructed to END with a line `COUNCIL-VOTE: <approve|reject|escalate> :: <why>`. We take
// the LAST such line (so a seat that reasons out loud then concludes is honored), case-insensitive.
// No parseable line => null: the caller records an ABSTAIN (fail-safe — never a silent approve).
export function parseVote(reply) {
  if (!reply || typeof reply !== 'string') return null
  const re = /council-vote:\s*(approve|reject|escalate|abstain)\b\s*(?:::\s*(.*))?$/i
  let hit = null
  for (const line of reply.split(/\r?\n/)) {
    const m = line.trim().match(re)
    if (m) hit = m
  }
  if (!hit) return null
  const vote = hit[1].toLowerCase()
  const rationale = (hit[2] || '').trim() || `(${vote}, no rationale given)`
  return { vote, rationale }
}

// Build the per-seat dispatch prompt. BLIND-FIRST-ROUND invariant: round-1 output is a pure
// function of (seat, question) and NEVER embeds another seat's take/vote, so no seat anchors on
// another before its own vote is recorded. The rebuttal round (adversarial only, round 2) DOES
// show the round-1 votes and is recorded separately.
export function seatPrompt(seat, ctx = {}) {
  const round = ctx.round || 1
  const q = ctx.question || ''
  const head = `You hold the "${seat.id}" seat on the 5dive Council. Your lens: ${seat.lens || seat.id}.`
  const ask = `Question before the council: "${q}"`
  const fmt = `Reply with brief reasoning, then END with EXACTLY this line and nothing after it:
COUNCIL-VOTE: <approve|reject|escalate> :: <one-sentence rationale>
Escalate ONLY if this genuinely needs a human (money/spend, destructive/irreversible, secrets, or a brand call on a mature product) or the council is hopelessly split.`
  if (round >= 2 && Array.isArray(ctx.priorVotes) && ctx.priorVotes.length) {
    const prior = ctx.priorVotes.map(v => `- ${v.seat}: ${String(v.vote).toUpperCase()} — ${v.rationale}`).join('\n')
    return `${head}
${ask}
The council's first-round votes:
${prior}
REBUT: find the strongest objection to the leading position, then cast your FINAL vote.
${fmt}`
  }
  return `${head}
${ask}
Give your INDEPENDENT vote BEFORE hearing any other seat.
${fmt}`
}

// Normalize a seatVote adapter result into a recorded vote row. An unusable result becomes an
// ABSTAIN — counted in the roster denominator (seatCount) but not in approve/reject/escalate.
export function normalizeSeatVote(seat, res) {
  if (!res || typeof res !== 'object' || !VOTE_TOKENS.includes(res.vote)) {
    return { seat: seat.id, vote: 'abstain', rationale: (res && res.rationale) ? String(res.rationale) : 'abstained (no reply / unparseable)' }
  }
  const rationale = (res.rationale && String(res.rationale).trim()) || `(${res.vote})`
  return { seat: seat.id, vote: res.vote, rationale }
}

// Gather one round of votes from real seats via the injected dispatch adapter, in parallel. Each
// seat is isolated: it only ever sees seatPrompt(seat, ctx) this round. A seat adapter that
// rejects is caught -> abstain (liveness), so one crashed seat cannot abort the whole convene.
async function dispatchRound(seats, ctx, seatVote) {
  return Promise.all(seats.map(async (s) => {
    try { return normalizeSeatVote(s, await seatVote(s, ctx)) }
    catch (e) { return { seat: s.id, vote: 'abstain', rationale: `dispatch error: ${String(e && e.message || e)}` } }
  }))
}

// DETERMINISTIC synthesis (fleet mode, NO model key): confidence from the winning margin among
// votes cast, dissent from the losing side's rationales, a human brief assembled on escalate.
// Keeps the ENTIRE verdict path key-free + auditable for a real-agent convene (no LLM in the
// tally OR the summary — the chair narrative modelCall is only used on the standalone seam).
export function synthesizeNarrative(votes, counted) {
  const cast = (votes || []).filter(v => v.vote !== 'abstain')
  const abstained = (votes || []).filter(v => v.vote === 'abstain')
  const winner = counted.recommendation
  const withWinner = cast.filter(v => v.vote === winner)
  const against = cast.filter(v => v.vote !== winner)
  const confidence = cast.length ? Math.round((withWinner.length / cast.length) * 100) / 100 : 0
  const dissent = against.length ? against.map(v => `${v.seat} (${v.vote}): ${v.rationale}`).join('; ') : 'none'
  let brief = ''
  if (counted.escalated) {
    const why = !counted.quorumMet
      ? `Inquorate: only ${counted.votesCast} of ${counted.seatCount} seats voted (quorum ${counted.quorum})${abstained.length ? `; abstained: ${abstained.map(v => v.seat).join(', ')}` : ''}.`
      : `Council split (tally ${tallyStr(counted.tally)}); no side reached the ${counted.decisionClass} threshold and escalate carried.`
    const takes = cast.map(v => `${v.seat}: ${v.vote} — ${v.rationale}`).join(' | ')
    brief = `${why} Seat positions: ${takes || '(none)'}`
  }
  return { confidence, dissent, brief }
}

// Assemble the convene/standing verdict from the deterministic count + a narrative (synthesized
// in fleet mode, chair-written on the seam). Carries the quorum bookkeeping onto the verdict so
// the disposition + receipt reflect liveness.
export function buildConveneVerdict(counted, narr) {
  return {
    recommendation: counted.recommendation, tally: counted.tally, threshold: counted.threshold,
    seatCount: counted.seatCount, quorum: counted.quorum, quorumMet: counted.quorumMet, votesCast: counted.votesCast,
    // CNCL-11: surface the applied decision class + who recused so the sealed receipt's verdict is
    // self-describing for audit. These are NOT in canonicalTranscript (additive, no seal change).
    decisionClass: counted.decisionClass, recused: counted.recused || [],
    confidence: narr.confidence, dissent: narr.dissent,
    escalated: counted.escalated, brief: counted.escalated ? narr.brief : '',
  }
}

// ==================== deliberation engine ====================
// Narrative-only synthesis for the named council: the chair writes confidence/dissent/
// brief but does NOT decide the recommendation (that's the deterministic tallyVotes count).
const NARRATIVE = { type: 'object', additionalProperties: false, required: ['confidence', 'dissent', 'brief'],
  properties: { confidence: { type: 'number' }, dissent: { type: 'string' }, brief: { type: 'string' } } }

function log(on, msg) { if (on) process.stderr.write(`[council] ${msg}\n`) }

// Run a full convene -> deliberate -> chair-synthesis over `question` with `seats`.
// `modelCall` is injected (real adapter in prod, a deterministic mock in tests).
// mode: quick (no cross-take context) | deliberate (seats see all opening takes) |
// adversarial (deliberate + one rebuttal round). role: 'convene'|'gate'|'verifier'|'node'.
export async function runCouncil(input, deps = {}) {
  const modelCall = deps.modelCall || makeAnthropicModelCall(input.config || {})
  const verbose = !!deps.verbose
  const role = input.role || 'convene'
  const mode = input.mode || 'deliberate'
  const seats = input.seats && input.seats.length ? input.seats : DEFAULT_COUNCIL.seats
  const isNode = role === 'node'
  const question = input.question || nodeQuestion(input)

  // Guardrail (gate/verifier/node) — escalate-only on a hard-gate class, no model spend.
  const guardTarget = role === 'gate' ? input.gate : role === 'verifier' ? input.task : isNode ? input.node : null
  if (guardTarget) {
    const g = guardrail(guardTarget)
    if (g.forceEscalate) {
      log(verbose, `force-escalated by guardrail: ${g.reason}`)
      const verdict = isNode
        ? { choice: '', tally: { approve: 0, reject: 0, escalate: seats.length }, confidence: 1, dissent: 'none', escalated: true, brief: `Not council-decidable: ${g.reason}.` }
        : { recommendation: 'escalate', tally: { approve: 0, reject: 0, escalate: seats.length }, confidence: 1, dissent: 'none', escalated: true, brief: `Not council-gradable/clearable: ${g.reason}.` }
      return finish(role, input, { question, mode, seats, guardrail: g, convened: false, takes: [], votes: [], verdict })
    }
  }

  // ---- CNCL-7: convene/standing DISPATCH to the REAL seated agents (fleet mode) or, when no
  // dispatch adapter is injected, the deferred standalone modelCall seam. Blind round 1,
  // adversarial rebuttal round 2 recorded separately, timeout/unparse -> abstain, deterministic
  // quorum-gated tally + key-free synthesis. Gate/verifier/node (P1/P2) keep the path below.
  if (role === 'convene' || role === 'standing') {
    return await runConvene(input, deps, { modelCall, seatVote: deps.seatVote, verbose, role, mode, seats, question })
  }

  // Convene — independent opening takes.
  log(verbose, `convening ${seats.length} seats (${mode})`)
  const takes = await Promise.all(seats.map(s =>
    modelCall(`You hold the "${s.id}" seat on the 5dive Council${roleBlurb(role)}. Your lens: ${s.lens}
${questionBlock(role, input, question)}
Give your independent opening take BEFORE hearing the other seats. Be concrete and brief.`, TAKE)))
  const takeText = takes.map(t => `- ${t.seat}: ${t.position} (key risk: ${t.keyRisk})`).join('\n')

  // Deliberate — vote (node seats choose a branch; others vote approve/reject/escalate).
  const seeTakes = mode === 'quick' ? '' : `The opening takes from all seats:\n${takeText}\n`
  const voteSchema = isNode ? NODE_VOTE : VOTE
  const votePrompt = (s) => isNode
    ? `You hold the "${s.id}" seat deciding a goal-DAG branch. Your lens: ${s.lens}
${questionBlock(role, input, question)}
${seeTakes}Name exactly ONE of the options (${input.node.options}) as your choice, with a one-to-two sentence rationale.`
    : `You hold the "${s.id}" seat on the 5dive Council${roleBlurb(role)}. Your lens: ${s.lens}
${questionBlock(role, input, question)}
${seeTakes}Cast your vote (approve | reject | escalate) with a one-to-two sentence rationale. Escalate ONLY if this genuinely needs a human (money/spend, destructive/irreversible, secrets, or a brand call on a mature product) or the council is hopelessly split.`
  let votes = await Promise.all(seats.map(s => modelCall(votePrompt(s), voteSchema)))

  // Adversarial: one rebuttal round where each seat may revise after seeing the votes.
  if (mode === 'adversarial' && !isNode) {
    const voteText = votes.map(v => `- ${v.seat}: ${v.vote} — ${v.rationale}`).join('\n')
    votes = await Promise.all(seats.map(s => modelCall(
      `You hold the "${s.id}" seat. Lens: ${s.lens}
${questionBlock(role, input, question)}
The first-round votes:\n${voteText}
REBUT: try to find the strongest objection to the leading position. Then cast your FINAL vote (approve | reject | escalate) with a one-to-two sentence rationale.`, VOTE)))
  }

  // Verdict. Gate/verifier/node (P1/P2) keep their ported chair-synthesized verdict + action
  // map (convene/standing returned early via runConvene above).
  const verdict = await chair(modelCall, role, input, question, votes, isNode)
  return finish(role, input, { question, mode, seats, guardrail: guardTarget ? { forceEscalate: false, reason: '' } : null, convened: true, takes, votes, verdict })
}

// CNCL-7 convene/standing driver — split out of runCouncil. Two paths share one deterministic
// tally + one receipt: (1) FLEET dispatch (deps.seatVote present) — each seat votes via its own
// harness, blind round 1, adversarial rebuttal round 2 recorded separately, timeout/unparse ->
// abstain, KEY-FREE synthesis; (2) the standalone modelCall SEAM (no seatVote) — one model
// answers each seat, same blind-round-1 discipline, chair-written narrative. Founder veto threads
// both. `deps` is forwarded only for symmetry; the resolved handles come in via `h`.
async function runConvene(input, deps, h) {
  const { modelCall, seatVote, verbose, role, mode, question } = h
  let { seats } = h
  // CNCL-11: a governance MOTION runs as a convened vote with the SUBJECT recused — the recused
  // seat is not dispatched (it doesn't vote on its own membership) and the class is derived from
  // the motion IN CODE (never a trusted string), so seatCount = full roster minus the recused set.
  const recuse = new Set([].concat(input.recuse || []).filter(Boolean).map(String))
  const fullCount = seats.length
  if (recuse.size) seats = seats.filter(s => !recuse.has(String(s.id)))
  const tallyOpts = {
    decisionClass: input.motion ? undefined : (input.decisionClass || (input.bench && input.bench.decisionClass) || 'ordinary'),
    motion: input.motion,
    recuse: [...recuse],
    policy: input.policy,
    threshold: input.threshold != null ? input.threshold : (input.bench && input.bench.threshold),
    thresholdRule: input.thresholdRule || (input.bench && input.bench.thresholdRule),
    seatCount: fullCount,
  }
  let round1Votes, finalVotes, rebuttalVotes = null, verdict
  if (seatVote) {
    log(verbose, `dispatching ${seats.length} real seats (blind round 1, ${mode})`)
    round1Votes = await dispatchRound(seats, { question, role, mode, round: 1 }, seatVote)
    finalVotes = round1Votes
    if (mode === 'adversarial') {
      log(verbose, `adversarial rebuttal (round 2, recorded separately)`)
      rebuttalVotes = await dispatchRound(seats, { question, role, mode, round: 2, priorVotes: round1Votes }, seatVote)
      finalVotes = rebuttalVotes
    }
    const counted = tallyVotes(finalVotes, tallyOpts)
    verdict = buildConveneVerdict(counted, synthesizeNarrative(finalVotes, counted))
  } else {
    // Standalone seam: one modelCall answers each seat. Blind round 1 (seatPrompt embeds NO
    // other seat's take), then an adversarial rebuttal that sees the round-1 votes.
    log(verbose, `convening ${seats.length} seats via the modelCall seam (blind round 1, ${mode})`)
    const askSeam = (s, ctx) => modelCall(seatPrompt(s, ctx), VOTE).then(v => ({ seat: v.seat || s.id, vote: v.vote, rationale: v.rationale }))
    round1Votes = await Promise.all(seats.map(s => askSeam(s, { question, round: 1 })))
    finalVotes = round1Votes
    if (mode === 'adversarial') {
      rebuttalVotes = await Promise.all(seats.map(s => askSeam(s, { question, round: 2, priorVotes: round1Votes })))
      finalVotes = rebuttalVotes
    }
    const counted = tallyVotes(finalVotes, tallyOpts)
    const narr = await chairNarrative(modelCall, question, finalVotes)
    verdict = buildConveneVerdict(counted, narr)
  }
  // CNCL-9: convene only ever OFFERS the veto (non-blocking); the flip happens later, and only
  // via an authenticated tap on the tier-2 rail (exerciseFounderVeto). No string ever flips here.
  verdict = attachVetoOffer(verdict, input.vetoOffer)
  return finish(role, input, {
    question, mode, seats, guardrail: null, convened: true,
    takes: [], votes: finalVotes, round1Votes, rebuttalVotes, verdict,
  })
}

function roleBlurb(role) {
  if (role === 'verifier') return ' acting as a VERIFIER (a bench of graders)'
  if (role === 'gate') return ' reviewing a risk-tiered gate'
  return ''
}
function nodeQuestion(input) {
  if (input.role === 'node' && input.node) return `Decision node: "${input.node.question}". Options: ${input.node.options}.`
  return input.question || ''
}
function questionBlock(role, input, question) {
  if (role === 'verifier' && input.task) {
    const t = input.task
    return `A maker submitted work for ${t.ident}. Original ask: "${t.ask}". Acceptance: "${t.accept}". Result: "${t.result}". Does it meet the criteria (approve), fail (reject — bounce to maker), or need a human (escalate)?`
  }
  if (role === 'gate' && input.gate) {
    const g = input.gate
    return `A tier-${g.tier} gate ${g.ident} needs a decision. Ask: "${g.ask}".${g.options ? ` Options: ${g.options}.` : ''}${g.recommend ? ` Filer recommends: ${g.recommend}.` : ''} Clear it (approve) or bump to a human (escalate)?`
  }
  if (role === 'node' && input.node) return `Question before the council: ${question}`
  return `Question before the council: "${question}"`
}

// Narrative-only chair for the named council: writes confidence/dissent/brief; does NOT
// decide the recommendation (that's the deterministic tally).
async function chairNarrative(modelCall, question, votes) {
  const voteText = votes.map(v => `- ${v.seat}: ${String(v.vote).toUpperCase()} — ${v.rationale}`).join('\n')
  return modelCall(`You are the Chair of the 5dive Council. The PASS/FAIL is decided by seat count, not by you — your job is only to summarize. Do not add your own opinion.
Question: "${question}"
Seat votes:\n${voteText}
Produce: confidence in [0,1] (how firm the panel is), dissent = the load-bearing minority view or "none" if unanimous, brief = one paragraph a human would need IF this has to go to them (else "").`, NARRATIVE)
}

async function chair(modelCall, role, input, question, votes, isNode) {
  if (isNode) {
    const voteText = votes.map(v => `- ${v.seat}: ${v.choice} — ${v.rationale}`).join('\n')
    return modelCall(`You are the Chair synthesizing a goal-DAG node verdict; aggregate only, no new opinion.
Decision: "${input.node.question}". Options: ${input.node.options}.
Seat choices:\n${voteText}
choice = the option with the most seat support (must be one of: ${input.node.options}); if evenly split or it genuinely needs a human, set escalated=true and choice="". tally: seats backing the winner as approve, others as reject, escalate-wanters as escalate. confidence [0,1]. dissent = load-bearing minority or "none". brief = one paragraph for the human iff escalated, else "".`, NODE_VERDICT)
  }
  const voteText = votes.map(v => `- ${v.seat}: ${String(v.vote).toUpperCase()} — ${v.rationale}`).join('\n')
  return modelCall(`You are the Chair of the 5dive Council. Synthesize the verdict from the seat votes; aggregate only, no new opinion.
${questionBlock(role, input, question)}
Seat votes:\n${voteText}
recommendation = the majority vote; if split evenly OR any seat escalated on a hard-gate class, set recommendation=escalate and escalated=true. tally = count each vote type. confidence [0,1]. dissent = load-bearing minority or "none". brief = one paragraph for the human iff escalated, else "".`, VERDICT)
}

// Attach the role-appropriate action map / receipt to the verdict.
function finish(role, input, base) {
  const out = { role, ...base }
  if (role === 'gate') out.gateAction = verdictToAction(input.gate, base.verdict)
  else if (role === 'verifier') out.verifierAction = verifierVerdictToAction(input.task, base.verdict)
  else if (role === 'node') out.nodeDecision = nodeVerdictToDecision(input.node, base.verdict)
  if (role === 'convene' || role === 'standing') {
    const rec = {
      council: input.councilName || 'ad-hoc', mode: base.mode, stampedAt: input.stampedAt || '',
      question: base.question, seats: base.seats.map(s => s.id), votes: base.votes, verdict: base.verdict,
      // Seal round-1 history ONLY when a rebuttal round ran (adversarial); a single-round receipt
      // omits it and stays byte-identical to CNCL-6. Makes the between-round record tamper-evident.
      ...(base.rebuttalVotes ? { round1Votes: base.round1Votes } : {}),
    }
    out.receipt = { canonical: canonicalTranscript(rec), ...sealCommands() }
  }
  return out
}

// ==================== CNCL-10: per-seat Ed25519 CO-SIGNED VOTES ====================
//
// The CNCL-6 receipt root-signs the WHOLE transcript with the ROOT gate-proof key — it proves
// the convener recorded these bytes, but NOTHING proves each seat actually cast its own vote:
// the convener assembles the vote rows and could forge or edit any of them before the seal.
// CNCL-10 closes that: every seat holds its OWN Ed25519 keypair and SIGNS its vote AT SOURCE
// (inside its own harness, before the vote leaves the agent). The convener holds no other
// seat's private key, so it can neither forge a vote nor alter one without breaking the sig.
//
// REPLAY PROOF: the signed bytes bind the CONVENE ID + the QUESTION DIGEST, so a seat's signed
// "approve" from an old convene fails verification in a new one (different convene id / digest).
// The verifier recomputes the expected preimage from the CURRENT convene context + the vote's
// own (seat, vote, rationale, stampedAt) — it never trusts a vote's self-reported convene/digest.
//
// KEY LIFECYCLE (bash layer owns the on-disk side): a keypair is issued at init/promote; the
// public key + fingerprint live in the roster; the private key is 0600, owner-only (agent-<name>,
// NOT the shared `claude` group — that group holds every agent and would leak the key). A demote
// REVOKES the key (fingerprint + revocation stamped in the lineage); compromise = revoke+reissue.
// A revoked seat's vote is rejected by verifyReceiptVotes even if the signature is cryptographically
// valid, so a demoted seat can no longer sway a convene.
//
// The receipt bundles the co-signed vote rows; the existing ROOT HMAC seal (canonicalTranscript)
// sits on top unchanged. `council verify` re-checks EVERY seat signature against the roster pubkeys
// AND revocation AND the root seal — all three must pass for a green receipt.

const _cnorm = (s) => String(s == null ? '' : s).replace(/\s+/g, ' ').trim()
function _b64url(buf) { return Buffer.from(buf).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '') }
function _b64urlDecode(str) { const s = String(str || '').replace(/-/g, '+').replace(/_/g, '/'); return Buffer.from(s, 'base64') }

// Deterministic sha256 (hex) of the normalized question — the replay-binding digest a seat signs.
export function questionDigest(question) {
  return createHash('sha256').update(_cnorm(question), 'utf8').digest('hex')
}

// Deterministic, whitespace-normalized preimage of ONE seat's vote — the exact bytes the seat
// signs at source and the verifier recomputes. Binds seat + position(vote) + reasoning(rationale)
// + ts(stampedAt) + CONVENE ID + QUESTION DIGEST. A v1 tag guards against a future format swap.
export function canonicalVoteBytes(v) {
  return [
    'council-vote v1',
    `convene: ${_cnorm(v.conveneId)}`,
    `qdigest: ${_cnorm(v.questionDigest)}`,
    `seat: ${_cnorm(v.seat)}`,
    `vote: ${_cnorm(v.vote)}`,
    `rationale: ${_cnorm(v.rationale)}`,
    `stampedAt: ${_cnorm(v.stampedAt)}`,
  ].join('\n')
}

// sha256(pubkey)[:16] — the short human-readable key fingerprint stored in the roster + lineage.
export function fingerprintOf(pub) {
  return createHash('sha256').update(String(pub || ''), 'utf8').digest('hex').slice(0, 16)
}

// Mint a fresh per-seat Ed25519 keypair. Returns the PUBLIC key (base64url SPKI-DER, roster-safe),
// its fingerprint, and the PRIVATE key as a PKCS8 PEM string — the bash layer writes the PEM 0600
// owner-only and stores only {pub, fingerprint} in the roster. No clock, no randomness seam needed
// (generateKeyPairSync is the platform CSPRNG). Never log or persist the PEM anywhere world/group
// readable.
export function generateSeatKeypair() {
  const { publicKey, privateKey } = generateKeyPairSync('ed25519')
  const pub = _b64url(publicKey.export({ type: 'spki', format: 'der' }))
  const privPem = privateKey.export({ type: 'pkcs8', format: 'pem' }).toString()
  return { pub, privPem, fingerprint: fingerprintOf(pub) }
}

// Raw Ed25519 sign/verify over a preimage string. Sign returns a base64url signature; verify is
// fail-closed (any malformed key/sig/bytes -> false, never a throw that could be read as "valid").
export function signBytes(bytes, privPem) {
  const key = createPrivateKey(privPem)
  return _b64url(edSign(null, Buffer.from(String(bytes), 'utf8'), key))
}
export function verifyBytes(bytes, sigB64, pub) {
  try {
    const key = createPublicKey({ key: _b64urlDecode(pub), format: 'der', type: 'spki' })
    return edVerify(null, Buffer.from(String(bytes), 'utf8'), key, _b64urlDecode(sigB64))
  } catch { return false }
}

// SIGN-AT-SOURCE: a seat signs its own vote with its OWN private key before the vote leaves the
// agent. `ctx` carries the convene binding {conveneId, questionDigest}; `vote` is {seat, vote,
// rationale, stampedAt}. Returns the vote row plus {sig, sigAlg, fingerprint}. This runs inside
// the seat's harness (via `5dive council sign-vote`), NEVER on the convener.
export function signSeatVote(vote, ctx, privPem, fingerprint = '') {
  const bytes = canonicalVoteBytes({
    conveneId: ctx.conveneId, questionDigest: ctx.questionDigest,
    seat: vote.seat, vote: vote.vote, rationale: vote.rationale, stampedAt: vote.stampedAt,
  })
  return { ...vote, sig: signBytes(bytes, privPem), sigAlg: 'ed25519', ...(fingerprint ? { fingerprint } : {}) }
}

// Verify ONE co-signed vote against the roster. Recomputes the preimage from the CURRENT convene
// context (ctx.conveneId + ctx.questionDigest) so a vote signed for another convene/question fails
// (replay). Fail-closed: no roster key, revoked key, missing sig, or a non-matching signature all
// return ok=false with a reason. An ABSTAIN is a recorded non-vote (a dead/silent seat that never
// signed): it is allowed unsigned but carries no weight — flagged abstain=true, ok=true.
export function verifySeatVote(signedVote, ctx, roster = {}) {
  const seat = signedVote && signedVote.seat
  if (signedVote && signedVote.vote === 'abstain' && !signedVote.sig) {
    return { seat, ok: true, abstain: true, reason: 'abstain (unsigned non-vote)' }
  }
  const entry = roster[seat]
  if (!entry || !entry.pub) return { seat, ok: false, reason: `no roster key for seat "${seat}"` }
  if (entry.revokedAt) return { seat, ok: false, reason: `seat "${seat}" key was revoked (${_cnorm(entry.revokedAt)})` }
  if (!signedVote.sig) return { seat, ok: false, reason: `vote from "${seat}" is unsigned` }
  const bytes = canonicalVoteBytes({
    conveneId: ctx.conveneId, questionDigest: ctx.questionDigest,
    seat: signedVote.seat, vote: signedVote.vote, rationale: signedVote.rationale, stampedAt: signedVote.stampedAt,
  })
  const ok = verifyBytes(bytes, signedVote.sig, entry.pub)
  return { seat, ok, reason: ok ? '' : `signature does not verify for "${seat}" (forged, edited, replayed, or wrong key)` }
}

// Re-check EVERY co-signed vote in a receipt against the roster pubkeys + revocation. Returns
// { ok, results, badSeats } — ok iff every non-abstain vote carries a valid, non-revoked signature
// bound to THIS convene. This is the per-seat half of `council verify`; the root HMAC seal is the
// other half (bash re-signs canonicalTranscript). Both must pass for a green receipt.
export function verifyReceiptVotes(votes, ctx, roster = {}) {
  const results = (votes || []).map(v => verifySeatVote(v, ctx, roster))
  const badSeats = results.filter(r => !r.ok).map(r => r.seat)
  return { ok: badSeats.length === 0, results, badSeats }
}
COUNCIL_ENGINE_MJS
  cat > "$dir/cli.mjs" <<'COUNCIL_CLI_MJS'
#!/usr/bin/env node
// CNCL-6 — `5dive council` CLI entrypoint. Thin arg-parser over the deliberation
// ENGINE (engine.mjs, written alongside this file into a temp dir by cmd_council.sh).
// It never seals or persists directly: it emits a JSON envelope on stdout and the
// bash layer does the root-only receipt seal (gate-proof) + registry file write.
//
// Contract (bash always passes --key=value form, so no positional/flag ambiguity):
//   convene "<question>" --seats=a,b,c --mode=quick|deliberate|adversarial
//           [--bench=<name>] [--registry=<path>] [--class=<decisionClass>]
//           [--threshold=<n>] [--threshold-rule=flat|majority|fraction]
//           [--veto-by=<who> --veto-reason=<why>] [--stamped-at=<iso>]
//   bench ls|show|add|rm  (persisted registry lives at --registry=<path>)
//
// COUNCIL_MOCK=1 swaps in a deterministic no-network modelCall (offline tests + VM smoke
// with no key). Otherwise the A-with-seam Anthropic adapter reads COUNCIL_API_KEY.
import * as E from './engine.mjs'
import fs from 'node:fs'
import { execFileSync } from 'node:child_process'
import { pathToFileURL } from 'node:url'

const argv = process.argv.slice(2)
const sub = argv[0] || ''
const rest = argv.slice(1)
const positionals = rest.filter(a => !a.startsWith('--'))
const flag = (k, d) => {
  const hit = rest.find(a => a === `--${k}` || a.startsWith(`--${k}=`))
  if (hit == null) return d
  return hit.includes('=') ? hit.slice(hit.indexOf('=') + 1) : true
}
const die = (msg, code = 2) => { process.stderr.write(`council: ${msg}\n`); process.exit(code) }
// bash passes boolean flags as the STRINGS "0"/"1" — and JS `!"0"` is false, so never test a
// flag's truthiness for these. `--genesis-exists=0` MUST read as false (fail-closed correctness).
const flagBool = (k) => { const v = flag(k); return v === true || v === '1' || v === 'true' }
const out = (obj) => { process.stdout.write(JSON.stringify(obj) + '\n') }

// ---- persisted registry ----------------------------------------------------
// Built-ins are read-only defaults; the persisted file extends/overrides them and
// is the only thing `bench add|rm` mutate. Resolution is fail-closed on a miss.
const BUILTINS = { ...E.STANDING_COUNCILS, council: { ...E.DEFAULT_COUNCIL } }
function loadRegistry(p) {
  if (!p) return {}
  try { return JSON.parse(fs.readFileSync(p, 'utf-8')) } catch { return {} }
}
function saveRegistry(p, reg) {
  if (!p) die('bench mutation needs --registry=<path>')
  fs.writeFileSync(p, JSON.stringify(reg, null, 2) + '\n')
}
function resolveBench(name, reg) {
  // persisted wins over a same-named built-in (lets the council re-seat a standing bench).
  return E.resolveCouncil(name, { ...BUILTINS, ...reg })
}
function parseSeats(spec) {
  // "a,b,c" -> default lens; "a:the a lens|b:the b lens" -> explicit lenses.
  if (!spec) return []
  const parts = spec.includes('|') ? spec.split('|') : spec.split(',')
  return parts.map(s => s.trim()).filter(Boolean).map(s => {
    const i = s.indexOf(':')
    return i < 0 ? { id: s, lens: `${s} — council seat.` } : { id: s.slice(0, i).trim(), lens: s.slice(i + 1).trim() }
  })
}

// ---- model call (A-with-seam, or deterministic mock) -----------------------
function mockModelCall() {
  // Deterministic, network-free. Every seat approves with a canned take/vote so the
  // full convene path (takes -> votes -> chair -> tally -> veto -> receipt) exercises
  // offline. Shape matches whichever schema the engine forces.
  return async (prompt, schema) => {
    const req = new Set(schema.required || [])
    if (req.has('position')) return { seat: 'mock', position: 'proceed', keyRisk: 'none material' }
    if (req.has('vote')) return { seat: 'mock', vote: 'approve', rationale: 'mock: no blocker found.' }
    if (req.has('choice') && req.has('rationale')) return { seat: 'mock', choice: (String(flag('_opt', 'a')).split(',')[0] || 'a'), rationale: 'mock choice.' }
    if (req.has('confidence') && req.has('brief') && !req.has('recommendation') && !req.has('choice')) return { confidence: 0.9, dissent: 'none', brief: '' }
    return { recommendation: 'approve', tally: { approve: 1, reject: 0, escalate: 0 }, confidence: 0.9, dissent: 'none', escalated: false, brief: '' }
  }
}
function modelCallFor() {
  if (process.env.COUNCIL_MOCK) return mockModelCall()
  return E.makeAnthropicModelCall({})
}

// ---- CNCL-7 dispatch: convene -> real seated agents (default fleet path) ----
// Each seat votes via its OWN harness over the `5dive agent ask` rail — no shared model key.
// A per-seat timeout, a non-running agent, or a reply with no COUNCIL-VOTE line all resolve to
// an ABSTAIN (the engine records it; abstains still count toward the quorum denominator).
function dispatchSeatVote(opts) {
  const timeout = Number(opts.timeout) || 120
  const idle = Number(opts.idle) || 5
  const poll = Number(opts.poll) || 2
  const from = opts.from || 'council'
  const bin = process.env.COUNCIL_5DIVE_BIN || '5dive'
  return async (seat, ctx) => {
    const prompt = E.seatPrompt(seat, ctx)
    // CNCL-16: dispatch to the seat's REGISTRY agent (persona 'theo' -> 'marketing', etc.), not
    // its display id. Pre-flight (below) has already fail-closed on any unresolvable seat.
    const target = E.resolveSeatAgent(seat)
    let reply = ''
    try {
      const stdout = execFileSync(bin, ['agent', 'ask', target, prompt,
        '--json', `--from=${from}`, `--timeout=${timeout}`, `--idle-secs=${idle}`, `--poll-secs=${poll}`],
        { encoding: 'utf-8', timeout: (timeout + 30) * 1000, maxBuffer: 16 * 1024 * 1024 })
      const env = JSON.parse(stdout)
      reply = (env && env.data && env.data.reply) || ''
    } catch (e) {
      // ask timed out (E_TIMEOUT), the agent isn't running, or the exec failed -> ABSTAIN.
      return { vote: 'abstain', rationale: `no reply from ${seat.id} (${String(e && e.message || e).replace(/\s+/g, ' ').slice(0, 140)})` }
    }
    return E.parseVote(reply) || { vote: 'abstain', rationale: `${seat.id} reply had no COUNCIL-VOTE line` }
  }
}
// ---- CNCL-18 dispatch: NON-BLOCKING ballots via the task queue (default fleet path) --------
// Instead of injecting the ballot into the seat's LIVE session (the blocking `agent ask` pane
// scrape — disruptive, needs a quiet window, times mid-work seats out to abstain), we mint a
// DEADLINE-STAMPED task into the seat's queue. The seat surfaces + works that ballot at its next
// heartbeat boundary (a ballot is just a normal assigned task — NO heartbeat code change), casts
// its vote by closing the task with a COUNCIL-VOTE line in the result, and the convener COLLECTS
// by polling `task show` until the task closes with a result OR the deadline elapses. A missed
// deadline / unreadable result / unparseable vote all resolve to an ABSTAIN (the engine records
// it; abstains still count toward the quorum denominator). Blind-first-round is preserved: the
// round-1 ballot body is E.seatPrompt(seat, ctx) which the engine guarantees carries no other
// seat's take. Exec + clock are injectable (opts._exec/_now/_sleep) so the pure collection logic
// is unit-testable offline with no real `5dive` exec and no real timers.
export function dispatchBallotVote(opts = {}) {
  const bin = process.env.COUNCIL_5DIVE_BIN || '5dive'
  const from = opts.from || 'council'
  const deadlineSecs = Number(opts.deadline) > 0 ? Number(opts.deadline) : 900   // 15m default
  const pollSecs = Number(opts.poll) > 0 ? Number(opts.poll) : 5
  const now = opts._now || (() => Date.now())
  const sleep = opts._sleep || ((ms) => new Promise(r => setTimeout(r, ms)))
  // Default exec shells the real CLI; a test injects a stub reader. Returns stdout as a string.
  const exec = opts._exec || ((args) => execFileSync(bin, args,
    { encoding: 'utf-8', timeout: 60000, maxBuffer: 16 * 1024 * 1024 }))
  const clip = (e) => String(e && e.message || e).replace(/\s+/g, ' ').slice(0, 140)
  return async (seat, ctx) => {
    const prompt = E.seatPrompt(seat, ctx)   // blind in round 1 (engine-guaranteed)
    // CNCL-16: mint into the seat's REGISTRY agent (persona 'theo' -> 'marketing', etc.). Pre-flight
    // (preflightSeats) has already fail-closed on any unresolvable seat before we get here.
    const target = E.resolveSeatAgent(seat)
    const deadlineAt = now() + deadlineSecs * 1000
    const deadlineIso = new Date(deadlineAt).toISOString()
    const title = `Council ballot: ${String(ctx.question || '').replace(/\s+/g, ' ').slice(0, 80)} (vote by ${deadlineIso})`
    const body = `${prompt}\n\n[council ballot] Cast your vote by CLOSING this task with your COUNCIL-VOTE line as the result: 5dive task done <id> --result="...COUNCIL-VOTE: <approve|reject|escalate> :: <why>". Deadline: ${deadlineIso}. A missed deadline counts as an abstain.`
    // (c) mint the deadline-stamped ballot task. --no-verify keeps it a plain task that closes
    // directly on `task done` (no maker->grader handoff that would keep the result out of reach).
    let taskId
    try {
      const stdout = exec(['task', 'add', title, `--body=${body}`, `--assignee=${target}`,
        `--from=${from}`, '--priority=high', '--no-verify', '--json'])
      const env = JSON.parse(stdout)
      taskId = env && env.data && (env.data.ident || env.data.id)
      if (taskId == null) throw new Error('task add returned no id')
    } catch (e) {
      return { vote: 'abstain', rationale: `${seat.id} ballot: could not mint task (${clip(e)}) (deadline/no-vote)` }
    }
    // (d) COLLECT: poll task show until the seat closes it with a result, or the deadline elapses.
    // The collection-loop deadline is AUTHORITATIVE regardless of any stamp in the task body.
    while (now() < deadlineAt) {
      let row = null
      try {
        const env = JSON.parse(exec(['task', 'show', String(taskId), '--json']))
        row = env && env.data && env.data.task
      } catch { row = null }
      if (row && (row.status === 'done' || row.status === 'cancelled')) {
        const result = row.result || ''
        return E.parseVote(result) ||
          { vote: 'abstain', rationale: `${seat.id} ballot ${taskId}: closed with no COUNCIL-VOTE line (deadline/no-vote)` }
      }
      await sleep(pollSecs * 1000)
    }
    return { vote: 'abstain', rationale: `${seat.id} ballot ${taskId}: no vote by deadline ${deadlineIso} (deadline/no-vote)` }
  }
}
// Deterministic, network-free, NO `5dive` exec — every seat approves so the full dispatch path
// (blind round -> tally -> synthesis -> receipt) exercises offline in tests + VM smoke.
function mockSeatVote() {
  return async (seat) => ({ vote: 'approve', rationale: `mock: ${seat.id} sees no blocker.` })
}
// COUNCIL_MOCK -> offline mock (untouched). Otherwise the DEFAULT fleet path is the non-blocking
// ballot (CNCL-18). The old `agent ask` pane-scrape survives as an ESCAPE HATCH, opt-in via
// `--ask-rail` or COUNCIL_ASK_RAIL=1 (anything but "0"/empty).
function askRailSelected() {
  if (flagBool('ask-rail')) return true
  const e = process.env.COUNCIL_ASK_RAIL
  return !!e && e !== '0'
}
function seatVoteFor() {
  if (process.env.COUNCIL_MOCK) return mockSeatVote()
  if (askRailSelected()) {
    return dispatchSeatVote({ timeout: flag('timeout'), idle: flag('idle-secs'), poll: flag('poll-secs'), from: flag('from') })
  }
  return dispatchBallotVote({
    deadline: flag('ballot-deadline') !== undefined && flag('ballot-deadline') !== true ? flag('ballot-deadline') : flag('deadline'),
    poll: flag('ballot-poll'), from: flag('from'),
  })
}
// CNCL-16 pre-flight: the live set of registry agent names `5dive agent ask` can reach. Returns a
// Set, or null if the registry could not be read (transport/exec failure) — the caller fails CLOSED
// on null so a broken registry can't be mistaken for "every seat resolves".
function knownRegistryAgents() {
  const bin = process.env.COUNCIL_5DIVE_BIN || '5dive'
  try {
    const stdout = execFileSync(bin, ['agent', 'list', '--json'],
      { encoding: 'utf-8', timeout: 30000, maxBuffer: 16 * 1024 * 1024 })
    const env = JSON.parse(stdout)
    const arr = (env && env.data) || []
    if (!Array.isArray(arr)) return null
    return new Set(arr.map(a => a && a.name).filter(Boolean))
  } catch {
    return null
  }
}
// Resolve every seat to a registry agent and FAIL CLOSED (loud pre-flight error, exit 6) if any
// seat maps to no known agent — instead of the old behaviour where an unreachable persona seat
// (e.g. 'theo' vs registry 'marketing') was silently recorded as an ABSTAIN on every convene.
function preflightSeats(seats) {
  const known = knownRegistryAgents()
  if (known === null) {
    die("council pre-flight FAILED: could not read the agent registry (`5dive agent list --json`) — refusing to convene rather than silently abstain unreachable seats.", 6)
  }
  const unresolved = seats
    .map(s => ({ id: (s && s.id) || String(s), agent: E.resolveSeatAgent(s) }))
    .filter(x => !known.has(x.agent))
  if (unresolved.length) {
    die(`council pre-flight FAILED: ${unresolved.length} seat(s) resolve to no known registry agent — ${unresolved.map(u => `${u.id}→${u.agent}`).join(', ')}. Fix the bench seat's \`agent\` field / alias or re-seed. Known agents: ${[...known].sort().join(', ')}.`, 6)
  }
}

// ---- subcommands -----------------------------------------------------------
function cmdConstitution() {
  const p = flag('path')
  const path = p === true || p == null ? '' : String(p)
  out(E.loadConstitution(path))
}

async function cmdConvene() {
  const question = positionals[0]
  if (!question) die('convene needs a question: 5dive council convene "<q>" --seats=a,b,c')
  const registryPath = flag('registry')
  const reg = loadRegistry(registryPath)
  const cp = flag('constitution-path')
  const constitution = E.loadConstitution(cp === true || cp == null ? '' : String(cp))
  if (!constitution.valid) process.stderr.write(`council: invalid 5dive.md; using built-in defaults (${constitution.error})\n`)
  const explicitBench = flag('bench')
  const benchName = explicitBench || ((flag('seats') == null || flag('seats') === true) ? constitution.council.bench : null)
  // CNCL-8: convening THE primary council (by name, or the default with no explicit --seats)
  // fails closed until it has been human-seeded via `council init`. An ad-hoc panel (explicit
  // --seats) or an alternate bench (ship/brand/security) is a different, non-governance thing
  // and stays available. bash passes --genesis-exists=1 when the sealed genesis record is present.
  const primaryCouncil = benchName === 'council' || (!benchName && (flag('seats') == null || flag('seats') === true))
  if (primaryCouncil && !flagBool('genesis-exists')) {
    die('the Council has no genesis roster — it must be human-seeded first: sudo 5dive council init --seats=<a:chair,b,c> --threshold=<spec> --veto=<principal>', 8)
  }
  // The primary council convenes its HUMAN-SEEDED roster (the `council` bench init wrote),
  // never the hardcoded default — so init is the single source of truth for who sits.
  const effBench = benchName || (primaryCouncil ? 'council' : null)
  let seats, mode, bench = null
  if (effBench) {
    bench = resolveBench(effBench, reg)
    if (!bench) die(`unknown bench: ${effBench} (fail-closed — see 'council bench ls')`, 3)
    seats = bench.seats
    mode = flag('mode', bench.mode || 'deliberate')
  } else {
    seats = parseSeats(flag('seats'))
    if (!seats.length) seats = E.DEFAULT_COUNCIL.seats
    mode = flag('mode', 'deliberate')
  }
  const input = {
    role: 'convene', question, seats, mode,
    councilName: effBench || 'ad-hoc',
    decisionClass: flag('class') || (bench && bench.decisionClass) || 'ordinary',
    policy: constitution.thresholds,
    stampedAt: flag('stamped-at') || '',
  }
  const th = flag('threshold'); if (th != null && th !== true) input.threshold = Number(th)
  const tr = flag('threshold-rule'); if (tr) input.thresholdRule = tr
  // CNCL-11: a governance MOTION convene carries the motion descriptor (so the class is
  // auto-derived IN the engine, never trusted from --class) + the recused subject (dropped from
  // both dispatch and the tally base). bash passes these on `council promote|demote|expel`.
  const mkind = flag('motion-kind')
  if (mkind && mkind !== true) {
    input.motion = { kind: String(mkind), subject: flag('motion-subject') === true ? null : (flag('motion-subject') || null),
      param: flag('motion-param') === true ? null : (flag('motion-param') || null), to: flag('motion-to') === true ? null : (flag('motion-to') || null) }
    const rc = flag('recuse'); if (rc && rc !== true) input.recuse = String(rc).split(',').map(s => s.trim()).filter(Boolean)
    delete input.decisionClass   // the motion class wins; never a caller string
  }
  // CNCL-9 FORGE REFUSAL: a veto can NEVER be asserted from a plain CLI string. Pre-CNCL-9,
  // `--veto-by=<who>` flipped the verdict inline, so any agent could forge lodar's veto into a
  // signed receipt. convene now REFUSES it outright (bash logs the attempt). convene only ever
  // OFFERS the veto to the authenticated genesis principal; the flip happens later via the
  // authenticated `council veto exercise` tap path, never here.
  if (flag('veto-by') != null || flag('veto-reason') != null) {
    die('refused: `--veto-by`/`--veto-reason` cannot assert a veto (a signed receipt is not forgeable from a string). The Council OFFERS the veto to the genesis principal; only an authenticated tap exercises it. This attempt is logged.', 9)
  }
  // Non-blocking veto OFFER: bash supplies the genesis-resolved principal + hold window on a
  // primary-council convene. On a PASS the engine records the offer inside the sealed bytes;
  // disposition stays `pass` (nobody waits — the ACTION waits, enforced downstream by CNCL-12).
  const vp = flag('veto-principal'), vr = flag('veto-resolved')
  if (vp && vp !== true && vr && vr !== true) {
    input.vetoOffer = { principal: String(vp), resolved: String(vr), windowSecs: Number(flag('veto-window')) || 0 }
  }
  // FLEET DEFAULT (CNCL-7): dispatch to the real seated agents (no model key). --standalone
  // (or COUNCIL_STANDALONE) selects the deferred single-key modelCall seam instead. COUNCIL_MOCK
  // runs either path offline. The engine records a timed-out/silent seat as an abstain.
  const standalone = !!flag('standalone') || !!process.env.COUNCIL_STANDALONE
  // CNCL-16: on the real-agents dispatch path, fail closed at convene START if any seat resolves
  // to no known registry agent. Skipped for the standalone seam and for COUNCIL_MOCK (offline).
  if (!standalone && !process.env.COUNCIL_MOCK) preflightSeats(seats)
  const deps = standalone
    ? { modelCall: modelCallFor(), verbose: !!flag('verbose') }
    : { seatVote: seatVoteFor(), verbose: !!flag('verbose') }
  let result
  try { result = await E.runCouncil(input, deps) }
  catch (e) { die(String(e && e.message || e), 1) }
  out({
    council: input.councilName, mode: result.mode, question,
    seats: result.seats.map(s => s.id),
    dispatch: standalone ? 'standalone-seam' : 'real-agents',
    verdict: result.verdict,
    disposition: E.dispositionOf(result.verdict),
    votes: (result.votes || []).map(v => ({ seat: v.seat, vote: v.vote, rationale: v.rationale })),
    round1Votes: result.round1Votes ? result.round1Votes.map(v => ({ seat: v.seat, vote: v.vote, rationale: v.rationale })) : undefined,
    rebuttalVotes: result.rebuttalVotes ? result.rebuttalVotes.map(v => ({ seat: v.seat, vote: v.vote, rationale: v.rationale })) : undefined,
    constitution: { source: constitution.source, valid: constitution.valid, path: constitution.path },
    receipt: result.receipt,   // { canonical, seal, verify } — bash seals canonical
  })
}

function cmdBench() {
  const action = positionals[0] || 'ls'
  const registryPath = flag('registry')
  const reg = loadRegistry(registryPath)
  if (action === 'ls') {
    const names = [...new Set([...Object.keys(BUILTINS), ...Object.keys(reg)])].sort()
    out({ benches: names.map(n => ({ name: n, builtin: n in BUILTINS, custom: n in reg })) })
    return
  }
  if (action === 'show') {
    const name = positionals[1]; if (!name) die('bench show needs a name')
    const b = resolveBench(name, reg)
    if (!b) die(`unknown bench: ${name} (fail-closed)`, 3)
    out({ name: b.name, description: b.description, mode: b.mode, seats: b.seats, builtin: name in BUILTINS, custom: name in reg })
    return
  }
  // CNCL-8: the primary council is special in EXACTLY one way — its membership changes ONLY
  // via promote/demote motions. A raw bench add/rm against it fails closed (otherwise a plain
  // `sudo bench rm council` would bypass the whole governance layer). Motions land in a later
  // wave; until then the guard is the load-bearing invariant.
  if ((action === 'add' || action === 'rm') && positionals[1] === 'council') {
    die("'council' is the primary governance body — its seats change ONLY via promote/demote motions, never raw bench add/rm (re-seed the whole roster with: sudo 5dive council init --force).", 7)
  }
  if (action === 'add') {
    const name = positionals[1]; if (!name) die('bench add needs a name')
    const seats = parseSeats(flag('seats'))
    if (!seats.length) die('bench add needs --seats=a:lens|b:lens (or a,b,c)')
    const entry = { description: flag('desc') || `${name} — custom council bench.`, mode: flag('mode') || 'deliberate', seats }
    const th = flag('threshold'); if (th != null && th !== true) { entry.threshold = Number(th); entry.thresholdRule = 'flat' }
    const tr = flag('threshold-rule'); if (tr) entry.thresholdRule = tr
    const cls = flag('class'); if (cls) entry.decisionClass = cls
    reg[name] = entry
    saveRegistry(registryPath, reg)
    out({ added: name, entry })
    return
  }
  if (action === 'rm') {
    const name = positionals[1]; if (!name) die('bench rm needs a name')
    if (!(name in reg)) {
      if (name in BUILTINS) die(`'${name}' is a built-in bench and cannot be removed (shadow it with a same-named custom bench instead)`, 4)
      die(`unknown custom bench: ${name}`, 3)
    }
    delete reg[name]
    saveRegistry(registryPath, reg)
    out({ removed: name })
    return
  }
  die(`unknown bench action: ${action} (ls|show|add|rm)`)
}

// ---- CNCL-8: council init (human-seeded genesis roster) --------------------
// Seeds the primary `council` bench ONCE from a human-supplied roster + veto principal.
// bash owns the sudo gate, the veto-principal resolution (--veto-resolved), the ROOT seal of
// the canonical bytes, and the hash-chained lineage write. cli owns: validate the roster,
// enforce one-time (fail-closed unless --force), seed the registry, and emit the record +
// canonical bytes for bash to seal. An agent can never call this to bootstrap its own council
// because the write path (COUNCIL_DIR) is root-owned — bash refuses a non-sudo init.
function cmdInit() {
  const registryPath = flag('registry')
  const genesisExists = flagBool('genesis-exists')
  const forced = !!flag('force')
  if (genesisExists && !forced) {
    die('council is already initialized (one-time). Re-seed with --force (the re-seed is logged in the lineage).', 5)
  }
  let parsed
  try { parsed = E.parseGenesisSeats(flag('seats')) }
  catch (e) { die(`bad --seats: ${String(e && e.message || e)}`) }
  const threshold = E.parseThresholdSpec(flag('threshold') || 'majority')
  if (!threshold) die(`bad --threshold (use: majority | all | <N> | <a>/<b>, e.g. 2/3)`)
  const principal = flag('veto')
  if (!principal || principal === true) die('init needs --veto=<principal> (a resolvable human, e.g. human:main)')
  const resolved = flag('veto-resolved')   // bash resolves the principal -> tg user_id
  if (!resolved || resolved === true) die(`veto principal "${principal}" did not resolve to a real recipient — init rejects an unknown/unresolvable principal (fail-closed).`, 6)
  let rec
  try {
    rec = E.buildGenesisRecord({
      seats: parsed.seats, chair: parsed.chair, threshold,
      veto: { principal: String(principal), resolved: String(resolved) },
      prevDigest: flag('prev-digest') || '', stampedAt: flag('stamped-at') || '',
      forced, seq: Number(flag('seq')) || 0,
    })
  } catch (e) { die(String(e && e.message || e)) }
  // Seed / re-seat the primary council bench in the persisted registry (bench edits on it are
  // refused elsewhere — init and, later, motions are the ONLY writers).
  const reg = loadRegistry(registryPath)
  reg.council = E.genesisToBench(rec)
  saveRegistry(registryPath, reg)
  out({ genesis: rec, canonical: E.canonicalGenesis(rec), bench: 'council', seats: rec.seats.map(s => s.id), chair: rec.chair })
}

// ---- CNCL-9: council veto exercise (authenticated tap → chained veto record) ----------------
// Bash owns the authentication: it has already validated the tap came over the tier-2 nonce rail
// from the recipient the veto was OFFERED to (--resolved), and it reads the sealed convene receipt
// to supply --orig-digest + the original verdict. cli owns: reconstruct the flip, refuse a tap that
// doesn't match the recorded offer (fail-closed), and emit the chained record + its canonical bytes
// for bash to root-seal and hash-chain. cli NEVER trusts a --by string on its own — the resolved
// recipient must equal the offer's resolved recipient, which only bash's nonce check can honour.
function cmdVeto() {
  const action = positionals[0] || ''
  if (action !== 'exercise') die(`unknown veto action: ${action || '(none)'} (exercise)`)
  const origDigest = flag('orig-digest')
  if (!origDigest || origDigest === true) die('veto exercise needs --orig-digest=<sealed convene receipt digest>')
  const by = flag('by'); if (!by || by === true) die('veto exercise needs --by=<principal>')
  const resolved = flag('resolved'); if (!resolved || resolved === true) die('veto exercise needs --resolved=<recipient id> (the authenticated tap recipient)')
  const tier = flag('tier') === 'posthoc' ? 'posthoc' : 'hold'
  let verdict
  try { verdict = JSON.parse(flag('verdict') || '') }
  catch { die('veto exercise needs --verdict=<original verdict JSON> (bash reads it from the sealed receipt)') }
  // The offer must be present on the original verdict AND its resolved recipient must equal the tap
  // recipient — otherwise the tap did not come from the offered principal (fail-closed, refused).
  const offer = verdict && verdict.vetoOffer
  if (!offer || String(offer.resolved) !== String(resolved)) {
    die('refused: this verdict carries no veto offer for that recipient — the tap is not from the offered principal (fail-closed).', 9)
  }
  const flipped = E.exerciseFounderVeto(verdict, { by: String(by), resolved: String(resolved), reason: flag('reason') || '', tier })
  if (!flipped.vetoed) die('refused: verdict is not a vetoable pass (only an un-escalated pass with a matching offer can be vetoed).', 9)
  const rec = E.buildVetoRecord({
    origDigest: String(origDigest), tier, by: String(by), resolved: String(resolved),
    reason: flag('reason') || '', stampedAt: flag('stamped-at') || '', flippedVerdict: flipped,
  })
  out({ vetoRecord: rec, flippedVerdict: flipped, disposition: E.dispositionOf(flipped), canonical: E.canonicalVetoRecord(rec) })
}

// ---- CNCL-9 amendment: fold the veto seal-binding into the SEALED canonical ----------------
// At seal time bash mints the nonce digest + executeAfter (post-convene) and calls this to APPEND
// the deterministic seal-binding line to the canonical BEFORE sealing, so both are covered by the
// HMAC. Reads the base canonical from --canonical or stdin ("-"); prints the augmented canonical.
function readCanonicalArg() {
  const c = flag('canonical')
  if (c === '-' || c == null || c === true) { try { return fs.readFileSync(0, 'utf-8') } catch { die('seal-augment/read-binding needs the canonical on stdin or --canonical=<text>') } }
  return String(c)
}
function cmdSealAugment() {
  const canonical = readCanonicalArg()
  const nonceDigest = flag('nonce-digest') === true ? '' : (flag('nonce-digest') || '')
  const executeAfter = flag('execute-after') === true ? '' : (flag('execute-after') || '')
  process.stdout.write(E.augmentCanonicalVetoBinding(canonical, { nonceDigest, executeAfter }))
}
// At exercise time bash re-seals `.canonical` (proving it matches the stored digest) and calls this
// to read the nonce digest + executeAfter + stampedAt back OUT of the VERIFIED canonical — never
// from the raw wrapper, which is unsealed and forgeable. Fail-closed: present=false on no binding.
function cmdReadBinding() {
  out(E.parseCanonicalVetoBinding(readCanonicalArg()))
}

// ---- CNCL-12: gate-map (pure guardrail + verdict->action, no side effects) -----------------
// The auditable heart of `council gate-clear` (T1) and `council rot-triage` (T2). Bash owns
// every side effect (task show/answer/need/escalate + the convene). This verb ONLY decides:
//   phase 1 (no --verdict): run the escalate-only guardrail on the gate; emit whether it is
//           council-decidable + the deliberation QUESTION to convene on (T1), or, for --triage,
//           the triage question. A guardrail hit on a T1 gate emits the escalate command.
//   phase 2 (--verdict=<json>): map the sealed convene verdict -> the action command.
//           --triage forces the T2 mapping (triageVerdictToAction) which NEVER clears.
function cmdGateMap() {
  let gate
  try { gate = JSON.parse(flag('gate') || '') }
  catch { die('gate-map needs --gate=<json> (from `5dive task show <id> --json`, mapped to {ident,ask,type,tier,recommend,options})') }
  const triage = flagBool('triage')
  const verdictRaw = flag('verdict')
  if (verdictRaw == null || verdictRaw === true) {
    // Phase 1 — pre-convene guardrail. T2 rot-triage deliberately SKIPS the clearable check
    // (a tier-2 gate is never clearable; the triage convenes anyway, only to sharpen/re-brief).
    const guard = E.gateGuardrail(gate)
    if (triage) {
      out({ phase: 'guardrail', triage: true, clearable: false,
        question: `A tier-${gate.tier} gate has sat UNANSWERED for 48h+. You CANNOT clear it (tier-2 is human-only). Ask: "${gate.ask}". Deliberate ONLY to (a) re-brief it sharper for the human, (b) propose a rescope so the work no longer needs this gate, or (c) recommend a park with a wake date. Do NOT approve/clear it.` })
      return
    }
    if (guard.forceEscalate) {
      const verdict = { recommendation: 'escalate', escalated: true, tally: { approve: 0, reject: 0, escalate: 0 }, confidence: 1,
        dissent: 'none', brief: `Not council-clearable: ${guard.reason}.` }
      out({ phase: 'guardrail', clearable: false, reason: guard.reason, ...E.verdictToAction(gate, verdict) })
      return
    }
    out({ phase: 'guardrail', clearable: true, reason: '',
      question: `A tier-${gate.tier} gate is on the board and needs clearing. Ask: "${gate.ask}". `
        + (gate.recommend && gate.recommend !== '-'
            ? `The recommended answer is "${gate.recommend}"${gate.options ? ` (options: ${gate.options})` : ''}. Should the council APPLY that recommendation (approve), reject it, or escalate to a human?`
            : `Should the council approve, reject, or escalate to a human?`) })
    return
  }
  // Phase 2 — map the verdict to the action command.
  let verdict
  try { verdict = JSON.parse(verdictRaw) }
  catch { die('gate-map --verdict must be the convene verdict JSON') }
  out({ phase: 'action', ...(triage ? E.triageVerdictToAction(gate, verdict) : E.verdictToAction(gate, verdict)) })
}

// ---- CNCL-10: per-seat co-signed votes ------------------------------------
// SIGN-AT-SOURCE: a seat runs this INSIDE its own harness to sign its vote before it leaves the
// agent. bash resolves the seat's OWN private key (0600, owner-only) and passes --key-file; cli
// never fetches another seat's key. The convene binding (--convene + the question digest) is in
// the signed bytes, so the signature is replay-proof. Emits the `COUNCIL-SIG:` line the seat pastes
// after its COUNCIL-VOTE line (--emit=line, the dispatch default) or the full JSON row (--emit=json).
function cmdSignVote() {
  const seat = flag('seat'); if (!seat || seat === true) die('sign-vote needs --seat=<id>')
  const vote = flag('vote'); if (!['approve', 'reject', 'escalate', 'abstain'].includes(vote)) die('sign-vote needs --vote=<approve|reject|escalate|abstain>')
  const conveneId = flag('convene'); if (!conveneId || conveneId === true) die('sign-vote needs --convene=<convene id> (replay binding)')
  // The digest binds the exact question. Accept a precomputed --qdigest (bash passes it from the
  // convene) or compute it here from --question. One is required — never sign an unbound vote.
  let qdigest = flag('qdigest')
  if (!qdigest || qdigest === true) { const q = flag('question'); if (!q || q === true) die('sign-vote needs --qdigest=<hex> or --question=<text>'); qdigest = E.questionDigest(q) }
  const keyFile = flag('key-file'); if (!keyFile || keyFile === true) die('sign-vote needs --key-file=<path to the seat PKCS8 PEM> ("-" for stdin)')
  let privPem
  try { privPem = keyFile === '-' ? fs.readFileSync(0, 'utf-8') : fs.readFileSync(keyFile, 'utf-8') }
  catch (e) { die(`sign-vote cannot read the seat key: ${String(e && e.message || e)}`) }
  const row = { seat, vote, rationale: flag('rationale') === true || flag('rationale') == null ? `(${vote})` : String(flag('rationale')), stampedAt: flag('stamped-at') === true ? '' : (flag('stamped-at') || '') }
  const fp = flag('fingerprint') === true ? '' : (flag('fingerprint') || '')
  let signed
  try { signed = E.signSeatVote(row, { conveneId: String(conveneId), questionDigest: String(qdigest) }, privPem, fp) }
  catch (e) { die(`sign-vote failed to sign: ${String(e && e.message || e)}`) }
  if (flag('emit') === 'json') { out(signed); return }
  process.stdout.write(`COUNCIL-SIG: ${signed.sig}\n`)   // the line a seat pastes after COUNCIL-VOTE
}

// VERIFY-VOTES (the per-seat half of `council verify`): re-check EVERY co-signed vote against the
// roster pubkeys + revocation, bound to THIS convene (replay-proof). bash re-checks the ROOT seal
// separately; both must be green. --votes + --roster are JSON (inline or @file). Exits non-zero if
// any non-abstain vote is unsigned/forged/replayed/revoked — so a caller can gate on the exit code.
function cmdVerifyVotes() {
  const readJson = (v, what) => {
    if (!v || v === true) die(`verify-votes needs --${what}=<json or @file>`)
    try { return JSON.parse(String(v).startsWith('@') ? fs.readFileSync(String(v).slice(1), 'utf-8') : v) }
    catch (e) { die(`verify-votes: bad --${what} json: ${String(e && e.message || e)}`) }
  }
  const votes = readJson(flag('votes'), 'votes')
  const roster = readJson(flag('roster'), 'roster')
  const conveneId = flag('convene'); if (!conveneId || conveneId === true) die('verify-votes needs --convene=<convene id>')
  let qdigest = flag('qdigest')
  if (!qdigest || qdigest === true) { const q = flag('question'); if (!q || q === true) die('verify-votes needs --qdigest=<hex> or --question=<text>'); qdigest = E.questionDigest(q) }
  const res = E.verifyReceiptVotes(votes, { conveneId: String(conveneId), questionDigest: String(qdigest) }, roster)
  out({ ok: res.ok, badSeats: res.badSeats, results: res.results })
  process.exit(res.ok ? 0 : 5)
}

// ---- CNCL-11: governance surface — roster / motion (promote|demote|expel) / verify-chain -----
// The pure engine owns classification, recusal, the motion record + its canonical bytes, and the
// chain check. bash owns the sudo gate, the ROOT seal (gate-proof), the persisted lineage write,
// and reading the current roster off the sealed lineage head. cli NEVER trusts a caller class.
function readJsonFlag(name, { optional = false } = {}) {
  const v = flag(name)
  if (!v || v === true) { if (optional) return null; die(`needs --${name}=<json or @file>`) }
  try { return JSON.parse(String(v).startsWith('@') ? fs.readFileSync(String(v).slice(1), 'utf-8') : v) }
  catch (e) { die(`bad --${name} json: ${String(e && e.message || e)}`) }
}
function seatsToSpec(seats) {
  return (seats || []).map(s => `${s.id}:${(s.lens || `${s.id} — council seat.`).replace(/[|:]/g, ' ')}`).join('|')
}
function motionFromFlags() {
  const kind = flag('kind'); if (!['promote', 'demote', 'expel'].includes(kind)) die('needs --kind=promote|demote|expel')
  const subject = flag('subject'); if (!subject || subject === true) die('needs --subject=<seat id>')
  return { kind, subject: String(subject),
    param: flag('param') === true || flag('param') == null ? null : String(flag('param')),
    to: flag('to') === true || flag('to') == null ? null : String(flag('to')) }
}

// council roster — the current seats (from the persisted, motion-governed `council` bench) + the
// live pass threshold. bash augments with the veto principal + lineage head (root-owned files).
function cmdRoster() {
  const registryPath = flag('registry')
  const reg = loadRegistry(registryPath)
  // Read the RAW persisted bench (not resolveCouncil, which drops genesis/threshold/seededAt).
  const bench = { ...BUILTINS, ...reg }.council
  if (!bench || !bench.genesis) die('the Council has no genesis roster — human-seed it first: sudo 5dive council init …', 8)
  const seatCount = (bench.seats || []).length
  const threshold = E.resolveThreshold(seatCount, bench.threshold || { rule: 'majority' })
  const quorum = E.quorumSize(seatCount, bench.threshold || { rule: 'majority' })
  out({ council: 'council', seats: bench.seats, seatCount, threshold, quorum,
    thresholdSpec: bench.threshold || { rule: 'majority' }, seededAt: bench.seededAt || '' })
}

// council promote|demote|expel — PLAN phase (pre-convene): classify the motion IN CODE, compute
// recusal, and emit the deliberation question + the recused voting roster for bash to convene on.
function cmdMotionPlan() {
  const motion = motionFromFlags()
  const roster = readJsonFlag('seats-json')   // current roster [{id,lens,chair?}] off the lineage head
  const cls = E.classifyMotion(motion)
  const recuse = E.recusalFor(motion)
  const seated = (roster || []).some(s => String(s.id) === motion.subject)
  if ((cls === 'demote' || cls === 'expel') && !seated) die(`cannot ${cls} '${motion.subject}' — not a current council seat (fail-closed)`, 3)
  if (cls === 'promote' && seated) die(`'${motion.subject}' already holds a council seat — nothing to promote`, 4)
  const votingSeats = (roster || []).filter(s => !recuse.includes(String(s.id)))
  if (!votingSeats.length) die('no eligible voting seats after recusal (fail-closed)', 3)
  const verb = cls === 'promote' ? `SEAT '${motion.subject}' on the Council` : `${cls.toUpperCase()} '${motion.subject}' from the Council`
  const question = `Council membership motion (${cls}): should the Council ${verb}? `
    + `This is a ${cls} motion — the bar is ${cls === 'promote' ? 'a simple majority' : 'a 2/3 supermajority'} of the ${votingSeats.length} eligible seat(s)`
    + `${recuse.length ? ` ('${recuse.join(', ')}' recused as the subject)` : ''}. Approve to carry the motion, reject to deny, escalate only if it genuinely needs a human.`
  out({ class: cls, recuse, subject: motion.subject, votingSeats, votingSeatSpec: seatsToSpec(votingSeats), question })
}

// council promote|demote|expel — APPLY phase (post-convene, on a PASS only): mutate the roster,
// build the hash-chained motion record + its canonical bytes for bash to root-seal, and persist
// the new roster into the motion-governed `council` bench. Refuses a non-pass verdict (fail-closed).
function cmdMotionApply() {
  const motion = motionFromFlags()
  const roster = readJsonFlag('seats-json')
  const verdict = readJsonFlag('verdict')
  if (!verdict || verdict.recommendation !== 'approve' || verdict.escalated) {
    die(`motion did not carry (recommendation=${verdict && verdict.recommendation}) — the roster is unchanged, no lineage record written`, 5)
  }
  const cls = E.classifyMotion(motion)
  let newSeats
  if (cls === 'promote') {
    const lens = flag('lens') === true || flag('lens') == null ? undefined : String(flag('lens'))
    newSeats = E.addSeat(roster, { id: motion.subject, lens })
  } else {
    newSeats = E.removeSeat(roster, motion.subject)
    if (!newSeats.length) die('refused: a demote/expel cannot empty the Council (fail-closed)', 7)
  }
  const threshold = readJsonFlag('threshold-json', { optional: true }) || { rule: 'majority' }
  const veto = readJsonFlag('veto-json', { optional: true })
  let rec
  try {
    rec = E.buildMotionRecord({ motion, verdict, seats: newSeats, threshold, veto,
      prevDigest: flag('prev-digest') === true ? '' : (flag('prev-digest') || ''),
      stampedAt: flag('stamped-at') === true ? '' : (flag('stamped-at') || ''),
      seq: Number(flag('seq')) || 0, receiptDigest: flag('receipt-digest') === true ? '' : (flag('receipt-digest') || '') })
  } catch (e) { die(String(e && e.message || e)) }
  // Emit the record + canonical bytes + the new roster; bash root-seals FIRST, then persists the
  // roster into the motion-governed `council` bench only on a good seal (never split roster/lineage).
  const benchSeats = newSeats.map(s => ({ id: s.id, lens: s.lens || `${s.id} — council seat.` }))
  out({ record: rec, canonical: E.canonicalMotion(rec), seats: newSeats.map(s => s.id), benchSeats, bench: 'council', class: cls })
}

// council verify — the structural chain check (bash re-seals each record's canonical separately;
// both must be green). Detects an edited/dropped/reordered receipt across the WHOLE append-only log.
function cmdVerifyChain() {
  const entries = readJsonFlag('entries')
  const res = E.verifyLineageChain(entries)
  out(res)
  process.exit(res.ok ? 0 : 5)
}

const main = async () => {
  if (sub === 'constitution') return cmdConstitution()
  if (sub === 'convene') return cmdConvene()
  if (sub === 'roster') return cmdRoster()
  if (sub === 'motion-plan') return cmdMotionPlan()
  if (sub === 'motion-apply') return cmdMotionApply()
  if (sub === 'verify-chain') return cmdVerifyChain()
  if (sub === 'bench') return cmdBench()
  if (sub === 'init') return cmdInit()
  if (sub === 'veto') return cmdVeto()
  if (sub === 'gate-map') return cmdGateMap()
  if (sub === 'seal-augment') return cmdSealAugment()
  if (sub === 'read-binding') return cmdReadBinding()
  if (sub === 'sign-vote') return cmdSignVote()
  if (sub === 'verify-votes') return cmdVerifyVotes()
  die(`unknown council subcommand: ${sub} (constitution|convene|bench|init|veto|gate-map|seal-augment|read-binding|sign-vote|verify-votes|roster|motion-plan|motion-apply|verify-chain)`)
}
// Run as the CLI entrypoint only when executed directly (node cli.mjs …). Guarded so a test can
// `import` this module (e.g. to exercise dispatchBallotVote's pure logic) WITHOUT triggering the
// arg-parser + process.exit. When embedded and run via `node "$dir/cli.mjs"`, argv[1] IS this file.
const isEntrypoint = process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href
if (isEntrypoint) main().catch(e => die(String(e && e.message || e), 1))
COUNCIL_CLI_MJS
}

# CNCL-8: resolve a veto PRINCIPAL to a concrete recipient id (fail-closed: echoes
# nothing if it can't resolve, and init then refuses). Supported forms:
#   human:<agent>  -> that agent's paired human (access.json allowFrom[0]) — e.g.
#                     human:main resolves to the human paired to @agent-main's bot.
#   tg:<digits> | <digits>  -> a literal Telegram user_id.
# An agent can only resolve principals that already exist as paired channels; it cannot
# invent a recipient. This is the "resolvable principal" invariant from the redesign.
_council_resolve_principal() {
  local p="$1"
  case "$p" in
    tg:*) local id="${p#tg:}"; [[ "$id" =~ ^[0-9]+$ ]] && printf '%s' "$id"; return 0 ;;
    human:*)
      local name="${p#human:}"
      [[ -n "$name" ]] || return 0
      _task_agent_channel "$name" >/dev/null 2>&1 || return 0
      [[ -n "${TASK_CH_ACCESS:-}" && -r "$TASK_CH_ACCESS" ]] || return 0
      jq -r '(.allowFrom // [])[0] // empty' "$TASK_CH_ACCESS" 2>/dev/null
      return 0 ;;
    *) [[ "$p" =~ ^[0-9]+$ ]] && printf '%s' "$p"; return 0 ;;
  esac
}

# CNCL-9: SHA-256 hex of a string (the nonce-digest primitive; seal stores the digest, exercise
# hashes the presented nonce and compares). Empty on a missing sha256sum (fail-closed downstream).
_council_sha256() { printf '%s' "${1:-}" | sha256sum 2>/dev/null | awk '{print $1}'; }

# CNCL-9 (main gate amendment 3): durable audit trail for REFUSED veto attempts — a forged
# `--veto-by` CLI string on convene, or a nonce/recipient mismatch on exercise. "refused + logged"
# must mean a real line on disk a test can assert, not just an stderr message. The file is
# attacker-triggerable, so it is root-owned 0600 (never group-readable).
_council_veto_audit() {
  local event="$1" ref="${2:-}" subject="${3:-}"
  mkdir -p "$COUNCIL_DIR" 2>/dev/null || true
  [[ -w "$COUNCIL_DIR" || -f "${COUNCIL_DIR}/veto-audit.jsonl" ]] || return 0
  local line
  line="$(jq -cn --arg e "$event" --arg r "$ref" --arg s "$subject" --arg u "$(id -un 2>/dev/null)" \
    '{ts:(now|todate? // ""), event:$e, ref:$r, subject:$s, by:$u, kind:"veto-refused"}' 2>/dev/null)" || return 0
  printf '%s\n' "$line" >> "${COUNCIL_DIR}/veto-audit.jsonl" 2>/dev/null || true
  chmod 0600 "${COUNCIL_DIR}/veto-audit.jsonl" 2>/dev/null || true
  [[ "$(id -u)" -eq 0 ]] && chown root:root "${COUNCIL_DIR}/veto-audit.jsonl" 2>/dev/null || true
  return 0
}

# CNCL-9: fire the founder veto ping at seal (non-blocking, best-effort). Records a durable ping
# entry (so "the ping fired" is observable + testable) and attempts a live notify to the resolved
# recipient. The tappable button + its callback -> `council veto exercise` is the telegram-plugin
# leg that pairs with a live genesis; this CLI leg guarantees the recipient is notified with the
# receipt handle + the one-time nonce the tap must present.
_council_veto_ping() {
  local resolved="$1" digest="$2" execute_after="$3" nonce="$4"
  mkdir -p "$COUNCIL_DIR" 2>/dev/null || true
  # CNCL-9 (main gate amendment 2): the pings audit records ONLY the nonce DIGEST, never the raw
  # bearer token. The raw nonce leaves this process solely via the founder delivery leg (_tg_send)
  # below. The file is additionally locked 0600 root so a group-claude agent cannot read even the
  # digest+recipient trail.
  local nonce_digest; nonce_digest="$(_council_sha256 "$nonce")"
  local line
  line="$(jq -cn --arg r "$resolved" --arg d "$digest" --arg ea "$execute_after" --arg nd "$nonce_digest" \
    '{ts:(now|todate? // ""), recipient:$r, receiptDigest:$d, executeAfter:$ea, nonceDigest:$nd, kind:"veto-offer"}' 2>/dev/null)" || line=""
  if [[ -n "$line" && -w "$COUNCIL_DIR" ]]; then
    printf '%s\n' "$line" >> "${COUNCIL_DIR}/veto-pings.jsonl" 2>/dev/null || true
    chmod 0600 "${COUNCIL_DIR}/veto-pings.jsonl" 2>/dev/null || true
    [[ "$(id -u)" -eq 0 ]] && chown root:root "${COUNCIL_DIR}/veto-pings.jsonl" 2>/dev/null || true
  fi
  # Founder delivery leg: the RAW one-time nonce is delivered ONLY here, to the resolved recipient.
  # A missing rail must never fail the (already-sealed) convene. Skipped under MOCK (offline tests
  # exercise the durable audit above without touching a live telegram rail).
  if [[ -z "${COUNCIL_MOCK:-}" ]] && command -v _tg_send >/dev/null 2>&1; then
    _tg_send "$resolved" "Council veto offer — a pass sealed (${digest:0:12}…). Execution holds until ${execute_after}. Tap to VETO (nonce ${nonce}), or ignore to let it proceed." >/dev/null 2>&1 || true
  fi
  return 0
}

# CNCL-9: authenticated founder veto EXERCISE (the confirmed tap). bash owns authentication (the
# one-time nonce minted at seal, bound to the offered recipient); cli owns the fail-closed flip +
# the chained record. The original convene receipt is NEVER re-sealed or mutated — the veto is a
# NEW root-sealed record hash-chained to the original verdict digest.
#   5dive council veto exercise --receipt=<sealed digest> --nonce=<tap nonce> [--tier=hold|posthoc]
#                               [--reason=<why>]
_council_veto() {
  local dir="$1"; shift
  [[ "${1:-}" == "exercise" ]] || fail "$E_USAGE" "unknown veto action: ${1:-} (exercise)"
  shift
  local rcpt_digest="" nonce="" tier="" reason=""
  local a
  for a in "$@"; do
    case "$a" in
      --receipt=*) rcpt_digest="${a#--receipt=}" ;;
      --nonce=*)   nonce="${a#--nonce=}" ;;
      --tier=*)    tier="${a#--tier=}" ;;
      --reason=*)  reason="${a#--reason=}" ;;
    esac
  done
  [[ -n "$rcpt_digest" ]] || fail "$E_USAGE" "veto exercise needs --receipt=<sealed convene receipt digest>"
  [[ -n "$nonce" ]]       || fail "$E_PERMISSION" "veto exercise needs --nonce=<the one-time tap nonce> (an unauthenticated exercise is refused)"

  # Locate the sealed convene receipt by its digest.
  local rf found=""
  if [[ -d "$COUNCIL_RECEIPTS" ]]; then
    for rf in "$COUNCIL_RECEIPTS"/*.json; do
      [[ -f "$rf" ]] || continue
      [[ "$(jq -r '.sealedDigest // empty' "$rf" 2>/dev/null)" == "$rcpt_digest" ]] && { found="$rf"; break; }
    done
  fi
  [[ -n "$found" ]] || fail "$E_GENERIC" "no sealed council receipt with digest ${rcpt_digest:0:16}… (fail-closed)"

  # HARDENING (main gate): before trusting ANY field of the receipt (.verdict / .vetoNonceDigest /
  # .vetoOffer), re-seal its canonical bytes on the gate-proof rail and confirm they match the
  # stored sealedDigest. A receipt whose body was edited (swapped nonce digest, flipped verdict,
  # widened offer) fails HERE — fail-closed — so the authenticated-tap path only ever acts on a
  # byte-intact receipt.
  local rcanon rseal=""
  rcanon="$(jq -r '.canonical // empty' "$found" 2>/dev/null)"
  [[ -n "$rcanon" ]] || fail "$E_GENERIC" "sealed receipt carries no canonical bytes to re-verify (fail-closed)"
  if [[ "$(id -u)" -eq 0 ]]; then rseal="$(printf '%s' "$rcanon" | cmd_gate_proof_sign_stdin 2>/dev/null)" || rseal=""
  else rseal="$(printf '%s' "$rcanon" | sudo -n 5dive gate-proof sign 2>/dev/null)" || rseal=""; fi
  [[ -n "$rseal" ]] || fail "$E_GENERIC" "cannot re-seal the receipt canonical (need root + an enforce key) — refusing to trust an unverifiable receipt (fail-closed)"
  [[ "$rseal" == "$rcpt_digest" ]] || { _council_veto_audit "receipt-tampered" "$rcpt_digest"; fail "$E_PERMISSION" "receipt canonical does not re-seal to its sealedDigest — the receipt was tampered (refused + logged, fail-closed)"; }

  # AUTHENTICATE the tap: sha256(presented nonce) must equal the nonce DIGEST minted for THIS offer.
  # The raw nonce is never stored server-side (only its digest rides in the receipt), so a
  # group-readable receipt no longer leaks the bearer token (main gate amendment 2).
  # CNCL-9 AMENDMENT (main gate): the nonce digest + executeAfter + stampedAt are read from the
  # VERIFIED canonical (which just re-sealed to the stored digest above), NEVER from the raw wrapper.
  # The wrapper's `.vetoNonceDigest`/`.executeAfter` are unsealed and forgeable; before this fix the
  # re-seal check only covered `.canonical`, so swapping `.vetoNonceDigest` to sha256(attacker-nonce)
  # passed the check and let an attacker exercise with a chosen nonce. Now those fields ride INSIDE
  # `.canonical` (seal-augment folded them in at seal time), so any edit breaks the re-seal above and
  # the values used here come from the byte-intact bytes. offer_resolved/principal stay wrapper-read:
  # exercise still requires the sealed-digest-matching nonce (the bearer token), which only the
  # founder holds, so a widened offer cannot help an attacker who lacks that nonce.
  local stored_nonce_digest offer_resolved offer_principal execute_after stamped_at verdict_json binding_json
  binding_json="$(printf '%s' "$rcanon" | node "$dir/cli.mjs" read-binding --canonical=- 2>/dev/null)" || binding_json=""
  stored_nonce_digest="$(printf '%s' "$binding_json" | jq -r '.nonceDigest // empty' 2>/dev/null)"
  execute_after="$(printf '%s' "$binding_json" | jq -r '.executeAfter // empty' 2>/dev/null)"
  stamped_at="$(printf '%s' "$binding_json" | jq -r '.stampedAt // empty' 2>/dev/null)"
  offer_resolved="$(jq -r '.verdict.vetoOffer.resolved // empty' "$found" 2>/dev/null)"
  offer_principal="$(jq -r '.verdict.vetoOffer.principal // empty' "$found" 2>/dev/null)"
  [[ -n "$stored_nonce_digest" && -n "$offer_resolved" ]] || fail "$E_GENERIC" "receipt carries no veto offer to exercise (fail-closed)"
  local presented_digest; presented_digest="$(_council_sha256 "$nonce")"
  [[ -n "$presented_digest" && "$presented_digest" == "$stored_nonce_digest" ]] || { _council_veto_audit "nonce-mismatch" "$rcpt_digest" "$offer_resolved"; fail "$E_PERMISSION" "veto nonce mismatch — this tap is not the one offered to the founder principal (refused + logged)"; }

  # Derive the tier from the clock unless explicitly given: within the HOLD window -> hold; after it
  # (up to veto_posthoc) -> posthoc; at/beyond the posthoc deadline -> refused (window expired, pass
  # is final). Boundary is inclusive: a zero/already-past window IS expired the instant it is reached
  # (now_e >= st_e + posthoc), so a 0s window never admits a same-second exercise — no clock race.
  local now_e ea_e st_e posthoc="${COUNCIL_VETO_POSTHOC_SECS:-172800}" _veto_cfg=""
  _veto_cfg="$(_council_constitution_json 2>/dev/null || true)"
  if [[ "$(printf '%s' "$_veto_cfg" | jq -r '.source // "defaults"' 2>/dev/null)" == "file" ]]; then
    posthoc="$(printf '%s' "$_veto_cfg" | jq -r '.veto.posthocSecs')"
  elif [[ "$(printf '%s' "$_veto_cfg" | jq -r '.valid // true' 2>/dev/null)" == "false" ]]; then
    posthoc=172800
  fi
  [[ "$posthoc" =~ ^[0-9]+$ ]] || posthoc=172800
  now_e="$(date -u +%s)"
  ea_e="$(date -u -d "$execute_after" +%s 2>/dev/null || echo 0)"
  st_e="$(date -u -d "$stamped_at" +%s 2>/dev/null || echo 0)"
  if [[ -z "$tier" ]]; then
    if (( ea_e > 0 && now_e < ea_e )); then tier="hold"; else tier="posthoc"; fi
  fi
  if [[ "$tier" == "posthoc" ]] && (( st_e > 0 && now_e >= st_e + posthoc )); then
    fail "$E_GENERIC" "veto window expired (past veto_posthoc=${posthoc}s from seal) — the pass is final, no override (fail-closed)"
  fi

  verdict_json="$(jq -c '.verdict' "$found" 2>/dev/null)"
  local stamped; stamped="$(date -u +%Y-%m-%dT%H:%M:%SZ)"
  local vraw
  vraw="$(node "$dir/cli.mjs" veto exercise \
    --orig-digest="$rcpt_digest" --by="$offer_principal" --resolved="$offer_resolved" \
    --tier="$tier" --reason="$reason" --verdict="$verdict_json" --stamped-at="$stamped")" || return $?

  # Root-seal the chained veto record and hash-chain it onto the original verdict digest. Same rail
  # + discipline as the genesis lineage; the original receipt bytes are left untouched.
  local canonical vdigest=""
  canonical="$(printf '%s' "$vraw" | jq -r '.canonical // empty')"
  if [[ -n "$canonical" ]]; then
    if [[ "$(id -u)" -eq 0 ]]; then vdigest="$(printf '%s' "$canonical" | cmd_gate_proof_sign_stdin)" || vdigest=""
    else vdigest="$(printf '%s' "$canonical" | sudo -n 5dive gate-proof sign 2>/dev/null)" || vdigest=""; fi
  fi
  [[ -n "$vdigest" ]] || fail "$E_GENERIC" "could not seal the veto record on the gate-proof rail (need root + an enforce key) — veto NOT recorded"

  if [[ -w "$COUNCIL_RECEIPTS" ]]; then
    printf '%s' "$vraw" | jq --arg d "$vdigest" --arg p "$rcpt_digest" --arg s "$stamped" \
      '{kind:"veto", stampedAt:$s, sealedDigest:$d, prevDigest:$p, tier: .vetoRecord.tier, unwindRequired: .vetoRecord.unwindRequired, record: .vetoRecord, flippedVerdict: .flippedVerdict, canonical: .canonical}' \
      > "${COUNCIL_RECEIPTS}/veto-${stamped//:/-}.json" 2>/dev/null || true
  fi
  # Append to the tamper-evident lineage. CNCL-9 (main gate amendment 1): the jsonl WRAPPER must
  # hash-chain to the LINEAGE head (prevDigest = the last lineage entry's digest, seq = last+1) so
  # `council lineage verify` stays green after a veto. The veto->original-verdict link is NOT lost:
  # it already rides INSIDE the signed record (record.prevDigest = the original verdict digest,
  # sealed in the canonical bytes). We keep it in the wrapper too, as `origDigest`, for readers.
  if [[ -f "$COUNCIL_LINEAGE" || -w "$COUNCIL_DIR" ]]; then
    local l_prev="" l_seq=0
    if [[ -f "$COUNCIL_LINEAGE" ]]; then
      l_prev="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null | jq -r '.digest // ""' 2>/dev/null)"
      local l_last; l_last="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null | jq -r '.seq // -1' 2>/dev/null)"
      [[ "$l_last" =~ ^[0-9]+$ ]] && l_seq=$((l_last+1))
    fi
    printf '%s' "$vraw" | jq -c --arg d "$vdigest" --arg lp "$l_prev" --arg od "$rcpt_digest" --arg sq "$l_seq" --arg s "$stamped" \
      '{seq: ($sq|tonumber), kind:"veto", stampedAt:$s, digest:$d, prevDigest:$lp, origDigest:$od, canonical: .canonical, record: .vetoRecord}' \
      >> "$COUNCIL_LINEAGE" 2>/dev/null || true
  fi

  if (( JSON_MODE )); then
    printf '%s' "$vraw" | jq --arg d "$vdigest" --arg p "$rcpt_digest" '{ok:true, data: (. + {sealedDigest:$d, prevDigest:$p})}'
  else
    echo "veto:         EXERCISED (${tier}) by ${offer_principal}"
    echo "disposition:  blocked  (pass overruled; original verdict left sealed + immutable)"
    [[ "$tier" == "posthoc" ]] && echo "unwind:       REQUIRED — reversible work must be manually unwound (v0.11)"
    echo "chained:      veto ${vdigest:0:16}… -> verdict ${rcpt_digest:0:16}…"
  fi
}

_council_init_or_lineage() {
  local sub="$1" dir="$2"; shift 2
  mkdir -p "$COUNCIL_DIR" 2>/dev/null || true

  if [[ "$sub" == "lineage" ]]; then
    local action="${1:-verify}"
    if [[ ! -f "$COUNCIL_LINEAGE" ]]; then
      if (( JSON_MODE )); then printf '%s\n' '{"ok":true,"data":{"entries":[],"chain":"empty"}}'; else echo "lineage: (empty — council not yet initialized)"; fi
      return 0
    fi
    if [[ "$action" == "ls" ]]; then
      if (( JSON_MODE )); then jq -s '{ok:true,data:{entries:.}}' "$COUNCIL_LINEAGE"
      else jq -r '"seq \(.seq)\t\(.kind)\t\(.stampedAt)\tdigest=\(.digest[0:16])…\tprev=\((.prevDigest // "")[0:8])"' "$COUNCIL_LINEAGE"; fi
      return 0
    fi
    # verify: re-seal each canonical on the ROOT rail, compare to the stored digest, and
    # check the prevDigest hash-chain links back to genesis. Fails closed on any mismatch.
    local ok=1 prev="" line seq canonical stored kind computed n=0
    while IFS= read -r line; do
      [[ -n "$line" ]] || continue
      n=$((n+1))
      seq="$(printf '%s' "$line" | jq -r '.seq')"
      kind="$(printf '%s' "$line" | jq -r '.kind')"
      stored="$(printf '%s' "$line" | jq -r '.digest')"
      canonical="$(printf '%s' "$line" | jq -r '.canonical')"
      local lprev; lprev="$(printf '%s' "$line" | jq -r '.prevDigest // ""')"
      if [[ "$lprev" != "$prev" ]]; then echo "lineage: BROKEN CHAIN at seq $seq (prevDigest=$lprev, expected $prev)" >&2; ok=0; fi
      if [[ "$(id -u)" -eq 0 ]]; then computed="$(printf '%s' "$canonical" | cmd_gate_proof_sign_stdin 2>/dev/null)"; else computed="$(printf '%s' "$canonical" | sudo -n 5dive gate-proof sign 2>/dev/null)"; fi
      if [[ -z "$computed" ]]; then echo "lineage: cannot re-seal seq $seq (no gate-proof key / not root)" >&2; ok=0
      elif [[ "$computed" != "$stored" ]]; then echo "lineage: TAMPERED seq $seq ($kind) — digest mismatch" >&2; ok=0; fi
      prev="$stored"
    done < "$COUNCIL_LINEAGE"
    if (( ok )); then
      if (( JSON_MODE )); then printf '%s\n' "{\"ok\":true,\"data\":{\"verified\":true,\"entries\":$n}}"; else echo "lineage: VERIFIED ($n entr$([[ $n -eq 1 ]] && echo y || echo ies), chain intact)"; fi
      return 0
    else
      if (( JSON_MODE )); then printf '%s\n' '{"ok":false,"error":"lineage verification failed"}'; fi
      return "$E_GENERIC"
    fi
  fi

  # ---- init (sudo-gated, one-time) ----------------------------------------
  if [[ ! -w "$COUNCIL_DIR" ]]; then
    fail "$E_PERMISSION" "council init seeds the governance body — it writes ${COUNCIL_DIR} (root-owned) and must be human/sudo-run: sudo 5dive council init $*"
  fi
  # Resolve the veto principal up front so init refuses an unresolvable one BEFORE any write.
  local principal="" a
  local -a passthru=()
  for a in "$@"; do
    case "$a" in --veto=*) principal="${a#--veto=}" ;; esac
    passthru+=("$a")
  done
  [[ -n "$principal" ]] || fail "$E_USAGE" "council init needs --veto=<principal> (e.g. human:main)"
  local resolved; resolved="$(_council_resolve_principal "$principal")"
  [[ -n "$resolved" ]] || fail "$E_USAGE" "veto principal '$principal' did not resolve to a real recipient — init rejects an unknown principal (fail-closed). Use human:<agent> (a paired agent) or tg:<user_id>."

  local genesis_exists=0; [[ -f "$COUNCIL_GENESIS" ]] && genesis_exists=1
  # hash-chain head: prevDigest + next seq come from the last lineage line.
  local prev_digest="" seq=0
  if [[ -f "$COUNCIL_LINEAGE" ]]; then
    prev_digest="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null | jq -r '.digest // ""' 2>/dev/null)"
    local last_seq; last_seq="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null | jq -r '.seq // -1' 2>/dev/null)"
    [[ "$last_seq" =~ ^[0-9]+$ ]] && seq=$((last_seq+1))
  fi
  local stamped; stamped="$(date -u +%Y-%m-%dT%H:%M:%SZ)"

  local raw
  raw="$(node "$dir/cli.mjs" init "${passthru[@]}" \
    --registry="$COUNCIL_REGISTRY" --veto-resolved="$resolved" \
    --genesis-exists="$genesis_exists" --prev-digest="$prev_digest" --seq="$seq" \
    --stamped-at="$stamped")" || return $?

  # Seal the canonical genesis bytes on the ROOT rail and hash-chain into the lineage. The
  # seal is what makes the roster non-forgeable; the chain makes the whole history verifiable.
  local canonical digest=""
  canonical="$(printf '%s' "$raw" | jq -r '.canonical // empty')"
  if [[ -z "$canonical" ]]; then fail "$E_GENERIC" "init produced no canonical record"; fi
  if [[ "$(id -u)" -eq 0 ]]; then digest="$(printf '%s' "$canonical" | cmd_gate_proof_sign_stdin 2>/dev/null)" || digest=""
  else digest="$(printf '%s' "$canonical" | sudo -n 5dive gate-proof sign 2>/dev/null)" || digest=""; fi
  [[ -n "$digest" ]] || fail "$E_GENERIC" "could not seal the genesis record on the gate-proof rail (need root + an enforce key) — genesis NOT written"

  printf '%s' "$raw" | jq --arg d "$digest" '.genesis + {sealedDigest:$d}' > "$COUNCIL_GENESIS"
  printf '%s' "$raw" | jq -c --arg d "$digest" --arg p "$prev_digest" \
    '{seq: .genesis.seq, kind: "genesis", stampedAt: .genesis.stampedAt, digest: $d, prevDigest: $p, canonical: .canonical, record: .genesis}' \
    >> "$COUNCIL_LINEAGE"

  if (( JSON_MODE )); then
    printf '%s' "$raw" | jq --arg d "$digest" '{ok:true, data: (. + {sealedDigest:$d})}'
  else
    local seats chair
    seats="$(printf '%s' "$raw" | jq -r '.seats | join(", ")')"
    chair="$(printf '%s' "$raw" | jq -r '.chair // "none"')"
    echo "council: initialized (seq $seq)"
    echo "seats:   $seats"
    echo "chair:   $chair"
    echo "veto:    $principal -> $resolved"
    echo "genesis: sealed (${digest:0:16}…) + hash-chained into lineage"
  fi
  return 0
}

# ==================== CNCL-12: gate-rot wiring ====================
# gate-clear (T1) + rot-triage (T2). Thin orchestrators: they read the gate from the tasks
# DB, ask the embedded pure `gate-map` verb what to do (guardrail + verdict->action), run the
# SAME sealed `5dive council convene` path for the deliberation, and drive real `task` verbs.
# No new seal/persist code — the convene it shells out to owns the tamper-evident receipt.
_council_bin() { echo "${COUNCIL_5DIVE_BIN:-5dive}"; }

# Emit {ident,ask,type,tier,recommend,options,live} JSON for an OPEN gate, or empty on a miss.
# `live` = the canonical still-answerable-gate predicate (need_type set, not answered, task open).
_council_gate_json() {
  local dir="$1" id="$2" row us
  us=$'\x1f'
  row="$(db "SELECT ident||x'1f'||COALESCE(need_type,'')||x'1f'||COALESCE(CAST(tier AS TEXT),'')||x'1f'||COALESCE(recommend,'')||x'1f'||COALESCE(need_options,'')||x'1f'||COALESCE(replace(ask,x'0a',' '),'')||x'1f'||CASE WHEN need_type IS NOT NULL AND need_answered_at IS NULL AND status NOT IN ('done','cancelled') THEN 1 ELSE 0 END FROM tasks WHERE ident=$(sqlq "$id") OR id=$(sqlq "$id") LIMIT 1;" 2>/dev/null)" || return 1
  [[ -n "$row" ]] || return 1
  local ident gtype gtier grec gopts gask glive
  IFS="$us" read -r ident gtype gtier grec gopts gask glive <<<"$row"
  # A missing tier defaults to 2 (fail-closed: unknown risk is treated as a hard human gate).
  [[ -n "$gtier" ]] || gtier=2
  jq -nc --arg ident "$ident" --arg ask "$gask" --arg type "$gtype" \
         --argjson tier "$gtier" --arg recommend "$grec" --arg options "$gopts" --argjson live "${glive:-0}" \
    '{ident:$ident, ask:$ask, type:$type, tier:$tier, recommend:$recommend, options:$options, live:$live}'
}

# Run the sealed primary-council convene on a question, return the --json envelope.
_council_convene_json() {
  local q="$1"; shift
  "$(_council_bin)" council convene "$q" --json "$@" 2>/dev/null
}

_council_gate_clear() {
  local dir="$1"; shift
  local id="" mode="deliberate" dry=0; local -a seat_args=()
  while [[ $# -gt 0 ]]; do
    case "$1" in
      --dry-run) dry=1 ;;
      --mode=*) mode="${1#--mode=}" ;;
      --seats=*|--bench=*|--timeout=*|--idle-secs=*|--poll-secs=*|--standalone) seat_args+=("$1") ;;
      --*) ;;  # ignore unknown flags
      *) id="$1" ;;
    esac; shift
  done
  [[ -n "$id" ]] || fail "$E_USAGE" "gate-clear needs a task id: 5dive council gate-clear <task|DIVE-N>"
  local gate; gate="$(_council_gate_json "$dir" "$id")" || fail "$E_NOT_FOUND" "no such task: $id"
  [[ "$(printf '%s' "$gate" | jq -r '.live')" == "1" ]] || fail "$E_VALIDATION" "$id has no open human gate to clear (already answered, or not a gate)"

  # Phase 1 — escalate-only guardrail (never convene a hard-gate class).
  local plan1 clearable; plan1="$(node "$dir/cli.mjs" gate-map --gate="$gate")" || fail "$E_GENERIC" "gate-map failed"
  clearable="$(printf '%s' "$plan1" | jq -r '.clearable')"
  if [[ "$clearable" != "true" ]]; then
    local cmd; cmd="$(printf '%s' "$plan1" | jq -r '.command')"
    _council_emit_gate_result "$dry" "escalate" "$id" "$(printf '%s' "$plan1" | jq -r '.reason')" "$cmd"
    return 0
  fi

  # Phase 2 — convene the primary council on the question from the guardrail, seal the receipt.
  local q; q="$(printf '%s' "$plan1" | jq -r '.question')"
  local env; env="$(_council_convene_json "$q" --mode="$mode" "${seat_args[@]}")" || fail "$E_GENERIC" "convene failed"
  local verdict digest; verdict="$(printf '%s' "$env" | jq -c '.data.verdict')"; digest="$(printf '%s' "$env" | jq -r '.data.sealedDigest // empty')"
  [[ -n "$verdict" && "$verdict" != "null" ]] || fail "$E_GENERIC" "convene returned no verdict"

  # Phase 3 — map the sealed verdict to the action command and run it.
  local plan2 action cmd; plan2="$(node "$dir/cli.mjs" gate-map --gate="$gate" --verdict="$verdict")" || fail "$E_GENERIC" "gate-map (verdict) failed"
  action="$(printf '%s' "$plan2" | jq -r '.action')"; cmd="$(printf '%s' "$plan2" | jq -r '.command')"
  _council_emit_gate_result "$dry" "$action" "$id" "receipt ${digest:0:16}…" "$cmd"
}

# Execute (or, on --dry-run, just print) a gate-map command. The command is a self-contained
# `5dive task ...` string built by the pure mapper; we run it through bash -c against the CLI.
_council_emit_gate_result() {
  local dry="$1" action="$2" id="$3" note="$4" cmd="$5"
  if (( dry )); then
    if (( JSON_MODE )); then jq -nc --arg a "$action" --arg id "$id" --arg n "$note" --arg c "$cmd" '{ok:true,data:{dryRun:true,action:$a,gate:$id,note:$n,command:$c}}'
    else echo "would $action $id ($note): $cmd"; fi
    return 0
  fi
  # Route the emitted `5dive ...` verbs through our own binary (test override honored).
  local runnable="${cmd//5dive /$(_council_bin) }"
  bash -c "$runnable" >/dev/null 2>&1 || true
  if (( JSON_MODE )); then jq -nc --arg a "$action" --arg id "$id" --arg n "$note" --arg c "$cmd" '{ok:true,data:{action:$a,gate:$id,note:$n,command:$c}}'
  else echo "council $action: $id ($note)"; fi
}

_council_rot_triage() {
  local dir="$1"; shift
  local id="" all=0 hours=48 dry=0
  while [[ $# -gt 0 ]]; do
    case "$1" in
      --all) all=1 ;;
      --dry-run) dry=1 ;;
      --older-than-hours=*) hours="${1#--older-than-hours=}" ;;
      --*) ;;
      *) id="$1" ;;
    esac; shift
  done
  [[ "$hours" =~ ^[0-9]+$ ]] || hours=48
  local -a idents=()
  if [[ -n "$id" ]]; then
    idents+=("$id")
  elif (( all )); then
    # Stale tier-2 (or legacy NULL-tier) gates, oldest first. Mirrors the heartbeat T2 predicate,
    # but gated on the gate-file time (need_asked_at) crossing the 48h threshold.
    local list; list="$(db "SELECT ident FROM tasks WHERE need_type IS NOT NULL AND need_answered_at IS NULL AND status NOT IN ('done','cancelled') AND (tier=2 OR tier IS NULL) AND need_asked_at IS NOT NULL AND need_asked_at <= datetime('now','-${hours} hours') ORDER BY need_asked_at ASC;" 2>/dev/null)"
    while IFS= read -r _l; do [[ -n "$_l" ]] && idents+=("$_l"); done <<<"$list"
  else
    fail "$E_USAGE" "rot-triage needs a task id or --all"
  fi
  if [[ ${#idents[@]} -eq 0 ]]; then
    if (( JSON_MODE )); then jq -nc '{ok:true,data:{triaged:[],count:0}}'; else echo "rot-triage: no stale tier-2 gates (>=${hours}h)"; fi
    return 0
  fi
  local -a done_idents=()
  local it
  for it in "${idents[@]}"; do
    local gate; gate="$(_council_gate_json "$dir" "$it")" || continue
    [[ "$(printf '%s' "$gate" | jq -r '.live')" == "1" ]] || continue
    # FAIL-CLOSED: only triage genuine tier>=2 gates (never a tier-1, which gate-clear handles).
    local gtier; gtier="$(printf '%s' "$gate" | jq -r '.tier')"
    [[ "$gtier" -ge 2 ]] 2>/dev/null || continue
    if (( dry )); then done_idents+=("$it"); continue; fi
    # Convene the triage question (the guardrail phase1 with --triage builds it). NEVER clears.
    local plan1 q; plan1="$(node "$dir/cli.mjs" gate-map --gate="$gate" --triage)" || continue
    q="$(printf '%s' "$plan1" | jq -r '.question')"
    local env verdict; env="$(_council_convene_json "$q" --mode=adversarial)" || continue
    verdict="$(printf '%s' "$env" | jq -c '.data.verdict')"; [[ -n "$verdict" && "$verdict" != "null" ]] || continue
    local plan2 cmd; plan2="$(node "$dir/cli.mjs" gate-map --gate="$gate" --triage --verdict="$verdict")" || continue
    # Belt-and-suspenders: the pure mapper never emits `task answer` for a triage, but assert it here
    # too — a triage must NEVER clear a tier-2 gate even if the mapping ever regresses.
    cmd="$(printf '%s' "$plan2" | jq -r '.command')"
    if printf '%s' "$cmd" | grep -q 'task answer'; then
      continue   # refuse: fail-closed, a tier-2 triage NEVER clears (should be unreachable)
    fi
    local runnable="${cmd//5dive /$(_council_bin) }"
    bash -c "$runnable" >/dev/null 2>&1 || true
    done_idents+=("$it")
  done
  if (( JSON_MODE )); then
    printf '%s\n' "${done_idents[@]}" | jq -R . | jq -sc --argjson dry "$dry" '{ok:true,data:{triaged:map(select(length>0)),count:(map(select(length>0))|length),dryRun:($dry==1)}}'
  else
    local _verb="re-briefed, none cleared"; (( dry )) && _verb="to triage (dry-run)"
    echo "rot-triage: ${#done_idents[@]} tier-2 gate(s) ${_verb}: ${done_idents[*]}"
  fi
}

# ==================== CNCL-11: governance surface ====================
# roster (live seats + threshold + veto holder + lineage head) / log (past verdicts) /
# verify (chain + per-record re-seal) / promote|demote|expel (a convened MOTION that, on a
# PASS, mutates the roster + writes a hash-chained, root-sealed lineage record). The convene
# it shells out to owns the tamper-evident receipt + the founder-veto offer; motions reuse it.

# Root seal of stdin canonical bytes on the gate-proof rail (empty on no key / not root).
_council_seal_stdin() {
  if [[ "$(id -u)" -eq 0 ]]; then cmd_gate_proof_sign_stdin 2>/dev/null; else sudo -n 5dive gate-proof sign 2>/dev/null; fi
}

# council roster — the current seats + live threshold (from the persisted council bench), the
# founder-veto principal (from genesis), and the sealed lineage head (seq + digest).
_council_roster() {
  local dir="$1"
  [[ -f "$COUNCIL_GENESIS" ]] || fail "$E_VALIDATION" "the Council has no genesis roster — human-seed it first: sudo 5dive council init --seats=<a:chair,b,c> --threshold=<spec> --veto=<principal>"
  local raw; raw="$(node "$dir/cli.mjs" roster --registry="$COUNCIL_REGISTRY")" || return $?
  local vprincipal vresolved head_seq head_digest hlen
  vprincipal="$(jq -r '.veto.principal // "none"' "$COUNCIL_GENESIS" 2>/dev/null)"
  vresolved="$(jq -r '.veto.resolved // ""' "$COUNCIL_GENESIS" 2>/dev/null)"
  head_seq="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null | jq -r '.seq // 0' 2>/dev/null)"
  head_digest="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null | jq -r '.digest // ""' 2>/dev/null)"
  hlen="$(wc -l < "$COUNCIL_LINEAGE" 2>/dev/null | tr -d ' ')"; [[ "$hlen" =~ ^[0-9]+$ ]] || hlen=0
  if (( JSON_MODE )); then
    printf '%s' "$raw" | jq --arg vp "$vprincipal" --arg vr "$vresolved" --argjson hs "${head_seq:-0}" --arg hd "$head_digest" --argjson hl "$hlen" \
      '{ok:true, data: (. + {veto:{principal:$vp, resolved:$vr}, lineage:{seq:$hs, headDigest:$hd, records:$hl}})}'
  else
    echo "council:   council ($(printf '%s' "$raw" | jq -r '.seatCount') seats)"
    printf '%s' "$raw" | jq -r '.seats[] | "  seat \(.id)\(if .chair then " (chair)" else "" end)"'
    echo "threshold: $(printf '%s' "$raw" | jq -r '.threshold') to pass, quorum $(printf '%s' "$raw" | jq -r '.quorum') (spec: $(printf '%s' "$raw" | jq -c '.thresholdSpec'))"
    echo "veto:      $vprincipal"
    echo "lineage:   seq $head_seq, ${hlen} record(s), head ${head_digest:0:16}…"
  fi
}

# council log — the past sealed verdicts (motions + genesis + vetoes) from the lineage, newest last.
_council_log() {
  local dir="$1"; shift
  local limit=0; for a in "$@"; do case "$a" in --limit=*) limit="${a#--limit=}";; esac; done
  if [[ ! -f "$COUNCIL_LINEAGE" ]]; then
    if (( JSON_MODE )); then printf '%s\n' '{"ok":true,"data":{"entries":[]}}'; else echo "log: (empty — council not yet initialized)"; fi
    return 0
  fi
  if (( JSON_MODE )); then
    jq -s --argjson lim "${limit:-0}" '{ok:true,data:{entries: (if $lim>0 then .[-$lim:] else . end)}}' "$COUNCIL_LINEAGE"
  else
    local src="$COUNCIL_LINEAGE"
    [[ "$limit" =~ ^[0-9]+$ && "$limit" -gt 0 ]] && src="$(tail -n "$limit" "$COUNCIL_LINEAGE")"
    printf '%s\n' "$([[ "$limit" -gt 0 ]] 2>/dev/null && printf '%s' "$src" || cat "$COUNCIL_LINEAGE")" | jq -r '
      if .kind=="genesis" then "seq \(.seq)\tgenesis\t\(.stampedAt)\tseats=\(.record.seats|map(.id)|join(","))"
      elif .kind=="motion" then "seq \(.seq)\tmotion:\(.record.motion.class)\t\(.stampedAt)\tsubject=\(.record.motion.subject // "-")\toutcome=\(.record.outcome)\ttally=a\(.record.tally.approve)/r\(.record.tally.reject)/e\(.record.tally.escalate)"
      elif .kind=="veto" then "seq \(.seq)\tveto\t\(.stampedAt)\ttier=\(.tier // "-")\tblocked"
      else "seq \(.seq)\t\(.kind)\t\(.stampedAt)" end'
  fi
}

# council verify [<receipt-digest>] — structural chain check (cli verify-chain over the lineage
# entries) AND a per-record ROOT re-seal (each canonical must re-seal to its stored digest). Both
# must be green. With a receipt digest, additionally locates + re-seals that specific sealed receipt.
_council_verify() {
  local dir="$1"; shift
  local target="${1:-}"
  if [[ ! -f "$COUNCIL_LINEAGE" ]]; then fail "$E_VALIDATION" "no lineage to verify — the council is not initialized"; fi
  # 1) structural chain (prevDigest links + seq monotonicity across the WHOLE log).
  local entries chain_res chain_ok
  entries="$(jq -s -c '[.[] | {seq, prevDigest: (.prevDigest // ""), digest}]' "$COUNCIL_LINEAGE")"
  chain_res="$(node "$dir/cli.mjs" verify-chain --entries="$entries")"; chain_ok=$?
  # 2) per-record re-seal on the ROOT rail (detects an edited canonical whose digest was faked).
  local reseal_ok=1 line canonical stored computed n=0 bad=""
  while IFS= read -r line; do
    [[ -n "$line" ]] || continue; n=$((n+1))
    stored="$(printf '%s' "$line" | jq -r '.digest')"
    canonical="$(printf '%s' "$line" | jq -r '.canonical')"
    computed="$(printf '%s' "$canonical" | _council_seal_stdin)"
    if [[ -z "$computed" ]]; then reseal_ok=0; bad="seq $(printf '%s' "$line" | jq -r '.seq') (no gate-proof key / not root)"; break
    elif [[ "$computed" != "$stored" ]]; then reseal_ok=0; bad="seq $(printf '%s' "$line" | jq -r '.seq') (canonical does not re-seal to its digest — TAMPERED)"; break; fi
  done < "$COUNCIL_LINEAGE"
  # 3) optional: a specific sealed receipt digest re-seals to itself.
  local rcpt_ok="skipped" rf found=""
  if [[ -n "$target" ]]; then
    rcpt_ok=0
    for rf in "$COUNCIL_RECEIPTS"/*.json; do
      [[ -f "$rf" ]] || continue
      [[ "$(jq -r '.sealedDigest // empty' "$rf" 2>/dev/null)" == "$target" ]] && { found="$rf"; break; }
    done
    if [[ -n "$found" ]]; then
      local rc; rc="$(jq -r '.canonical // empty' "$found")"
      [[ "$(printf '%s' "$rc" | _council_seal_stdin)" == "$target" ]] && rcpt_ok=1
    fi
  fi
  local all_ok=1
  [[ "$chain_ok" -eq 0 && "$reseal_ok" -eq 1 ]] || all_ok=0
  [[ -n "$target" && "$rcpt_ok" != "1" ]] && all_ok=0
  if (( JSON_MODE )); then
    jq -nc --argjson chain "$chain_res" --argjson chainOk "$([[ $chain_ok -eq 0 ]] && echo true || echo false)" \
      --argjson resealOk "$([[ $reseal_ok -eq 1 ]] && echo true || echo false)" --arg bad "$bad" \
      --arg rcpt "$rcpt_ok" --argjson n "$n" --argjson allOk "$([[ $all_ok -eq 1 ]] && echo true || echo false)" \
      '{ok:$allOk, data:{verified:$allOk, records:$n, chain:$chain, chainOk:$chainOk, resealOk:$resealOk, resealBad:$bad, receipt:$rcpt}}'
  else
    if (( all_ok )); then echo "council verify: OK — $n record(s), chain intact + every record re-seals${target:+ (receipt ${target:0:16}… verified)}"
    else
      echo "council verify: FAILED" >&2
      [[ "$chain_ok" -ne 0 ]] && echo "  chain: $(printf '%s' "$chain_res" | jq -r '.reason')" >&2
      [[ "$reseal_ok" -ne 1 ]] && echo "  re-seal: $bad" >&2
      [[ -n "$target" && "$rcpt_ok" != "1" ]] && echo "  receipt: $target not found or does not re-seal" >&2
    fi
  fi
  (( all_ok )) && return 0 || return "$E_GENERIC"
}

# council promote|demote|expel — the convened MOTION. Sudo-gated (mutates the root-owned roster +
# lineage). Reads the current roster off the sealed lineage head, PLANs (classify+recuse) via cli,
# CONVENEs the primary council (subject recused, class auto-derived, founder-veto offered), and on a
# PASS APPLYs: mutate roster, build a hash-chained motion record, ROOT-seal it, append the lineage,
# and persist the new roster — seal FIRST so a failed seal never splits roster from lineage.
_council_motion() {
  local dir="$1" kind="$2"; shift 2
  mkdir -p "$COUNCIL_DIR" 2>/dev/null || true
  if [[ ! -w "$COUNCIL_DIR" ]]; then
    fail "$E_PERMISSION" "council $kind mutates the governance roster — it writes ${COUNCIL_DIR} (root-owned) and must be sudo-run: sudo 5dive council $kind $*"
  fi
  [[ -f "$COUNCIL_GENESIS" && -f "$COUNCIL_LINEAGE" ]] || fail "$E_VALIDATION" "the Council has no genesis roster — seed it first: sudo 5dive council init …"
  local subject="" lens="" mode="adversarial" dry=0 a
  for a in "$@"; do
    case "$a" in
      --subject=*) subject="${a#--subject=}" ;;
      --lens=*)    lens="${a#--lens=}" ;;
      --mode=*)    mode="${a#--mode=}" ;;
      --dry-run)   dry=1 ;;
    esac
  done
  [[ -n "$subject" ]] || fail "$E_USAGE" "council $kind needs --subject=<seat id>"

  # Current roster + hash-chain head come from the SEALED lineage tail (the source of truth).
  local head head_seats prev_digest last_seq seq
  head="$(tail -n1 "$COUNCIL_LINEAGE" 2>/dev/null)"
  head_seats="$(printf '%s' "$head" | jq -c '.record.seats // []' 2>/dev/null)"
  [[ -n "$head_seats" && "$head_seats" != "null" && "$head_seats" != "[]" ]] || fail "$E_GENERIC" "cannot read the current roster from the lineage head (fail-closed)"
  prev_digest="$(printf '%s' "$head" | jq -r '.digest // ""')"
  last_seq="$(printf '%s' "$head" | jq -r '.seq // -1')"; [[ "$last_seq" =~ ^[0-9]+$ ]] && seq=$((last_seq+1)) || seq=0

  # PLAN — classify + recuse + build the deliberation question (fail-closed on a bad subject).
  local plan cls question recuse
  plan="$(node "$dir/cli.mjs" motion-plan --kind="$kind" --subject="$subject" --seats-json="$head_seats")" || return $?
  cls="$(printf '%s' "$plan" | jq -r '.class')"
  question="$(printf '%s' "$plan" | jq -r '.question')"
  recuse="$(printf '%s' "$plan" | jq -r '(.recuse // []) | join(",")')"

  if (( dry )); then
    if (( JSON_MODE )); then printf '%s' "$plan" | jq '{ok:true,data:(. + {dryRun:true})}'
    else echo "would convene ($cls, recuse=${recuse:-none}): $question"; fi
    return 0
  fi

  # CONVENE the primary council (bench=council -> genesis-gated + veto-offered), subject recused,
  # class auto-derived in the engine from --motion-*. The sealed receipt is the audit of the vote.
  local env verdict receipt_digest rec_out
  env="$("$(_council_bin)" council convene "$question" --json --bench=council --mode="$mode" \
    --motion-kind="$kind" --motion-subject="$subject" ${recuse:+--recuse="$recuse"})" || fail "$E_GENERIC" "motion convene failed"
  verdict="$(printf '%s' "$env" | jq -c '.data.verdict')"
  receipt_digest="$(printf '%s' "$env" | jq -r '.data.sealedDigest // empty')"
  rec_out="$(printf '%s' "$verdict" | jq -r '.recommendation // "reject"')"
  [[ -n "$verdict" && "$verdict" != "null" ]] || fail "$E_GENERIC" "motion convene returned no verdict"

  if [[ "$rec_out" != "approve" ]]; then
    # Motion did not carry — roster unchanged, NOTHING written to the lineage.
    if (( JSON_MODE )); then printf '%s' "$env" | jq --arg c "$cls" '{ok:true,data:{motion:$c,carried:false,outcome:(.data.verdict.recommendation),tally:(.data.verdict.tally),receipt:(.data.sealedDigest // null)}}'
    else echo "council $kind: NOT carried ($rec_out, tally $(printf '%s' "$verdict" | jq -r '"a\(.tally.approve)/r\(.tally.reject)/e\(.tally.escalate)"')) — roster unchanged"; fi
    return 0
  fi

  # APPLY — build the hash-chained motion record + its canonical (roster mutated in-code), root-seal,
  # append the lineage, THEN persist the new roster. Seal-first so a bad seal never mutates the roster.
  local stamped threshold_json veto_json apply canonical bench_seats
  stamped="$(date -u +%Y-%m-%dT%H:%M:%SZ)"
  threshold_json="$(jq -c '.threshold // {rule:"majority"}' "$COUNCIL_GENESIS" 2>/dev/null)"
  veto_json="$(jq -c '.veto // null' "$COUNCIL_GENESIS" 2>/dev/null)"
  apply="$(node "$dir/cli.mjs" motion-apply --kind="$kind" --subject="$subject" ${lens:+--lens="$lens"} \
    --seats-json="$head_seats" --verdict="$verdict" --threshold-json="$threshold_json" --veto-json="$veto_json" \
    --registry="$COUNCIL_REGISTRY" --prev-digest="$prev_digest" --seq="$seq" --stamped-at="$stamped" \
    --receipt-digest="$receipt_digest")" || return $?
  canonical="$(printf '%s' "$apply" | jq -r '.canonical')"
  [[ -n "$canonical" ]] || fail "$E_GENERIC" "motion produced no canonical record"
  local digest; digest="$(printf '%s' "$canonical" | _council_seal_stdin)" || digest=""
  [[ -n "$digest" ]] || fail "$E_GENERIC" "could not seal the motion record on the gate-proof rail (need root + an enforce key) — roster NOT changed"

  # Append the hash-chained lineage record.
  printf '%s' "$apply" | jq -c --arg d "$digest" --arg p "$prev_digest" --arg s "$stamped" \
    '{seq: .record.seq, kind: "motion", stampedAt: $s, digest: $d, prevDigest: $p, canonical: .canonical, record: .record}' \
    >> "$COUNCIL_LINEAGE"
  # Persist the new roster into the motion-governed council bench (only now the seal succeeded).
  bench_seats="$(printf '%s' "$apply" | jq -c '.benchSeats')"
  local tmpreg; tmpreg="$(mktemp)"
  jq --argjson seats "$bench_seats" '(.council.seats)=$seats | (.council.genesis)=true' "$COUNCIL_REGISTRY" > "$tmpreg" 2>/dev/null && mv "$tmpreg" "$COUNCIL_REGISTRY" || rm -f "$tmpreg"

  if (( JSON_MODE )); then
    printf '%s' "$apply" | jq --arg d "$digest" --arg r "$receipt_digest" '{ok:true,data:{motion:.class,carried:true,subject:(.record.motion.subject),seats:.seats,sealedDigest:$d,receiptDigest:$r,seq:.record.seq}}'
  else
    echo "council $kind: CARRIED — '$subject' ${kind}d"
    echo "roster:   $(printf '%s' "$apply" | jq -r '.seats | join(", ")')"
    echo "motion:   sealed (${digest:0:16}…) + hash-chained into lineage (seq $seq)"
    echo "receipt:  convene ${receipt_digest:0:16}…"
  fi
}

cmd_council() {
  command -v node >/dev/null 2>&1 || fail "$E_GENERIC" "5dive council needs node on PATH"
  command -v jq   >/dev/null 2>&1 || fail "$E_GENERIC" "5dive council needs jq on PATH"
  local sub="${1:-}"; [[ $# -gt 0 ]] && shift || true
  case "$sub" in
    ""|-h|--help|help) _council_help; return 0 ;;
    convene|bench|init|lineage|veto|gate-clear|rot-triage|roster|log|verify|promote|demote|expel|sign-vote|verify-votes) ;;
    *) fail "$E_USAGE" "unknown council command: $sub (convene|bench|init|lineage|roster|log|verify|promote|demote|expel|veto|gate-clear|rot-triage|sign-vote|verify-votes)" ;;
  esac

  local dir; dir="$(mktemp -d -t 5dive-council.XXXXXX)" || fail "$E_GENERIC" "mktemp failed"
  # shellcheck disable=SC2064
  trap "rm -rf '$dir'" RETURN
  _council_write_runtime "$dir"

  # CNCL-8: council init (human-seeded genesis) + lineage verify -----------
  if [[ "$sub" == "init" || "$sub" == "lineage" ]]; then
    _council_init_or_lineage "$sub" "$dir" "$@"
    return $?
  fi

  # CNCL-9: authenticated founder veto exercise (the confirmed tap) ---------
  if [[ "$sub" == "veto" ]]; then
    _council_veto "$dir" "$@"
    return $?
  fi

  # CNCL-12: gate-rot wiring — clear a tier-1 gate / rot-triage stale tier-2 gates.
  if [[ "$sub" == "gate-clear" ]]; then
    _council_gate_clear "$dir" "$@"
    return $?
  fi
  if [[ "$sub" == "rot-triage" ]]; then
    _council_rot_triage "$dir" "$@"
    return $?
  fi

  # CNCL-11: governance surface — roster / log / verify (read) + promote|demote|expel (motion).
  if [[ "$sub" == "roster" ]]; then _council_roster "$dir" "$@"; return $?; fi
  if [[ "$sub" == "log" ]];    then _council_log    "$dir" "$@"; return $?; fi
  if [[ "$sub" == "verify" ]]; then _council_verify "$dir" "$@"; return $?; fi
  if [[ "$sub" == "promote" || "$sub" == "demote" || "$sub" == "expel" ]]; then
    _council_motion "$dir" "$sub" "$@"; return $?
  fi

  # CNCL-10: co-signed votes — the per-seat sign-at-source (`sign-vote`) + the verifier
  # (`verify-votes`) are pure engine verbs a SEAT invokes from its OWN harness during a
  # dispatched convene (the shell IS the product surface here — a seat has no node runtime
  # of its own). No sudo, no root seal, no lineage write: pass straight through to cli.mjs
  # (like gate-map) and preserve its stdout contract (the `COUNCIL-SIG:` line / JSON row)
  # AND its exit code (verify-votes exits non-zero on a forged/replayed/revoked vote so the
  # seat harness can gate on it). Both take their roster/key inline (--roster / --key-file),
  # so no --registry: pass the seat's args straight through, verbatim.
  if [[ "$sub" == "sign-vote" || "$sub" == "verify-votes" ]]; then
    node "$dir/cli.mjs" "$sub" "$@"; return $?
  fi

  if [[ "$sub" == "bench" ]]; then
    local action="${1:-ls}"
    case "$action" in
      add|rm)
        mkdir -p "$COUNCIL_DIR" 2>/dev/null || true
        if [[ ! -w "$COUNCIL_DIR" ]]; then
          fail "$E_PERMISSION" "editing standing benches writes ${COUNCIL_REGISTRY} (root-owned) — re-run via: sudo 5dive council bench $action $*"
        fi
        ;;
    esac
    # cli.mjs always emits JSON; format it here so text/JSON honor the global contract.
    local braw; braw="$(node "$dir/cli.mjs" bench "$@" --registry="$COUNCIL_REGISTRY")" || return $?
    if (( JSON_MODE )); then
      printf '%s' "$braw" | jq '{ok:true, data: .}'
    elif [[ "$action" == "ls" ]]; then
      printf '%s' "$braw" | jq -r '.benches[] | "  \(.name)\t\(if .builtin then "(built-in)" else "" end)\(if .custom then "(custom)" else "" end)"'
    elif [[ "$action" == "show" ]]; then
      printf '%s' "$braw" | jq -r '"bench:  \(.name)\ndesc:   \(.description)\nmode:   \(.mode)\nseats:  \(.seats | map(.id) | join(", "))"'
    else
      printf '%s' "$braw" | jq -r 'to_entries[0] | "OK — bench \(.value) \(.key)"'
    fi
    return 0
  fi

  # convene ------------------------------------------------------------------
  local stamped; stamped="$(date -u +%Y-%m-%dT%H:%M:%SZ)"
  local genesis_exists=0; [[ -f "$COUNCIL_GENESIS" ]] && genesis_exists=1

  # CNCL-9 (main gate amendment 3): a `--veto-by` / `--veto-reason` on convene is a FORGE attempt —
  # an agent trying to assert a veto from a plain CLI string. cli.mjs refuses it (exit 9), but the
  # acceptance says "refused + LOGGED", so we write the durable audit line HERE before dispatch,
  # independent of cli's ordering (the refusal message still comes from cli). A test asserts it.
  local _fa _forge=""
  for _fa in "$@"; do
    case "$_fa" in
      --veto-by=*|--veto-by|--veto-reason=*|--veto-reason)
        _forge="${_forge:+$_forge,}${_fa%%=*}" ;;
    esac
  done
  [[ -n "$_forge" ]] && _council_veto_audit "forge-attempt-veto-by" "convene" "$_forge"

  # CNCL-9: on a PRIMARY-council convene we OFFER the founder veto to the genesis principal. The
  # offer rides inside the sealed receipt; the flip only ever happens later via an authenticated
  # tap (`council veto exercise`). We pass the genesis-resolved principal + the HOLD window (the
  # veto_hold constitution key; env-overridable seam until CNCL-13/14) down to the engine so the
  # offer is recorded on a pass. Ad-hoc panels (no genesis) get no offer.
  local -a veto_args=()
  local veto_hold="${COUNCIL_VETO_HOLD_SECS:-900}" constitution_json="" constitution_source="defaults" constitution_valid="true" constitution_principal=""
  constitution_json="$(_council_constitution_json 2>/dev/null || true)"
  if [[ -n "$constitution_json" ]]; then
    constitution_source="$(printf '%s' "$constitution_json" | jq -r '.source // "defaults"')"
    constitution_valid="$(printf '%s' "$constitution_json" | jq -r '.valid // true')"
    constitution_principal="$(printf '%s' "$constitution_json" | jq -r '.veto.principal // empty')"
    if [[ "$constitution_source" == "file" ]]; then
      veto_hold="$(printf '%s' "$constitution_json" | jq -r '.veto.holdSecs')"
    elif [[ "$constitution_valid" == "false" ]]; then
      veto_hold=900
      warn "invalid $(_council_constitution_path); council is using built-in governance defaults"
    fi
  fi
  [[ "$veto_hold" =~ ^[0-9]+$ ]] || veto_hold=900
  if (( genesis_exists )); then
    local g_principal g_resolved
    g_principal="$(jq -r '.veto.principal // empty' "$COUNCIL_GENESIS" 2>/dev/null)"
    g_resolved="$(jq -r '.veto.resolved // empty' "$COUNCIL_GENESIS" 2>/dev/null)"
    if [[ "$constitution_source" == "file" && -n "$constitution_principal" ]]; then
      if [[ "$constitution_principal" == "$g_principal" ]]; then
        g_principal="$constitution_principal"
      else
        warn "constitution veto principal '$constitution_principal' has no genesis-resolved recipient; veto offer omitted fail-closed"
        g_principal=""; g_resolved=""
      fi
    fi
    if [[ -n "$g_principal" && -n "$g_resolved" ]]; then
      veto_args=(--veto-principal="$g_principal" --veto-resolved="$g_resolved" --veto-window="$veto_hold")
    fi
  fi

  local raw
  raw="$(node "$dir/cli.mjs" convene "$@" "${veto_args[@]}" --constitution-path="$(_council_constitution_path)" --registry="$COUNCIL_REGISTRY" --genesis-exists="$genesis_exists" --stamped-at="$stamped")" || return $?

  # Seal the receipt canonical at the root HMAC rail — a standalone engine has no
  # key, so the seal (via gate-proof) is what makes the verdict tamper-evident. The
  # founder veto + dissent already ride INSIDE the signed bytes (canonicalTranscript).
  local base_canonical canonical digest=""
  base_canonical="$(printf '%s' "$raw" | jq -r '.receipt.canonical // empty')"
  if [[ -n "$base_canonical" ]]; then
    # CNCL-9: if the sealed verdict carries a veto OFFER (a primary-council pass), stamp the HOLD
    # deadline (executeAfter = sealedAt + veto_hold) and mint a one-time tap nonce bound to the
    # offered recipient. AMENDMENT (main gate): mint these BEFORE sealing and FOLD their binding
    # (nonce DIGEST + executeAfter) INTO the canonical via seal-augment, so they are covered by the
    # same HMAC as the rest of the receipt. Pre-amendment they were stamped onto the unsealed
    # wrapper AFTER the seal, so the exercise-time re-seal (which only re-signs `.canonical`) did
    # not cover them and an edited `.vetoNonceDigest` slipped through. A base receipt (no offer)
    # gets no seal-binding line and stays byte-identical to CNCL-6/8.
    local offer_resolved execute_after="" veto_nonce="" veto_nonce_digest=""
    offer_resolved="$(printf '%s' "$raw" | jq -r '.verdict.vetoOffer.resolved // empty' 2>/dev/null)"
    if [[ -n "$offer_resolved" ]]; then
      execute_after="$(date -u -d "$stamped + ${veto_hold} seconds" +%Y-%m-%dT%H:%M:%SZ 2>/dev/null || echo "")"
      veto_nonce="$(openssl rand -hex 16 2>/dev/null || head -c 16 /dev/urandom | od -An -tx1 | tr -d ' \n')"
      veto_nonce_digest="$(_council_sha256 "$veto_nonce")"
      canonical="$(printf '%s' "$base_canonical" | node "$dir/cli.mjs" seal-augment --canonical=- --nonce-digest="$veto_nonce_digest" --execute-after="$execute_after")" || canonical="$base_canonical"
    else
      canonical="$base_canonical"
    fi
    if [[ "$(id -u)" -eq 0 ]]; then
      digest="$(printf '%s' "$canonical" | cmd_gate_proof_sign_stdin)" || digest=""
    else
      digest="$(printf '%s' "$canonical" | sudo -n 5dive gate-proof sign 2>/dev/null)" || digest=""
    fi
    if [[ -n "$digest" ]]; then
      mkdir -p "$COUNCIL_RECEIPTS" 2>/dev/null || true
      if [[ -w "$COUNCIL_RECEIPTS" ]]; then
        # Offline-test capture ONLY: when MOCK is on AND a sink path is provided, drop the raw nonce
        # so the bash e2e can present it at exercise. Double-gated on COUNCIL_MOCK (never set in a
        # real convene) + COUNCIL_VETO_NONCE_SINK, so PRODUCTION never writes the raw nonce to disk —
        # in prod it leaves solely via the _tg_send founder delivery leg (main gate amendment 2).
        if [[ -n "$veto_nonce" && -n "${COUNCIL_MOCK:-}" && -n "${COUNCIL_VETO_NONCE_SINK:-}" ]]; then
          ( umask 077; printf '%s\n' "$veto_nonce" > "$COUNCIL_VETO_NONCE_SINK" ) 2>/dev/null || true
        fi
        # The receipt stores the AUGMENTED canonical (with the sealed veto-binding line). The wrapper
        # still surfaces executeAfter + vetoNonceDigest for display/dashboard audit, but exercise no
        # longer TRUSTS them — it reads the binding back out of the verified canonical (fail-closed).
        # The raw nonce never touches the receipt; it is delivered solely to the founder via the ping.
        printf '%s' "$raw" | jq --arg d "$digest" --arg s "$stamped" --arg ea "$execute_after" --arg nd "$veto_nonce_digest" --arg canon "$canonical" \
          '{stampedAt:$s, sealedDigest:$d, council, question, disposition, verdict, canonical: $canon}
           + (if ($ea|length)>0 then {executeAfter:$ea} else {} end)
           + (if ($nd|length)>0 then {vetoNonceDigest:$nd} else {} end)' \
          > "${COUNCIL_RECEIPTS}/${stamped//:/-}.json" 2>/dev/null || true
        # Fire the founder ping at seal (non-blocking, best-effort). Writes the durable digest-only
        # pings audit (0600) always; the live _tg_send notify (which carries the raw nonce) is
        # skipped under MOCK. The tappable button + its callback -> `council veto exercise` routing
        # is the telegram-plugin leg that pairs with a live genesis (post-seed).
        if [[ -n "$offer_resolved" ]]; then
          _council_veto_ping "$offer_resolved" "$digest" "$execute_after" "$veto_nonce" || true
        fi
      fi
    fi
  fi

  if (( JSON_MODE )); then
    printf '%s' "$raw" | jq --arg d "$digest" '{ok:true, data: (. + {sealedDigest: $d})}'
  else
    local council q disp rec tally conf dissent brief
    council="$(printf '%s' "$raw" | jq -r '.council')"
    q="$(printf '%s' "$raw" | jq -r '.question')"
    disp="$(printf '%s' "$raw" | jq -r '.disposition')"
    rec="$(printf '%s' "$raw" | jq -r '.verdict.recommendation')"
    tally="$(printf '%s' "$raw" | jq -r '.verdict.tally | "a\(.approve)/r\(.reject)/e\(.escalate)"')"
    conf="$(printf '%s' "$raw" | jq -r '.verdict.confidence')"
    dissent="$(printf '%s' "$raw" | jq -r '.verdict.dissent // "none"')"
    brief="$(printf '%s' "$raw" | jq -r '.verdict.brief // empty')"
    echo "council:      $council"
    echo "question:     $q"
    echo "disposition:  $disp  (recommendation=$rec, tally=$tally, confidence=$conf)"
    [[ -n "$dissent" && "$dissent" != "none" ]] && echo "dissent:      $dissent"
    [[ -n "$brief" ]] && echo "brief:        $brief"
    if [[ -n "$digest" ]]; then
      echo "receipt:      sealed (${digest:0:16}…)"
    else
      echo "receipt:      unsealed (no gate-proof key / not root — run via sudo to seal)"
    fi
  fi
}

# In-process root seal: reuse the existing gate-proof signer without a re-exec when
# we are already root (keeps the HMAC key handling in one place).
cmd_gate_proof_sign_stdin() { cmd_gate_proof sign; }
